/// Nested and_v(or_c, hash) + bad control block → hard error (tamper).
#[test]
fn finalize_taproot_and_v_or_c_hash_bad_control_block_is_hard_error() {
    use bitcoin::hashes::{Hash, sha256};
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let sk_a = [85u8; 32];
    let sk_b = [86u8; 32];
    let (preimage, digest) = sample_sha256_preimage_and_digest(87);
    let (mut psbt, leaf, _good_cb, pk_a, _pk_b) = p2tr_and_v_or_c_hash_script_path_psbt(
        [88u8; 32],
        sk_a,
        sk_b,
        TapscriptHashKind::Sha256,
        &digest,
    );
    let secp = Secp256k1::new();
    let wrong_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[89u8; 32]).expect("wsk"));
    let (wrong_internal, wrong_parity) = wrong_kp.x_only_public_key();
    let bad_cb = bitcoin::taproot::ControlBlock {
        leaf_version: LeafVersion::TapScript,
        output_key_parity: wrong_parity,
        internal_key: wrong_internal,
        merkle_branch: Default::default(),
    };
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    psbt.inputs[0]
        .tap_scripts
        .insert(bad_cb, (leaf, LeafVersion::TapScript));
    psbt.inputs[0]
        .tap_script_sigs
        .insert((pk_a, leaf_hash), sample_tap_key_sig(sk_a, [90u8; 32]));
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(digest), preimage.to_vec());

    let err = finalize_psbt(&mut psbt).unwrap_err();
    let msg = err.to_string().to_ascii_lowercase();
    assert!(
        msg.contains("control block")
            || msg.contains("verify")
            || msg.contains("tamper")
            || msg.contains("commit"),
        "{err}"
    );
    assert!(psbt.inputs[0].final_script_witness.is_none());
}

/// Template parser rejects bare or_c, bare hash, and_v(v:pk, hash), older dual, empty.
#[test]
fn bare_tapscript_and_v_or_c_hash_template_rejects_siblings() {
    use bitcoin::secp256k1::{Keypair, SecretKey};

    let secp = Secp256k1::new();
    let kp_a = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[91u8; 32]).expect("ska"));
    let (pk_a, _) = kp_a.x_only_public_key();
    let kp_b = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[92u8; 32]).expect("skb"));
    let (pk_b, _) = kp_b.x_only_public_key();
    let (_preimage, digest) = sample_sha256_preimage_and_digest(93);

    // Bare or_c (no hash tail) must not match.
    let bare_or_c = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_NOTIF)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .into_script();
    assert!(bare_tapscript_and_v_or_c_hash_template(&bare_or_c).is_none());
    assert!(bare_tapscript_or_c_checksig_template(&bare_or_c).is_some());

    // Nested older dual (CSV not hash) must not match.
    let or_c_older = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_NOTIF)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .push_int(9)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .into_script();
    assert!(bare_tapscript_and_v_or_c_hash_template(&or_c_older).is_none());
    assert!(bare_tapscript_and_v_or_c_older_template(&or_c_older).is_some());

    // Nested after dual (CLTV not hash) must not match.
    let or_c_after = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_NOTIF)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .push_int(9)
        .push_opcode(bitcoin::opcodes::all::OP_CLTV)
        .into_script();
    assert!(bare_tapscript_and_v_or_c_hash_template(&or_c_after).is_none());
    assert!(bare_tapscript_and_v_or_c_after_template(&or_c_after).is_some());

    // Single-key and_v(v:pk, hash) must not match.
    let pk_hash = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(<&bitcoin::script::PushBytes>::try_from(digest.as_slice()).unwrap())
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    assert!(bare_tapscript_and_v_or_c_hash_template(&pk_hash).is_none());
    assert!(bare_tapscript_and_v_pk_hash_template(&pk_hash).is_some());

    // Bare hash must not match.
    let bare_hash = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(<&bitcoin::script::PushBytes>::try_from(digest.as_slice()).unwrap())
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    assert!(bare_tapscript_and_v_or_c_hash_template(&bare_hash).is_none());
    assert!(bare_tapscript_hash_preimage_template(&bare_hash).is_some());

    // Nested form with CHECKSIG (not VERIFY) for B + hash is not our template.
    let bad_b_checksig = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_NOTIF)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(<&bitcoin::script::PushBytes>::try_from(digest.as_slice()).unwrap())
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    assert!(bare_tapscript_and_v_or_c_hash_template(&bad_b_checksig).is_none());

    assert!(bare_tapscript_and_v_or_c_hash_template(&ScriptBuf::new()).is_none());
}

/// Build nested CLEANSTACK-valid `and_v(or_i(v:pk(A), v:pk(B)), hash(H))`
/// leaf under a single-leaf Taproot tree.
fn p2tr_and_v_or_i_hash_script_path_psbt(
    internal_sk: [u8; 32],
    sk_a: [u8; 32],
    sk_b: [u8; 32],
    kind: TapscriptHashKind,
    digest: &[u8],
) -> (
    bitcoin::psbt::Psbt,
    ScriptBuf,
    bitcoin::taproot::ControlBlock,
    bitcoin::secp256k1::XOnlyPublicKey,
    bitcoin::secp256k1::XOnlyPublicKey,
) {
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TaprootBuilder};

    let secp = Secp256k1::new();
    let internal_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&internal_sk).expect("isk"));
    let (internal_xonly, _) = internal_kp.x_only_public_key();
    let kp_a = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&sk_a).expect("ska"));
    let (pk_a, _) = kp_a.x_only_public_key();
    let kp_b = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&sk_b).expect("skb"));
    let (pk_b, _) = kp_b.x_only_public_key();

    let hash_op = match kind {
        TapscriptHashKind::Sha256 => bitcoin::opcodes::all::OP_SHA256,
        TapscriptHashKind::Hash256 => bitcoin::opcodes::all::OP_HASH256,
        TapscriptHashKind::Ripemd160 => bitcoin::opcodes::all::OP_RIPEMD160,
        TapscriptHashKind::Hash160 => bitcoin::opcodes::all::OP_HASH160,
    };
    // and_v(or_i(v:pk(A), v:pk(B)), hash(H)):
    // IF <A> CHECKSIGVERIFY ELSE <B> CHECKSIGVERIFY ENDIF SIZE 32 EQUALVERIFY HASHOP digest EQUAL
    let leaf = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_IF)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_ELSE)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(hash_op)
        .push_slice(<&bitcoin::script::PushBytes>::try_from(digest).expect("digest pushable"))
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    let (parsed_a, parsed_b, parsed_kind, parsed_digest) =
        bare_tapscript_and_v_or_i_hash_template(&leaf).expect("test leaf is and_v(or_i, hash)");
    assert_eq!(parsed_a, pk_a);
    assert_eq!(parsed_b, pk_b);
    assert_eq!(parsed_kind, kind);
    assert_eq!(parsed_digest, digest);
    // Must not parse as bare or_i / or_c / or_d / and_v(v:pk, hash) / bare hash /
    // and_v(or_c, hash|older|after).
    assert!(bare_tapscript_or_i_checksig_template(&leaf).is_none());
    assert!(bare_tapscript_or_c_checksig_template(&leaf).is_none());
    assert!(bare_tapscript_or_d_checksig_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_pk_hash_template(&leaf).is_none());
    assert!(bare_tapscript_hash_preimage_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_or_c_hash_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_or_c_older_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_or_c_after_template(&leaf).is_none());
    assert!(bare_tapscript_and_n_checksig_template(&leaf).is_none());

    let spend_info = TaprootBuilder::new()
        .add_leaf(0, leaf.clone())
        .expect("add leaf")
        .finalize(&secp, internal_xonly)
        .expect("finalize tree");
    let merkle = spend_info.merkle_root();
    let control_block = spend_info
        .control_block(&(leaf.clone(), LeafVersion::TapScript))
        .expect("control block for leaf");
    let (psbt, spk) = p2tr_psbt_with_internal(internal_xonly, merkle);
    assert_eq!(spk, ScriptBuf::new_p2tr_tweaked(spend_info.output_key()));
    assert!(control_block.verify_taproot_commitment(
        &secp,
        p2tr_output_key(&spk).expect("output key"),
        &leaf
    ));
    (psbt, leaf, control_block, pk_a, pk_b)
}

/// Nested and_v(or_i, hash) IF/A branch + matching preimage → Complete.
#[test]
fn finalize_taproot_and_v_or_i_hash_if_branch_is_complete() {
    use bitcoin::hashes::{Hash, sha256};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let sk_a = [100u8; 32];
    let sk_b = [101u8; 32];
    let (preimage, digest) = sample_sha256_preimage_and_digest(102);
    let (mut psbt, leaf, control_block, pk_a, _pk_b) = p2tr_and_v_or_i_hash_script_path_psbt(
        [103u8; 32],
        sk_a,
        sk_b,
        TapscriptHashKind::Sha256,
        &digest,
    );
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    let sig_a = sample_tap_key_sig(sk_a, [104u8; 32]);
    psbt.inputs[0].tap_scripts.insert(
        control_block.clone(),
        (leaf.clone(), LeafVersion::TapScript),
    );
    psbt.inputs[0]
        .tap_script_sigs
        .insert((pk_a, leaf_hash), sig_a);
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(digest), preimage.to_vec());

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete() && fin.is_broadcast_ready(), "{fin:?}");
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("and_v(or_i, hash) IF final")
        .to_vec();
    // <preimage> <sigA> <0x01> <script> <cb>
    assert_eq!(items.len(), 5);
    assert_eq!(items[0], preimage.to_vec());
    assert_eq!(items[1], sig_a.to_vec());
    assert_eq!(items[2], vec![1u8], "IF branch selector must be 0x01");
    assert_eq!(items[3], leaf.as_bytes());
    assert_eq!(items[4], control_block.serialize());
    let _tx = extract_finalized_tx(psbt).unwrap();
}

