/// Nested and_v(or_i, older) with sig but unsatisfying nSequence → Partial
/// (never invent sequence).
#[test]
fn finalize_taproot_and_v_or_i_older_bad_sequence_is_partial() {
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let sk_a = [156u8; 32];
    let sk_b = [157u8; 32];
    let older_n = 20u32;
    let (mut psbt, leaf, control_block, pk_a, _pk_b) =
        p2tr_and_v_or_i_older_script_path_psbt([158u8; 32], sk_a, sk_b, older_n);
    // Sequence too low for older(20) — present, not invented, fails BIP-112.
    psbt.unsigned_tx.input[0].sequence = Sequence::from_height(5);
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    psbt.inputs[0]
        .tap_scripts
        .insert(control_block, (leaf, LeafVersion::TapScript));
    psbt.inputs[0]
        .tap_script_sigs
        .insert((pk_a, leaf_hash), sample_tap_key_sig(sk_a, [159u8; 32]));

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(!fin.is_complete(), "{fin:?}");
    match &fin {
        FinalizeOutcome::Partial { detail, .. } => {
            let d = detail.to_ascii_lowercase();
            assert!(
                d.contains("nsequence") || d.contains("csv") || d.contains("older"),
                "{detail}"
            );
            assert!(
                d.contains("or_i") || d.contains("and_v"),
                "must name and_v(or_i, older) residual: {detail}"
            );
            assert!(
                d.contains("not invent") || d.contains("never invent") || d.contains("present"),
                "{detail}"
            );
        }
        other => panic!("expected Partial, got {other:?}"),
    }
    assert!(psbt.inputs[0].final_script_witness.is_none());
    assert!(extract_finalized_tx(psbt).is_err());
}

/// Nested and_v(or_i, older) + bad control block → hard error (tamper).
#[test]
fn finalize_taproot_and_v_or_i_older_bad_control_block_is_hard_error() {
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let sk_a = [160u8; 32];
    let sk_b = [161u8; 32];
    let older_n = 7u32;
    let (mut psbt, leaf, _good_cb, pk_a, _pk_b) =
        p2tr_and_v_or_i_older_script_path_psbt([162u8; 32], sk_a, sk_b, older_n);
    psbt.unsigned_tx.input[0].sequence = Sequence::from_height(7);
    let secp = Secp256k1::new();
    let wrong_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[163u8; 32]).expect("wsk"));
    let (wrong_internal, wrong_parity) = wrong_kp.x_only_public_key();
    let bad_cb = bitcoin::taproot::ControlBlock {
        leaf_version: LeafVersion::TapScript,
        output_key_parity: wrong_parity,
        internal_key: wrong_internal,
        merkle_branch: Default::default(),
    };
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    psbt.inputs[0]
        .tap_scripts
        .insert(bad_cb, (leaf, LeafVersion::TapScript));
    psbt.inputs[0]
        .tap_script_sigs
        .insert((pk_a, leaf_hash), sample_tap_key_sig(sk_a, [164u8; 32]));

    let err = finalize_psbt(&mut psbt).unwrap_err();
    let msg = err.to_string().to_ascii_lowercase();
    assert!(
        msg.contains("control block")
            || msg.contains("verify")
            || msg.contains("tamper")
            || msg.contains("commit"),
        "{err}"
    );
    assert!(psbt.inputs[0].final_script_witness.is_none());
}

/// Template parser rejects bare or_i, and_v(or_c, older), and_v(or_i, hash),
/// CHECKSIG arms, empty.
#[test]
fn bare_tapscript_and_v_or_i_older_template_rejects_siblings() {
    use bitcoin::secp256k1::{Keypair, SecretKey};

    let secp = Secp256k1::new();
    let kp_a = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[165u8; 32]).expect("ska"));
    let (pk_a, _) = kp_a.x_only_public_key();
    let kp_b = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[166u8; 32]).expect("skb"));
    let (pk_b, _) = kp_b.x_only_public_key();

    // Bare or_i (CHECKSIG, no CSV) must not match.
    let bare_or_i = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_IF)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_ELSE)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .into_script();
    assert!(bare_tapscript_and_v_or_i_older_template(&bare_or_i).is_none());
    assert!(bare_tapscript_or_i_checksig_template(&bare_or_i).is_some());

    // Nested and_v(or_c, older) must not match (NOTIF shape, not IF/ELSE).
    let or_c_older = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_NOTIF)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .push_int(9)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .into_script();
    assert!(bare_tapscript_and_v_or_i_older_template(&or_c_older).is_none());
    assert!(bare_tapscript_and_v_or_c_older_template(&or_c_older).is_some());

    // Nested and_v(or_i, after) must not match (CLTV not CSV).
    let or_i_after = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_IF)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_ELSE)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .push_int(9)
        .push_opcode(bitcoin::opcodes::all::OP_CLTV)
        .into_script();
    assert!(bare_tapscript_and_v_or_i_older_template(&or_i_after).is_none());
    assert!(bare_tapscript_and_v_or_i_after_template(&or_i_after).is_some());

    // Nested and_v(or_i, hash) must not match (hash tail, not CSV).
    let (_preimage, digest) = sample_sha256_preimage_and_digest(167);
    let or_i_hash = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_IF)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_ELSE)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(<&bitcoin::script::PushBytes>::try_from(digest.as_slice()).unwrap())
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    assert!(bare_tapscript_and_v_or_i_older_template(&or_i_hash).is_none());
    assert!(bare_tapscript_and_v_or_i_hash_template(&or_i_hash).is_some());

    // Single-key and_v(v:pk, older) must not match.
    let pk_older = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_int(9)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .into_script();
    assert!(bare_tapscript_and_v_or_i_older_template(&pk_older).is_none());
    assert!(bare_tapscript_and_v_pk_older_template(&pk_older).is_some());

    // or_i with CHECKSIG (not VERIFY) + CSV is not our template.
    let bad_checksig_arms = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_IF)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_ELSE)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .push_int(9)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .into_script();
    assert!(bare_tapscript_and_v_or_i_older_template(&bad_checksig_arms).is_none());

    assert!(bare_tapscript_and_v_or_i_older_template(&ScriptBuf::new()).is_none());
}

/// Build nested CLEANSTACK-valid `and_v(or_i(v:pk(A), v:pk(B)), after(n))`
/// leaf under a single-leaf Taproot tree.
fn p2tr_and_v_or_i_after_script_path_psbt(
    internal_sk: [u8; 32],
    sk_a: [u8; 32],
    sk_b: [u8; 32],
    after_n: u32,
) -> (
    bitcoin::psbt::Psbt,
    ScriptBuf,
    bitcoin::taproot::ControlBlock,
    bitcoin::secp256k1::XOnlyPublicKey,
    bitcoin::secp256k1::XOnlyPublicKey,
) {
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TaprootBuilder};

    let secp = Secp256k1::new();
    let internal_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&internal_sk).expect("isk"));
    let (internal_xonly, _) = internal_kp.x_only_public_key();
    let kp_a = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&sk_a).expect("ska"));
    let (pk_a, _) = kp_a.x_only_public_key();
    let kp_b = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&sk_b).expect("skb"));
    let (pk_b, _) = kp_b.x_only_public_key();

    // and_v(or_i(v:pk(A), v:pk(B)), after(n)):
    // IF <A> CHECKSIGVERIFY ELSE <B> CHECKSIGVERIFY ENDIF <n> CLTV
    let leaf = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_IF)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_ELSE)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .push_int(i64::from(after_n))
        .push_opcode(bitcoin::opcodes::all::OP_CLTV)
        .into_script();
    let (parsed_a, parsed_b, parsed_n) =
        bare_tapscript_and_v_or_i_after_template(&leaf).expect("test leaf is and_v(or_i, after)");
    assert_eq!(parsed_a, pk_a);
    assert_eq!(parsed_b, pk_b);
    assert_eq!(parsed_n, after_n);
    // Must not parse as bare or_i / or_c / and_v(v:pk, after) /
    // and_v(or_c, older|after|hash) / and_v(or_i, older|hash).
    assert!(bare_tapscript_or_i_checksig_template(&leaf).is_none());
    assert!(bare_tapscript_or_c_checksig_template(&leaf).is_none());
    assert!(bare_tapscript_or_d_checksig_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_pk_after_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_or_c_older_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_or_c_after_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_or_c_hash_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_or_i_hash_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_or_i_older_template(&leaf).is_none());
    assert!(bare_tapscript_and_n_checksig_template(&leaf).is_none());

    let spend_info = TaprootBuilder::new()
        .add_leaf(0, leaf.clone())
        .expect("add leaf")
        .finalize(&secp, internal_xonly)
        .expect("finalize tree");
    let merkle = spend_info.merkle_root();
    let control_block = spend_info
        .control_block(&(leaf.clone(), LeafVersion::TapScript))
        .expect("control block for leaf");
    let (psbt, spk) = p2tr_psbt_with_internal(internal_xonly, merkle);
    assert_eq!(spk, ScriptBuf::new_p2tr_tweaked(spend_info.output_key()));
    assert!(control_block.verify_taproot_commitment(
        &secp,
        p2tr_output_key(&spk).expect("output key"),
        &leaf
    ));
    (psbt, leaf, control_block, pk_a, pk_b)
}

/// Nested and_v(or_i, after) IF/A branch + satisfying nLockTime → Complete.
#[test]
fn finalize_taproot_and_v_or_i_after_if_branch_is_complete() {
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let sk_a = [170u8; 32];
    let sk_b = [171u8; 32];
    let after_n = 9u32;
    let (mut psbt, leaf, control_block, pk_a, _pk_b) =
        p2tr_and_v_or_i_after_script_path_psbt([172u8; 32], sk_a, sk_b, after_n);
    // Present nLockTime that satisfies after(9) — never invented by finalize.
    psbt.unsigned_tx.lock_time = LockTime::from_height(9).expect("height 9");
    assert!(
        psbt.unsigned_tx.input[0]
            .sequence
            .enables_absolute_lock_time()
    );
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    let sig_a = sample_tap_key_sig(sk_a, [173u8; 32]);
    psbt.inputs[0].tap_scripts.insert(
        control_block.clone(),
        (leaf.clone(), LeafVersion::TapScript),
    );
    psbt.inputs[0]
        .tap_script_sigs
        .insert((pk_a, leaf_hash), sig_a);

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete() && fin.is_broadcast_ready(), "{fin:?}");
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("and_v(or_i, after) IF final")
        .to_vec();
    // <sigA> <0x01> <script> <cb>
    assert_eq!(items.len(), 4);
    assert_eq!(items[0], sig_a.to_vec());
    assert_eq!(items[1], vec![1u8], "IF branch selector must be 0x01");
    assert_eq!(items[2], leaf.as_bytes());
    assert_eq!(items[3], control_block.serialize());
    assert_eq!(
        psbt.unsigned_tx.lock_time,
        LockTime::from_height(9).expect("height 9")
    );
    assert_eq!(
        psbt.unsigned_tx.input[0].sequence,
        Sequence::ENABLE_RBF_NO_LOCKTIME
    );
    let _tx = extract_finalized_tx(psbt).unwrap();
}

