/// Nested and_v(or_i, after) missing both sigs (locktime ok) → Partial.
#[test]
fn finalize_taproot_and_v_or_i_after_missing_both_sigs_is_partial() {
    use bitcoin::taproot::LeafVersion;

    let after_n = 10u32;
    let (mut psbt, leaf, control_block, _pk_a, _pk_b) =
        p2tr_and_v_or_i_after_script_path_psbt([183u8; 32], [184u8; 32], [185u8; 32], after_n);
    psbt.unsigned_tx.lock_time = LockTime::from_height(10).expect("height 10");
    psbt.inputs[0]
        .tap_scripts
        .insert(control_block, (leaf, LeafVersion::TapScript));
    assert!(psbt.inputs[0].tap_script_sigs.is_empty());

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(!fin.is_complete() && !fin.is_broadcast_ready(), "{fin:?}");
    match &fin {
        FinalizeOutcome::Partial { detail, .. } => {
            let d = detail.to_ascii_lowercase();
            assert!(d.contains("script-path"), "{detail}");
            assert!(
                d.contains("or_i") || d.contains("and_v") || d.contains("missing"),
                "{detail}"
            );
            assert!(
                d.contains("if/else") || d.contains("both") || d.contains("branch"),
                "{detail}"
            );
            assert!(d.contains("not broadcast-ready"), "{detail}");
        }
        other => panic!("expected Partial, got {other:?}"),
    }
    assert!(psbt.inputs[0].final_script_witness.is_none());
    assert!(extract_finalized_tx(psbt).is_err());
}

/// Nested and_v(or_i, after) with sig but unsatisfying nLockTime → Partial
