#[test]
fn finalize_taproot_and_v_or_c_multi_older_bad_control_block_is_hard_error() {
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let sk_a = [247u8; 32];
    let sk_b = [248u8; 32];
    let sk_c = [249u8; 32];
    let older_n = 9u32;
    let (mut psbt, leaf, _good_cb, pk_a, _pk_b, _pk_c) =
        p2tr_and_v_or_c_multi_older_script_path_psbt([250u8; 32], sk_a, sk_b, sk_c, older_n);
    psbt.unsigned_tx.input[0].sequence = Sequence::from_height(9);
    let secp = Secp256k1::new();
    let wrong_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[251u8; 32]).expect("wsk"));
    let (wrong_internal, wrong_parity) = wrong_kp.x_only_public_key();
    let bad_cb = bitcoin::taproot::ControlBlock {
        leaf_version: LeafVersion::TapScript,
        output_key_parity: wrong_parity,
        internal_key: wrong_internal,
        merkle_branch: Default::default(),
    };
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    psbt.inputs[0]
        .tap_scripts
        .insert(bad_cb, (leaf, LeafVersion::TapScript));
    psbt.inputs[0]
        .tap_script_sigs
        .insert((pk_a, leaf_hash), sample_tap_key_sig(sk_a, [252u8; 32]));

    let err = finalize_psbt(&mut psbt).unwrap_err();
    let msg = err.to_string().to_ascii_lowercase();
    assert!(
        msg.contains("control block")
            || msg.contains("verify")
            || msg.contains("tamper")
            || msg.contains("commit"),
        "{err}"
    );
    assert!(psbt.inputs[0].final_script_witness.is_none());
}

/// Multi-arm older template rejects dual-key nested, bare or_c, after multi, empty.
#[test]
fn bare_tapscript_and_v_or_c_multi_older_template_rejects_siblings() {
    use bitcoin::secp256k1::{Keypair, SecretKey};

    let secp = Secp256k1::new();
    let kp_a = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[10u8; 32]).expect("ska"));
    let (pk_a, _) = kp_a.x_only_public_key();
    let kp_b = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[11u8; 32]).expect("skb"));
    let (pk_b, _) = kp_b.x_only_public_key();
    let kp_c = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[12u8; 32]).expect("skc"));
    let (pk_c, _) = kp_c.x_only_public_key();

    // Dual-key and_v(or_c, older) must not match multi-arm.
    let dual = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_NOTIF)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .push_int(9)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .into_script();
    assert!(bare_tapscript_and_v_or_c_multi_older_template(&dual).is_none());
    assert!(bare_tapscript_and_v_or_c_older_template(&dual).is_some());

    // Bare or_c must not match.
    let bare_or_c = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_NOTIF)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .into_script();
    assert!(bare_tapscript_and_v_or_c_multi_older_template(&bare_or_c).is_none());

    // Multi-arm after (CLTV) must not match older template.
    let multi_after = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_NOTIF)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_NOTIF)
        .push_x_only_key(&pk_c)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .push_int(9)
        .push_opcode(bitcoin::opcodes::all::OP_CLTV)
        .into_script();
    assert!(bare_tapscript_and_v_or_c_multi_older_template(&multi_after).is_none());
    assert!(bare_tapscript_and_v_or_c_multi_after_template(&multi_after).is_some());

    // Innermost CHECKSIG (not VERIFY) is not our template.
    let bad_inner = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_NOTIF)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_NOTIF)
        .push_x_only_key(&pk_c)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .push_int(9)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .into_script();
    assert!(bare_tapscript_and_v_or_c_multi_older_template(&bad_inner).is_none());

    assert!(bare_tapscript_and_v_or_c_multi_older_template(&ScriptBuf::new()).is_none());
}

/// Build nested CLEANSTACK-valid multi-arm
/// `and_v(or_c(pk(A), or_c(pk(B), v:pk(C))), after(n))` under a single-leaf tree.
fn p2tr_and_v_or_c_multi_after_script_path_psbt(
    internal_sk: [u8; 32],
    sk_a: [u8; 32],
    sk_b: [u8; 32],
    sk_c: [u8; 32],
    after_n: u32,
) -> (
    bitcoin::psbt::Psbt,
    ScriptBuf,
    bitcoin::taproot::ControlBlock,
    bitcoin::secp256k1::XOnlyPublicKey,
    bitcoin::secp256k1::XOnlyPublicKey,
    bitcoin::secp256k1::XOnlyPublicKey,
) {
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TaprootBuilder};

    let secp = Secp256k1::new();
    let internal_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&internal_sk).expect("isk"));
    let (internal_xonly, _) = internal_kp.x_only_public_key();
    let kp_a = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&sk_a).expect("ska"));
    let (pk_a, _) = kp_a.x_only_public_key();
    let kp_b = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&sk_b).expect("skb"));
    let (pk_b, _) = kp_b.x_only_public_key();
    let kp_c = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&sk_c).expect("skc"));
    let (pk_c, _) = kp_c.x_only_public_key();

    // and_v(or_c(pk(A), or_c(pk(B), v:pk(C))), after(n)):
    // <A> CHECKSIG NOTIF <B> CHECKSIG NOTIF <C> CHECKSIGVERIFY ENDIF ENDIF <n> CLTV
    let leaf = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_NOTIF)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_NOTIF)
        .push_x_only_key(&pk_c)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .push_int(i64::from(after_n))
        .push_opcode(bitcoin::opcodes::all::OP_CLTV)
        .into_script();
    let (parsed_a, parsed_b, parsed_c, parsed_n) =
        bare_tapscript_and_v_or_c_multi_after_template(&leaf)
            .expect("test leaf is and_v(or_c multi-arm, after)");
    assert_eq!(parsed_a, pk_a);
    assert_eq!(parsed_b, pk_b);
    assert_eq!(parsed_c, pk_c);
    assert_eq!(parsed_n, after_n);
    assert!(bare_tapscript_and_v_or_c_multi_older_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_or_c_multi_hash_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_or_c_after_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_or_i_after_template(&leaf).is_none());
    assert!(bare_tapscript_or_c_checksig_template(&leaf).is_none());

    let spend_info = TaprootBuilder::new()
        .add_leaf(0, leaf.clone())
        .expect("add leaf")
        .finalize(&secp, internal_xonly)
        .expect("finalize tree");
    let merkle = spend_info.merkle_root();
    let control_block = spend_info
        .control_block(&(leaf.clone(), LeafVersion::TapScript))
        .expect("control block for leaf");
    let (psbt, spk) = p2tr_psbt_with_internal(internal_xonly, merkle);
    assert_eq!(spk, ScriptBuf::new_p2tr_tweaked(spend_info.output_key()));
    assert!(control_block.verify_taproot_commitment(
        &secp,
        p2tr_output_key(&spk).expect("output key"),
        &leaf
    ));
    (psbt, leaf, control_block, pk_a, pk_b, pk_c)
}

/// Multi-arm after A branch + satisfying nLockTime → Complete.
#[test]
fn finalize_taproot_and_v_or_c_multi_after_a_branch_is_complete() {
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let sk_a = [20u8; 32];
    let sk_b = [21u8; 32];
    let sk_c = [22u8; 32];
    let after_n = 9u32;
    let (mut psbt, leaf, control_block, pk_a, _pk_b, _pk_c) =
        p2tr_and_v_or_c_multi_after_script_path_psbt([23u8; 32], sk_a, sk_b, sk_c, after_n);
    psbt.unsigned_tx.lock_time = LockTime::from_height(9).expect("height 9");
    // Non-final sequence so absolute locktime is enabled.
    psbt.unsigned_tx.input[0].sequence = Sequence::from_consensus(0xffff_fffe);
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    let sig_a = sample_tap_key_sig(sk_a, [24u8; 32]);
    psbt.inputs[0].tap_scripts.insert(
        control_block.clone(),
        (leaf.clone(), LeafVersion::TapScript),
    );
    psbt.inputs[0]
        .tap_script_sigs
        .insert((pk_a, leaf_hash), sig_a);

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete() && fin.is_broadcast_ready(), "{fin:?}");
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("multi-arm after A final")
        .to_vec();
    assert_eq!(items.len(), 3);
    assert_eq!(items[0], sig_a.to_vec());
    assert_eq!(items[1], leaf.as_bytes());
    assert_eq!(items[2], control_block.serialize());
    assert_eq!(
        psbt.unsigned_tx.lock_time,
        LockTime::from_height(9).expect("height 9")
    );
    let _tx = extract_finalized_tx(psbt).unwrap();
}

