/// Multi-arm after all three sigs → prefer A.
#[test]
fn finalize_taproot_and_v_or_c_multi_after_all_sigs_prefers_a() {
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let sk_a = [35u8; 32];
    let sk_b = [36u8; 32];
    let sk_c = [37u8; 32];
    let after_n = 8u32;
    let (mut psbt, leaf, control_block, pk_a, pk_b, pk_c) =
        p2tr_and_v_or_c_multi_after_script_path_psbt([38u8; 32], sk_a, sk_b, sk_c, after_n);
    psbt.unsigned_tx.lock_time = LockTime::from_height(8).expect("height 8");
    psbt.unsigned_tx.input[0].sequence = Sequence::from_consensus(0xffff_fffe);
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    let sig_a = sample_tap_key_sig(sk_a, [39u8; 32]);
    let sig_b = sample_tap_key_sig(sk_b, [40u8; 32]);
    let sig_c = sample_tap_key_sig(sk_c, [41u8; 32]);
    psbt.inputs[0].tap_scripts.insert(
        control_block.clone(),
        (leaf.clone(), LeafVersion::TapScript),
    );
    psbt.inputs[0]
        .tap_script_sigs
        .insert((pk_a, leaf_hash), sig_a);
    psbt.inputs[0]
        .tap_script_sigs
        .insert((pk_b, leaf_hash), sig_b);
    psbt.inputs[0]
        .tap_script_sigs
        .insert((pk_c, leaf_hash), sig_c);

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete(), "{fin:?}");
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("final")
        .to_vec();
    assert_eq!(items.len(), 3);
    assert_eq!(items[0], sig_a.to_vec());
    assert_ne!(items[0], sig_b.to_vec());
    assert_ne!(items[0], sig_c.to_vec());
}

/// Multi-arm after missing all sigs → Partial.
#[test]
fn finalize_taproot_and_v_or_c_multi_after_missing_all_sigs_is_partial() {
    use bitcoin::taproot::LeafVersion;

    let after_n = 10u32;
    let (mut psbt, leaf, control_block, _a, _b, _c) = p2tr_and_v_or_c_multi_after_script_path_psbt(
        [42u8; 32], [43u8; 32], [44u8; 32], [45u8; 32], after_n,
    );
    psbt.unsigned_tx.lock_time = LockTime::from_height(10).expect("height 10");
    psbt.unsigned_tx.input[0].sequence = Sequence::from_consensus(0xffff_fffe);
    psbt.inputs[0]
        .tap_scripts
        .insert(control_block, (leaf, LeafVersion::TapScript));
    assert!(psbt.inputs[0].tap_script_sigs.is_empty());

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(!fin.is_complete() && !fin.is_broadcast_ready(), "{fin:?}");
    match &fin {
        FinalizeOutcome::Partial { detail, .. } => {
            let d = detail.to_ascii_lowercase();
            assert!(d.contains("script-path"), "{detail}");
            assert!(
                d.contains("multi-arm") || d.contains("or_c") || d.contains("missing"),
                "{detail}"
            );
            assert!(d.contains("not broadcast-ready"), "{detail}");
        }
        other => panic!("expected Partial, got {other:?}"),
    }
    assert!(psbt.inputs[0].final_script_witness.is_none());
}

