/// Multi-arm after with final nSequence (disables absolute locktime) → Partial.
#[test]
fn finalize_taproot_and_v_or_c_multi_after_final_sequence_is_partial() {
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let sk_a = [51u8; 32];
    let sk_b = [52u8; 32];
    let sk_c = [53u8; 32];
    let after_n = 9u32;
    let (mut psbt, leaf, control_block, pk_a, _pk_b, _pk_c) =
        p2tr_and_v_or_c_multi_after_script_path_psbt([54u8; 32], sk_a, sk_b, sk_c, after_n);
    psbt.unsigned_tx.lock_time = LockTime::from_height(9).expect("height 9");
    // Final sequence disables BIP-65 absolute locktime.
    psbt.unsigned_tx.input[0].sequence = Sequence::MAX;
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    psbt.inputs[0]
        .tap_scripts
        .insert(control_block, (leaf, LeafVersion::TapScript));
    psbt.inputs[0]
        .tap_script_sigs
        .insert((pk_a, leaf_hash), sample_tap_key_sig(sk_a, [55u8; 32]));

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(!fin.is_complete(), "{fin:?}");
    match &fin {
        FinalizeOutcome::Partial { detail, .. } => {
            let d = detail.to_ascii_lowercase();
            assert!(
                d.contains("nlocktime")
                    || d.contains("nsequence")
                    || d.contains("cltv")
                    || d.contains("after"),
                "{detail}"
            );
            assert!(
                d.contains("multi-arm") || d.contains("or_c") || d.contains("and_v"),
                "must name and_v(or_c multi-arm, after) residual: {detail}"
            );
        }
        other => panic!("expected Partial, got {other:?}"),
    }
    assert!(psbt.inputs[0].final_script_witness.is_none());
}

/// Multi-arm after + bad control block → hard error.
#[test]
fn finalize_taproot_and_v_or_c_multi_after_bad_control_block_is_hard_error() {
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let sk_a = [56u8; 32];
    let sk_b = [57u8; 32];
    let sk_c = [58u8; 32];
    let after_n = 9u32;
    let (mut psbt, leaf, _good_cb, pk_a, _pk_b, _pk_c) =
        p2tr_and_v_or_c_multi_after_script_path_psbt([59u8; 32], sk_a, sk_b, sk_c, after_n);
    psbt.unsigned_tx.lock_time = LockTime::from_height(9).expect("height 9");
    psbt.unsigned_tx.input[0].sequence = Sequence::from_consensus(0xffff_fffe);
    let secp = Secp256k1::new();
    let wrong_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[60u8; 32]).expect("wsk"));
    let (wrong_internal, wrong_parity) = wrong_kp.x_only_public_key();
    let bad_cb = bitcoin::taproot::ControlBlock {
        leaf_version: LeafVersion::TapScript,
        output_key_parity: wrong_parity,
        internal_key: wrong_internal,
        merkle_branch: Default::default(),
    };
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    psbt.inputs[0]
        .tap_scripts
        .insert(bad_cb, (leaf, LeafVersion::TapScript));
    psbt.inputs[0]
        .tap_script_sigs
        .insert((pk_a, leaf_hash), sample_tap_key_sig(sk_a, [61u8; 32]));

    let err = finalize_psbt(&mut psbt).unwrap_err();
    let msg = err.to_string().to_ascii_lowercase();
    assert!(
        msg.contains("control block")
            || msg.contains("verify")
            || msg.contains("tamper")
            || msg.contains("commit"),
        "{err}"
    );
    assert!(psbt.inputs[0].final_script_witness.is_none());
}

/// Multi-arm after template rejects dual-key after, multi older, bare or_c, empty.
#[test]
fn bare_tapscript_and_v_or_c_multi_after_template_rejects_siblings() {
    use bitcoin::secp256k1::{Keypair, SecretKey};

    let secp = Secp256k1::new();
    let kp_a = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[62u8; 32]).expect("ska"));
    let (pk_a, _) = kp_a.x_only_public_key();
    let kp_b = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[63u8; 32]).expect("skb"));
    let (pk_b, _) = kp_b.x_only_public_key();
    let kp_c = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[64u8; 32]).expect("skc"));
    let (pk_c, _) = kp_c.x_only_public_key();

    let dual_after = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_NOTIF)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .push_int(9)
        .push_opcode(bitcoin::opcodes::all::OP_CLTV)
        .into_script();
    assert!(bare_tapscript_and_v_or_c_multi_after_template(&dual_after).is_none());
    assert!(bare_tapscript_and_v_or_c_after_template(&dual_after).is_some());

    let multi_older = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_NOTIF)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_NOTIF)
        .push_x_only_key(&pk_c)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .push_int(9)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .into_script();
    assert!(bare_tapscript_and_v_or_c_multi_after_template(&multi_older).is_none());
    assert!(bare_tapscript_and_v_or_c_multi_older_template(&multi_older).is_some());

    let bare_or_c = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_NOTIF)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .into_script();
    assert!(bare_tapscript_and_v_or_c_multi_after_template(&bare_or_c).is_none());

    // after(0) is invalid (parse_cltv_after_n fail-closes).
    let after_zero = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_NOTIF)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_NOTIF)
        .push_x_only_key(&pk_c)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .push_int(0)
        .push_opcode(bitcoin::opcodes::all::OP_CLTV)
        .into_script();
    assert!(bare_tapscript_and_v_or_c_multi_after_template(&after_zero).is_none());

    assert!(bare_tapscript_and_v_or_c_multi_after_template(&ScriptBuf::new()).is_none());
}

/// Build nested CLEANSTACK-valid multi-arm
/// `and_v(or_c(pk(A), or_c(pk(B), v:pk(C))), hash(H))` under a single-leaf tree.
fn p2tr_and_v_or_c_multi_hash_script_path_psbt(
    internal_sk: [u8; 32],
    sk_a: [u8; 32],
    sk_b: [u8; 32],
    sk_c: [u8; 32],
    kind: TapscriptHashKind,
    digest: &[u8],
) -> (
    bitcoin::psbt::Psbt,
    ScriptBuf,
    bitcoin::taproot::ControlBlock,
    bitcoin::secp256k1::XOnlyPublicKey,
    bitcoin::secp256k1::XOnlyPublicKey,
    bitcoin::secp256k1::XOnlyPublicKey,
) {
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TaprootBuilder};

    let secp = Secp256k1::new();
    let internal_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&internal_sk).expect("isk"));
    let (internal_xonly, _) = internal_kp.x_only_public_key();
    let kp_a = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&sk_a).expect("ska"));
    let (pk_a, _) = kp_a.x_only_public_key();
    let kp_b = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&sk_b).expect("skb"));
    let (pk_b, _) = kp_b.x_only_public_key();
    let kp_c = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&sk_c).expect("skc"));
    let (pk_c, _) = kp_c.x_only_public_key();

    let hash_op = match kind {
        TapscriptHashKind::Sha256 => bitcoin::opcodes::all::OP_SHA256,
        TapscriptHashKind::Hash256 => bitcoin::opcodes::all::OP_HASH256,
        TapscriptHashKind::Ripemd160 => bitcoin::opcodes::all::OP_RIPEMD160,
        TapscriptHashKind::Hash160 => bitcoin::opcodes::all::OP_HASH160,
    };
    // and_v(or_c(pk(A), or_c(pk(B), v:pk(C))), hash(H)):
    // <A> CHECKSIG NOTIF <B> CHECKSIG NOTIF <C> CHECKSIGVERIFY ENDIF ENDIF
    // SIZE 32 EQUALVERIFY HASHOP digest EQUAL
    let leaf = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_NOTIF)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_NOTIF)
        .push_x_only_key(&pk_c)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(hash_op)
        .push_slice(<&bitcoin::script::PushBytes>::try_from(digest).expect("digest pushable"))
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    let (parsed_a, parsed_b, parsed_c, parsed_kind, parsed_digest) =
        bare_tapscript_and_v_or_c_multi_hash_template(&leaf)
            .expect("test leaf is and_v(or_c multi-arm, hash)");
    assert_eq!(parsed_a, pk_a);
    assert_eq!(parsed_b, pk_b);
    assert_eq!(parsed_c, pk_c);
    assert_eq!(parsed_kind, kind);
    assert_eq!(parsed_digest, digest);
    // Must not parse as dual-key hash / multi-arm older|after / bare or_c.
    assert!(bare_tapscript_and_v_or_c_hash_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_or_c_multi_older_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_or_c_multi_after_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_or_c_older_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_or_c_after_template(&leaf).is_none());
    assert!(bare_tapscript_or_c_checksig_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_or_i_hash_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_pk_hash_template(&leaf).is_none());
    assert!(bare_tapscript_hash_preimage_template(&leaf).is_none());

    let spend_info = TaprootBuilder::new()
        .add_leaf(0, leaf.clone())
        .expect("add leaf")
        .finalize(&secp, internal_xonly)
        .expect("finalize tree");
    let merkle = spend_info.merkle_root();
    let control_block = spend_info
        .control_block(&(leaf.clone(), LeafVersion::TapScript))
        .expect("control block for leaf");
    let (psbt, spk) = p2tr_psbt_with_internal(internal_xonly, merkle);
    assert_eq!(spk, ScriptBuf::new_p2tr_tweaked(spend_info.output_key()));
    assert!(control_block.verify_taproot_commitment(
        &secp,
        p2tr_output_key(&spk).expect("output key"),
        &leaf
    ));
    (psbt, leaf, control_block, pk_a, pk_b, pk_c)
}

/// Multi-arm and_v(or_c nested, hash) A branch + matching preimage → Complete.
#[test]
fn finalize_taproot_and_v_or_c_multi_hash_a_branch_is_complete() {
    use bitcoin::hashes::{Hash, sha256};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let sk_a = [100u8; 32];
    let sk_b = [101u8; 32];
    let sk_c = [102u8; 32];
    let (preimage, digest) = sample_sha256_preimage_and_digest(103);
    let (mut psbt, leaf, control_block, pk_a, _pk_b, _pk_c) =
        p2tr_and_v_or_c_multi_hash_script_path_psbt(
            [104u8; 32],
            sk_a,
            sk_b,
            sk_c,
            TapscriptHashKind::Sha256,
            &digest,
        );
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    let sig_a = sample_tap_key_sig(sk_a, [105u8; 32]);
    psbt.inputs[0].tap_scripts.insert(
        control_block.clone(),
        (leaf.clone(), LeafVersion::TapScript),
    );
    psbt.inputs[0]
        .tap_script_sigs
        .insert((pk_a, leaf_hash), sig_a);
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(digest), preimage.to_vec());

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete() && fin.is_broadcast_ready(), "{fin:?}");
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("multi-arm hash A final")
        .to_vec();
    // <preimage> <sigA> <script> <cb>
    assert_eq!(items.len(), 4);
    assert_eq!(items[0], preimage.to_vec());
    assert_eq!(items[1], sig_a.to_vec());
    assert_eq!(items[2], leaf.as_bytes());
    assert_eq!(items[3], control_block.serialize());
    let _tx = extract_finalized_tx(psbt).unwrap();
}

