    let (mut psbt, leaf, control_block, pk_a, pk_b, pk_c) =
        p2tr_and_v_or_c_multi_hash_script_path_psbt(
            [122u8; 32],
            sk_a,
            sk_b,
            sk_c,
            TapscriptHashKind::Sha256,
            &digest,
        );
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    let sig_a = sample_tap_key_sig(sk_a, [123u8; 32]);
    let sig_b = sample_tap_key_sig(sk_b, [124u8; 32]);
    let sig_c = sample_tap_key_sig(sk_c, [125u8; 32]);
    psbt.inputs[0].tap_scripts.insert(
        control_block.clone(),
        (leaf.clone(), LeafVersion::TapScript),
    );
    psbt.inputs[0]
        .tap_script_sigs
        .insert((pk_a, leaf_hash), sig_a);
    psbt.inputs[0]
        .tap_script_sigs
        .insert((pk_b, leaf_hash), sig_b);
    psbt.inputs[0]
        .tap_script_sigs
        .insert((pk_c, leaf_hash), sig_c);
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(digest), preimage.to_vec());

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete(), "{fin:?}");
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("final")
        .to_vec();
    // A path: <preimage> <sigA> <script> <cb>
    assert_eq!(items.len(), 4, "A path is <preimage> <sigA> <script> <cb>");
    assert_eq!(items[0], preimage.to_vec());
