/// Multi-arm or_i older all three sigs → prefer A (deterministic).
#[test]
fn finalize_taproot_and_v_or_i_multi_older_all_sigs_prefers_a() {
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let sk_a = [45u8; 32];
    let sk_b = [46u8; 32];
    let sk_c = [47u8; 32];
    let older_n = 8u32;
    let (mut psbt, leaf, control_block, pk_a, pk_b, pk_c) =
        p2tr_and_v_or_i_multi_older_script_path_psbt([48u8; 32], sk_a, sk_b, sk_c, older_n);
    psbt.unsigned_tx.input[0].sequence = Sequence::from_height(8);
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    let sig_a = sample_tap_key_sig(sk_a, [49u8; 32]);
    let sig_b = sample_tap_key_sig(sk_b, [50u8; 32]);
    let sig_c = sample_tap_key_sig(sk_c, [51u8; 32]);
    psbt.inputs[0].tap_scripts.insert(
        control_block.clone(),
        (leaf.clone(), LeafVersion::TapScript),
    );
    psbt.inputs[0]
        .tap_script_sigs
        .insert((pk_a, leaf_hash), sig_a);
    psbt.inputs[0]
        .tap_script_sigs
        .insert((pk_b, leaf_hash), sig_b);
    psbt.inputs[0]
        .tap_script_sigs
        .insert((pk_c, leaf_hash), sig_c);

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete(), "{fin:?}");
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("final")
        .to_vec();
    assert_eq!(items.len(), 4, "A path is <sigA> <0x01> <script> <cb>");
    assert_eq!(
        items[0],
        sig_a.to_vec(),
        "must prefer A when all three present"
    );
    assert_eq!(items[1], vec![1u8]);
    assert_ne!(items[0], sig_b.to_vec());
    assert_ne!(items[0], sig_c.to_vec());
}

