/// multi-pk older missing one sig → Partial (never invent / no empty placeholders).
#[test]
fn finalize_taproot_and_v_multi_pk_older_missing_sig_is_partial() {
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let sks = [[201u8; 32], [202u8; 32]];
    let older_n = 5u32;
    let (mut psbt, leaf, control_block, keys) =
        p2tr_and_v_multi_pk_older_script_path_psbt([203u8; 32], &sks, older_n);
    psbt.unsigned_tx.input[0].sequence = Sequence::from_height(5);
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    psbt.inputs[0]
        .tap_scripts
        .insert(control_block, (leaf, LeafVersion::TapScript));
    psbt.inputs[0].tap_script_sigs.insert(
        (keys[0], leaf_hash),
        sample_tap_key_sig(sks[0], [204u8; 32]),
    );

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(!fin.is_complete() && !fin.is_broadcast_ready(), "{fin:?}");
    match &fin {
        FinalizeOutcome::Partial { detail, .. } => {
            let d = detail.to_ascii_lowercase();
            assert!(d.contains("multi-pk") || d.contains("and_v"), "{detail}");
            assert!(
                d.contains("insufficient") || d.contains("tap_script_sig"),
                "{detail}"
            );
            assert!(d.contains("not broadcast-ready"), "{detail}");
        }
        other => panic!("expected Partial, got {other:?}"),
    }
    assert!(psbt.inputs[0].final_script_witness.is_none());
    assert!(extract_finalized_tx(psbt).is_err());
}

