/// multi-pk older + bad control block → hard error.
#[test]
fn finalize_taproot_and_v_multi_pk_older_bad_control_block_is_hard_error() {
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let sks = [[210u8; 32], [211u8; 32]];
    let older_n = 4u32;
    let (mut psbt, leaf, _good_cb, keys) =
        p2tr_and_v_multi_pk_older_script_path_psbt([212u8; 32], &sks, older_n);
    psbt.unsigned_tx.input[0].sequence = Sequence::from_height(4);
    let secp = Secp256k1::new();
    let wrong_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[213u8; 32]).expect("wsk"));
    let (wrong_internal, wrong_parity) = wrong_kp.x_only_public_key();
    let bad_cb = bitcoin::taproot::ControlBlock {
        leaf_version: LeafVersion::TapScript,
        output_key_parity: wrong_parity,
        internal_key: wrong_internal,
        merkle_branch: Default::default(),
    };
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    psbt.inputs[0]
        .tap_scripts
        .insert(bad_cb, (leaf, LeafVersion::TapScript));
    psbt.inputs[0].tap_script_sigs.insert(
        (keys[0], leaf_hash),
        sample_tap_key_sig(sks[0], [214u8; 32]),
    );
    psbt.inputs[0].tap_script_sigs.insert(
        (keys[1], leaf_hash),
        sample_tap_key_sig(sks[1], [215u8; 32]),
    );

    let err = finalize_psbt(&mut psbt).unwrap_err();
    let msg = err.to_string().to_ascii_lowercase();
    assert!(
        msg.contains("control block")
            || msg.contains("verify")
            || msg.contains("tamper")
            || msg.contains("commit"),
        "{err}"
    );
    assert!(psbt.inputs[0].final_script_witness.is_none());
}

/// multi-pk after 2-of-2 with both sigs + satisfying nLockTime → Complete.
#[test]
fn finalize_taproot_and_v_multi_pk_after_2of2_is_complete() {
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let sks = [[216u8; 32], [217u8; 32]];
    let after_n = 9u32;
    let (mut psbt, leaf, control_block, keys) =
        p2tr_and_v_multi_pk_after_script_path_psbt([218u8; 32], &sks, after_n);
    // Present nLockTime that satisfies after(9) — never invented by finalize.
    psbt.unsigned_tx.lock_time = LockTime::from_height(9).expect("height 9");
    // Default ENABLE_RBF_NO_LOCKTIME enables absolute locktime (≠ Sequence::MAX).
    assert!(
        psbt.unsigned_tx.input[0]
            .sequence
            .enables_absolute_lock_time()
    );
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    let sig0 = sample_tap_key_sig(sks[0], [219u8; 32]);
    let sig1 = sample_tap_key_sig(sks[1], [220u8; 32]);
    psbt.inputs[0].tap_scripts.insert(
        control_block.clone(),
        (leaf.clone(), LeafVersion::TapScript),
    );
    psbt.inputs[0]
        .tap_script_sigs
        .insert((keys[0], leaf_hash), sig0);
    psbt.inputs[0]
        .tap_script_sigs
        .insert((keys[1], leaf_hash), sig1);

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete() && fin.is_broadcast_ready(), "{fin:?}");
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("multi-pk after final")
        .to_vec();
    assert_eq!(items.len(), 4);
    assert_eq!(items[0], sig1.to_vec());
    assert_eq!(items[1], sig0.to_vec());
    assert_eq!(items[2], leaf.as_bytes());
    assert_eq!(items[3], control_block.serialize());
    assert_eq!(
        psbt.unsigned_tx.lock_time,
        LockTime::from_height(9).expect("height 9")
    );
    assert!(extract_finalized_tx(psbt).is_ok());
}

