/// multi-pk after with final sequence (disables CLTV) → Partial.
#[test]
fn finalize_taproot_and_v_multi_pk_after_final_sequence_is_partial() {
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let sks = [[225u8; 32], [226u8; 32]];
    let after_n = 9u32;
    let (mut psbt, leaf, control_block, keys) =
        p2tr_and_v_multi_pk_after_script_path_psbt([227u8; 32], &sks, after_n);
    psbt.unsigned_tx.lock_time = LockTime::from_height(9).expect("height 9");
    // Final sequence disables nLockTime for this input.
    psbt.unsigned_tx.input[0].sequence = Sequence::MAX;
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    psbt.inputs[0]
        .tap_scripts
        .insert(control_block, (leaf, LeafVersion::TapScript));
    psbt.inputs[0].tap_script_sigs.insert(
        (keys[0], leaf_hash),
        sample_tap_key_sig(sks[0], [228u8; 32]),
    );
    psbt.inputs[0].tap_script_sigs.insert(
        (keys[1], leaf_hash),
        sample_tap_key_sig(sks[1], [229u8; 32]),
    );

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(!fin.is_complete(), "{fin:?}");
    match &fin {
        FinalizeOutcome::Partial { detail, .. } => {
            let d = detail.to_ascii_lowercase();
            assert!(
                d.contains("nlocktime")
                    || d.contains("after")
                    || d.contains("cltv")
                    || d.contains("sequence"),
                "{detail}"
            );
        }
        other => panic!("expected Partial, got {other:?}"),
    }
    assert!(psbt.inputs[0].final_script_witness.is_none());
}

/// multi-pk after with nLockTime too low (sequence still enables absolute locktime) → Partial.
#[test]
fn finalize_taproot_and_v_multi_pk_after_bad_locktime_is_partial() {
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let sks = [[20u8; 32], [21u8; 32]];
    let after_n = 50u32;
    let (mut psbt, leaf, control_block, keys) =
        p2tr_and_v_multi_pk_after_script_path_psbt([22u8; 32], &sks, after_n);
    // Present but insufficient nLockTime — finalize never invents a higher value.
    psbt.unsigned_tx.lock_time = LockTime::from_height(10).expect("height 10");
    psbt.unsigned_tx.input[0].sequence = Sequence::from_consensus(0xffff_fffe);
    assert!(
        psbt.unsigned_tx.input[0]
            .sequence
            .enables_absolute_lock_time()
    );
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    psbt.inputs[0]
        .tap_scripts
        .insert(control_block, (leaf, LeafVersion::TapScript));
    psbt.inputs[0]
        .tap_script_sigs
        .insert((keys[0], leaf_hash), sample_tap_key_sig(sks[0], [23u8; 32]));
    psbt.inputs[0]
        .tap_script_sigs
        .insert((keys[1], leaf_hash), sample_tap_key_sig(sks[1], [24u8; 32]));

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(!fin.is_complete(), "{fin:?}");
    match &fin {
        FinalizeOutcome::Partial { detail, .. } => {
            let d = detail.to_ascii_lowercase();
            assert!(
                d.contains("nlocktime")
                    || d.contains("cltv")
                    || d.contains("after")
                    || d.contains("locktime"),
                "{detail}"
            );
            assert!(
                d.contains("multi-pk") || d.contains("and_v"),
                "must name multi-pk residual: {detail}"
            );
        }
        other => panic!("expected Partial, got {other:?}"),
    }
    assert!(psbt.inputs[0].final_script_witness.is_none());
}

