/// multi-pk hash 2-of-2 with both sigs + preimage → Complete.
#[test]
fn finalize_taproot_and_v_multi_pk_hash_2of2_is_complete() {
    use bitcoin::hashes::{Hash, sha256};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let sks = [[230u8; 32], [231u8; 32]];
    let (preimage, digest) = sample_sha256_preimage_and_digest(232);
    let (mut psbt, leaf, control_block, keys) = p2tr_and_v_multi_pk_hash_script_path_psbt(
        [233u8; 32],
        &sks,
        TapscriptHashKind::Sha256,
        &digest,
    );
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    let sig0 = sample_tap_key_sig(sks[0], [234u8; 32]);
    let sig1 = sample_tap_key_sig(sks[1], [235u8; 32]);
    psbt.inputs[0].tap_scripts.insert(
        control_block.clone(),
        (leaf.clone(), LeafVersion::TapScript),
    );
    psbt.inputs[0]
        .tap_script_sigs
        .insert((keys[0], leaf_hash), sig0);
    psbt.inputs[0]
        .tap_script_sigs
        .insert((keys[1], leaf_hash), sig1);
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(digest), preimage.to_vec());

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete() && fin.is_broadcast_ready(), "{fin:?}");
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("multi-pk hash final")
        .to_vec();
    // <preimage> <sig1> <sig0> <script> <cb>
    assert_eq!(items.len(), 5);
    assert_eq!(items[0], preimage.to_vec());
    assert_eq!(items[1], sig1.to_vec());
    assert_eq!(items[2], sig0.to_vec());
    assert_eq!(items[3], leaf.as_bytes());
    assert_eq!(items[4], control_block.serialize());
    assert!(extract_finalized_tx(psbt).is_ok());
}

