    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    let sig_l0 = sample_tap_key_sig(left[0], [139u8; 32]);
    let sig_l1 = sample_tap_key_sig(left[1], [140u8; 32]);
    let sig_r = sample_tap_key_sig(right[0], [141u8; 32]);
