/// inheritance older partial IF + good ELSE material → Complete via ELSE.
#[test]
fn finalize_taproot_or_i_pk_and_v_pk_older_partial_if_good_else_is_complete() {
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let if_sks = [[29u8; 32], [30u8; 32]];
    let else_sks = [[31u8; 32]];
    let older_n = 14u32;
    let (mut psbt, leaf, control_block, if_keys, else_keys) =
        p2tr_or_i_pk_and_v_pk_older_script_path_psbt([32u8; 32], &if_sks, &else_sks, older_n);
    psbt.unsigned_tx.input[0].sequence = Sequence::from_height(14);
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    psbt.inputs[0].tap_scripts.insert(
        control_block.clone(),
        (leaf.clone(), LeafVersion::TapScript),
    );
    // Only first of two hot keys — IF incomplete; cold+CSV present → ELSE.
    psbt.inputs[0].tap_script_sigs.insert(
        (if_keys[0], leaf_hash),
        sample_tap_key_sig(if_sks[0], [33u8; 32]),
    );
    let cold_sig = sample_tap_key_sig(else_sks[0], [34u8; 32]);
    psbt.inputs[0]
        .tap_script_sigs
        .insert((else_keys[0], leaf_hash), cold_sig);

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete() && fin.is_broadcast_ready(), "{fin:?}");
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("inheritance older partial-IF good-ELSE final")
        .to_vec();
    // ELSE-shaped: <cold_sig> <empty> <script> <cb> — no partial-sig IF.
    assert_eq!(items.len(), 4);
    assert_eq!(items[0], cold_sig.to_vec());
    assert!(items[1].is_empty());
    assert_eq!(items[2], leaf.as_bytes());
    assert_eq!(items[3], control_block.serialize());
    assert!(extract_finalized_tx(psbt).is_ok());
}

