/// inheritance templates reject vault, and_v(or_i), bare or_i, sandwich.
#[test]
fn bare_tapscript_or_i_pk_and_v_pk_templates_reject_siblings() {
    use bitcoin::secp256k1::{Keypair, SecretKey};

    let secp = Secp256k1::new();
    let kp_a = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[76u8; 32]).expect("a"));
    let kp_b = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[77u8; 32]).expect("b"));
    let (pk_a, _) = kp_a.x_only_public_key();
    let (pk_b, _) = kp_b.x_only_public_key();

    // Bare vault (no cold key on ELSE) must not match inheritance.
    let vault = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_IF)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_ELSE)
        .push_int(5)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .into_script();
    assert!(bare_tapscript_or_i_and_v_pk_older_template(&vault).is_some());
    assert!(bare_tapscript_or_i_pk_and_v_pk_older_template(&vault).is_none());
    assert!(bare_tapscript_or_i_pk_and_v_pk_after_template(&vault).is_none());
    assert!(bare_tapscript_or_i_pk_and_v_pk_hash_template(&vault).is_none());

    // and_v(or_i, older): CSV outside ENDIF.
    let and_v_or_i = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_IF)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_ELSE)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .push_int(5)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .into_script();
    assert!(bare_tapscript_and_v_or_i_older_template(&and_v_or_i).is_some());
    assert!(bare_tapscript_or_i_pk_and_v_pk_older_template(&and_v_or_i).is_none());

    // Bare or_i dual CHECKSIG (no VERIFY / no CSV).
    let bare_or_i = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_IF)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_ELSE)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .into_script();
    assert!(bare_tapscript_or_i_checksig_template(&bare_or_i).is_some());
    assert!(bare_tapscript_or_i_pk_and_v_pk_older_template(&bare_or_i).is_none());

    // Positive inheritance samples match only their own kind.
    let inh_older = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_IF)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_ELSE)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_int(7)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .into_script();
    assert!(bare_tapscript_or_i_pk_and_v_pk_older_template(&inh_older).is_some());
    assert!(bare_tapscript_or_i_pk_and_v_pk_after_template(&inh_older).is_none());
    assert!(bare_tapscript_or_i_pk_and_v_pk_hash_template(&inh_older).is_none());
    assert!(bare_tapscript_or_i_and_v_pk_older_template(&inh_older).is_none());

    assert!(bare_tapscript_or_i_pk_and_v_pk_older_template(&ScriptBuf::new()).is_none());
    assert!(bare_tapscript_or_i_pk_and_v_pk_after_template(&ScriptBuf::new()).is_none());
    assert!(bare_tapscript_or_i_pk_and_v_pk_hash_template(&ScriptBuf::new()).is_none());
}

// -------------------------------------------------------------------------
// HTLC dual-path: or_i(and_v(v:pk…, hash), and_v(v:pk…, older|after))
// -------------------------------------------------------------------------

/// Build HTLC `or_i(and_v(v:pk…, hash), and_v(v:pk…, older(n)))` leaf.
fn p2tr_or_i_hash_and_v_pk_older_script_path_psbt(
    internal_sk: [u8; 32],
    if_sks: &[[u8; 32]],
    else_sks: &[[u8; 32]],
    kind: TapscriptHashKind,
    digest: &[u8],
    older_n: u32,
) -> (
    bitcoin::psbt::Psbt,
    ScriptBuf,
    bitcoin::taproot::ControlBlock,
    Vec<bitcoin::secp256k1::XOnlyPublicKey>,
    Vec<bitcoin::secp256k1::XOnlyPublicKey>,
) {
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TaprootBuilder};

    assert!(!if_sks.is_empty() && !else_sks.is_empty());
    assert_eq!(digest.len(), kind.expected_digest_len());

    let secp = Secp256k1::new();
    let internal_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&internal_sk).expect("isk"));
    let (internal_xonly, _) = internal_kp.x_only_public_key();

    let mut if_keys = Vec::with_capacity(if_sks.len());
    for sk_bytes in if_sks {
        let kp = Keypair::from_secret_key(&secp, &SecretKey::from_slice(sk_bytes).expect("sk"));
        let (xonly, _) = kp.x_only_public_key();
        if_keys.push(xonly);
    }
    let mut else_keys = Vec::with_capacity(else_sks.len());
    for sk_bytes in else_sks {
        let kp = Keypair::from_secret_key(&secp, &SecretKey::from_slice(sk_bytes).expect("sk"));
        let (xonly, _) = kp.x_only_public_key();
        else_keys.push(xonly);
    }

    let hash_op = match kind {
        TapscriptHashKind::Sha256 => bitcoin::opcodes::all::OP_SHA256,
        TapscriptHashKind::Hash256 => bitcoin::opcodes::all::OP_HASH256,
        TapscriptHashKind::Ripemd160 => bitcoin::opcodes::all::OP_RIPEMD160,
        TapscriptHashKind::Hash160 => bitcoin::opcodes::all::OP_HASH160,
    };
    let mut builder = bitcoin::script::Builder::new().push_opcode(bitcoin::opcodes::all::OP_IF);
    for pk in &if_keys {
        builder = builder
            .push_x_only_key(pk)
            .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY);
    }
    builder = builder
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(hash_op)
        .push_slice(<&bitcoin::script::PushBytes>::try_from(digest).expect("digest"))
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .push_opcode(bitcoin::opcodes::all::OP_ELSE);
    for pk in &else_keys {
        builder = builder
            .push_x_only_key(pk)
            .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY);
    }
    let leaf = builder
        .push_int(i64::from(older_n))
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .into_script();
    let (p_if, p_else, p_kind, p_digest, p_n) =
        bare_tapscript_or_i_hash_and_v_pk_older_template(&leaf)
            .expect("test leaf is HTLC hash+older");
    assert_eq!(p_if, if_keys);
    assert_eq!(p_else, else_keys);
    assert_eq!(p_kind, kind);
    assert_eq!(p_digest, digest);
    assert_eq!(p_n, older_n);
    // Must not cross-match inheritance / vault / and_v(or_i).
    assert!(bare_tapscript_or_i_pk_and_v_pk_older_template(&leaf).is_none());
    assert!(bare_tapscript_or_i_and_v_pk_older_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_or_i_older_template(&leaf).is_none());
    assert!(bare_tapscript_or_i_hash_and_v_pk_after_template(&leaf).is_none());

    let spend_info = TaprootBuilder::new()
        .add_leaf(0, leaf.clone())
        .expect("add leaf")
        .finalize(&secp, internal_xonly)
        .expect("finalize tree");
    let merkle = spend_info.merkle_root();
    let control_block = spend_info
        .control_block(&(leaf.clone(), LeafVersion::TapScript))
        .expect("control block for leaf");
    let (psbt, spk) = p2tr_psbt_with_internal(internal_xonly, merkle);
    assert_eq!(spk, ScriptBuf::new_p2tr_tweaked(spend_info.output_key()));
    (psbt, leaf, control_block, if_keys, else_keys)
}

/// Build HTLC `or_i(and_v(v:pk…, hash), and_v(v:pk…, after(n)))` leaf.
fn p2tr_or_i_hash_and_v_pk_after_script_path_psbt(
    internal_sk: [u8; 32],
    if_sks: &[[u8; 32]],
    else_sks: &[[u8; 32]],
    kind: TapscriptHashKind,
    digest: &[u8],
    after_n: u32,
) -> (
    bitcoin::psbt::Psbt,
    ScriptBuf,
    bitcoin::taproot::ControlBlock,
    Vec<bitcoin::secp256k1::XOnlyPublicKey>,
    Vec<bitcoin::secp256k1::XOnlyPublicKey>,
) {
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TaprootBuilder};

    assert!(!if_sks.is_empty() && !else_sks.is_empty());
    assert_eq!(digest.len(), kind.expected_digest_len());

    let secp = Secp256k1::new();
    let internal_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&internal_sk).expect("isk"));
    let (internal_xonly, _) = internal_kp.x_only_public_key();

    let mut if_keys = Vec::with_capacity(if_sks.len());
    for sk_bytes in if_sks {
        let kp = Keypair::from_secret_key(&secp, &SecretKey::from_slice(sk_bytes).expect("sk"));
        let (xonly, _) = kp.x_only_public_key();
        if_keys.push(xonly);
    }
    let mut else_keys = Vec::with_capacity(else_sks.len());
    for sk_bytes in else_sks {
        let kp = Keypair::from_secret_key(&secp, &SecretKey::from_slice(sk_bytes).expect("sk"));
        let (xonly, _) = kp.x_only_public_key();
        else_keys.push(xonly);
    }

    let hash_op = match kind {
        TapscriptHashKind::Sha256 => bitcoin::opcodes::all::OP_SHA256,
        TapscriptHashKind::Hash256 => bitcoin::opcodes::all::OP_HASH256,
        TapscriptHashKind::Ripemd160 => bitcoin::opcodes::all::OP_RIPEMD160,
        TapscriptHashKind::Hash160 => bitcoin::opcodes::all::OP_HASH160,
    };
    let mut builder = bitcoin::script::Builder::new().push_opcode(bitcoin::opcodes::all::OP_IF);
    for pk in &if_keys {
        builder = builder
            .push_x_only_key(pk)
            .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY);
    }
    builder = builder
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(hash_op)
        .push_slice(<&bitcoin::script::PushBytes>::try_from(digest).expect("digest"))
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .push_opcode(bitcoin::opcodes::all::OP_ELSE);
    for pk in &else_keys {
        builder = builder
            .push_x_only_key(pk)
            .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY);
    }
    let leaf = builder
        .push_int(i64::from(after_n))
        .push_opcode(bitcoin::opcodes::all::OP_CLTV)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .into_script();
    let (p_if, p_else, p_kind, p_digest, p_n) =
        bare_tapscript_or_i_hash_and_v_pk_after_template(&leaf)
            .expect("test leaf is HTLC hash+after");
    assert_eq!(p_if, if_keys);
    assert_eq!(p_else, else_keys);
    assert_eq!(p_kind, kind);
    assert_eq!(p_digest, digest);
    assert_eq!(p_n, after_n);
    assert!(bare_tapscript_or_i_hash_and_v_pk_older_template(&leaf).is_none());
    assert!(bare_tapscript_or_i_pk_and_v_pk_after_template(&leaf).is_none());
    assert!(bare_tapscript_or_i_and_v_pk_after_template(&leaf).is_none());

    let spend_info = TaprootBuilder::new()
        .add_leaf(0, leaf.clone())
        .expect("add leaf")
        .finalize(&secp, internal_xonly)
        .expect("finalize tree");
    let merkle = spend_info.merkle_root();
    let control_block = spend_info
        .control_block(&(leaf.clone(), LeafVersion::TapScript))
        .expect("control block for leaf");
    let (psbt, spk) = p2tr_psbt_with_internal(internal_xonly, merkle);
    assert_eq!(spk, ScriptBuf::new_p2tr_tweaked(spend_info.output_key()));
    (psbt, leaf, control_block, if_keys, else_keys)
}

/// HTLC older IF claim (sig + preimage) → Complete.
#[test]
fn finalize_taproot_or_i_hash_and_v_pk_older_if_is_complete() {
    use bitcoin::hashes::{Hash, sha256};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let if_sks = [[80u8; 32]];
    let else_sks = [[81u8; 32]];
    let older_n = 6u32;
    let (preimage, digest) = sample_sha256_preimage_and_digest(82);
    let (mut psbt, leaf, control_block, if_keys, _else_keys) =
        p2tr_or_i_hash_and_v_pk_older_script_path_psbt(
            [83u8; 32],
            &if_sks,
            &else_sks,
            TapscriptHashKind::Sha256,
            &digest,
            older_n,
        );
    // Sequence also satisfies, but IF claim should still be preferred.
    psbt.unsigned_tx.input[0].sequence = Sequence::from_height(6);
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    let sig = sample_tap_key_sig(if_sks[0], [84u8; 32]);
    psbt.inputs[0].tap_scripts.insert(
        control_block.clone(),
        (leaf.clone(), LeafVersion::TapScript),
    );
    psbt.inputs[0]
        .tap_script_sigs
        .insert((if_keys[0], leaf_hash), sig);
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(digest), preimage.to_vec());

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete() && fin.is_broadcast_ready(), "{fin:?}");
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("HTLC older IF final")
        .to_vec();
    // <preimage> <sig_claim> <0x01> <script> <cb>
    assert_eq!(items.len(), 5);
    assert_eq!(items[0], preimage.to_vec());
    assert_eq!(items[1], sig.to_vec());
    assert_eq!(items[2], vec![1u8]);
    assert_eq!(items[3], leaf.as_bytes());
    assert_eq!(items[4], control_block.serialize());
    assert!(extract_finalized_tx(psbt).is_ok());
}

