/// HTLC older missing both arms → Partial.
#[test]
fn finalize_taproot_or_i_hash_and_v_pk_older_missing_both_is_partial() {
    use bitcoin::taproot::LeafVersion;

    let if_sks = [[99u8; 32]];
    let else_sks = [[100u8; 32]];
    let older_n = 12u32;
    let (_preimage, digest) = sample_sha256_preimage_and_digest(101);
    let (mut psbt, leaf, control_block, _if_keys, _else_keys) =
        p2tr_or_i_hash_and_v_pk_older_script_path_psbt(
            [102u8; 32],
            &if_sks,
            &else_sks,
            TapscriptHashKind::Sha256,
            &digest,
            older_n,
        );
    psbt.unsigned_tx.input[0].sequence = Sequence::from_height(1);
    psbt.inputs[0]
        .tap_scripts
        .insert(control_block, (leaf, LeafVersion::TapScript));

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(!fin.is_complete() && !fin.is_broadcast_ready(), "{fin:?}");
    match &fin {
        FinalizeOutcome::Partial { detail, .. } => {
            let d = detail.to_ascii_lowercase();
            assert!(
                d.contains("or_i")
                    || d.contains("hash")
                    || d.contains("older")
                    || d.contains("preimage")
                    || d.contains("insufficient")
                    || d.contains("sequence")
                    || d.contains("claim")
                    || d.contains("refund"),
                "{detail}"
            );
        }
        other => panic!("expected Partial, got {other:?}"),
    }
}

