/// Reverse HTLC templates reject classic HTLC, inheritance, vault, sandwich.
#[test]
fn bare_tapscript_or_i_older_and_v_pk_hash_templates_reject_siblings() {
    use bitcoin::secp256k1::{Keypair, SecretKey};

    let secp = Secp256k1::new();
    let kp_a = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[210u8; 32]).expect("a"));
    let kp_b = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[211u8; 32]).expect("b"));
    let (pk_a, _) = kp_a.x_only_public_key();
    let (pk_b, _) = kp_b.x_only_public_key();

    // Classic HTLC (hash on IF) must not match reverse.
    let digest = [0xcdu8; 32];
    let classic = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_IF)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&digest)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .push_opcode(bitcoin::opcodes::all::OP_ELSE)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_int(7)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .into_script();
    assert!(bare_tapscript_or_i_hash_and_v_pk_older_template(&classic).is_some());
    assert!(bare_tapscript_or_i_older_and_v_pk_hash_template(&classic).is_none());
    assert!(bare_tapscript_or_i_after_and_v_pk_hash_template(&classic).is_none());

    // Inheritance older (IF CHECKSIG not VERIFY+CSV).
    let inh_older = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_IF)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_ELSE)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_int(5)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .into_script();
    assert!(bare_tapscript_or_i_pk_and_v_pk_older_template(&inh_older).is_some());
    assert!(bare_tapscript_or_i_older_and_v_pk_hash_template(&inh_older).is_none());

    // Bare vault (ELSE no keys).
    let vault = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_IF)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_ELSE)
        .push_int(5)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .into_script();
    assert!(bare_tapscript_or_i_and_v_pk_older_template(&vault).is_some());
    assert!(bare_tapscript_or_i_older_and_v_pk_hash_template(&vault).is_none());

    // and_v(or_i, older): CSV outside ENDIF.
    let and_v_or_i = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_IF)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_ELSE)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .push_int(5)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .into_script();
    assert!(bare_tapscript_and_v_or_i_older_template(&and_v_or_i).is_some());
    assert!(bare_tapscript_or_i_older_and_v_pk_hash_template(&and_v_or_i).is_none());

    // Positive reverse HTLC samples match only their own kind.
    let rev_older = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_IF)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_int(7)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .push_opcode(bitcoin::opcodes::all::OP_ELSE)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&digest)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .into_script();
    assert!(bare_tapscript_or_i_older_and_v_pk_hash_template(&rev_older).is_some());
    assert!(bare_tapscript_or_i_after_and_v_pk_hash_template(&rev_older).is_none());
    assert!(bare_tapscript_or_i_hash_and_v_pk_older_template(&rev_older).is_none());
    assert!(bare_tapscript_or_i_pk_and_v_pk_hash_template(&rev_older).is_none());
    assert!(bare_tapscript_or_i_and_v_pk_older_template(&rev_older).is_none());
    // Dual-hash must not match reverse HTLC (IF has CSV, not hash).
    assert!(bare_tapscript_or_i_hash_and_v_pk_hash_template(&rev_older).is_none());

    assert!(bare_tapscript_or_i_older_and_v_pk_hash_template(&ScriptBuf::new()).is_none());
    assert!(bare_tapscript_or_i_after_and_v_pk_hash_template(&ScriptBuf::new()).is_none());
}

// -------------------------------------------------------------------------
// Dual-hash: or_i(and_v(v:pk…, hash(H1)), and_v(v:pk…, hash(H2)))
// -------------------------------------------------------------------------

/// Build dual-hash `or_i(and_v(v:pk…, hash(H1)), and_v(v:pk…, hash(H2)))` leaf.
fn p2tr_or_i_hash_and_v_pk_hash_script_path_psbt(
    internal_sk: [u8; 32],
    if_sks: &[[u8; 32]],
    else_sks: &[[u8; 32]],
    if_kind: TapscriptHashKind,
    if_digest: &[u8],
    else_kind: TapscriptHashKind,
    else_digest: &[u8],
) -> (
    bitcoin::psbt::Psbt,
    ScriptBuf,
    bitcoin::taproot::ControlBlock,
    Vec<bitcoin::secp256k1::XOnlyPublicKey>,
    Vec<bitcoin::secp256k1::XOnlyPublicKey>,
) {
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TaprootBuilder};

    assert!(!if_sks.is_empty() && !else_sks.is_empty());
    assert_eq!(if_digest.len(), if_kind.expected_digest_len());
    assert_eq!(else_digest.len(), else_kind.expected_digest_len());

    let secp = Secp256k1::new();
    let internal_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&internal_sk).expect("isk"));
    let (internal_xonly, _) = internal_kp.x_only_public_key();

    let mut if_keys = Vec::with_capacity(if_sks.len());
    for sk_bytes in if_sks {
        let kp = Keypair::from_secret_key(&secp, &SecretKey::from_slice(sk_bytes).expect("sk"));
        let (xonly, _) = kp.x_only_public_key();
        if_keys.push(xonly);
    }
    let mut else_keys = Vec::with_capacity(else_sks.len());
    for sk_bytes in else_sks {
        let kp = Keypair::from_secret_key(&secp, &SecretKey::from_slice(sk_bytes).expect("sk"));
        let (xonly, _) = kp.x_only_public_key();
        else_keys.push(xonly);
    }

    let hash_op = |kind: TapscriptHashKind| match kind {
        TapscriptHashKind::Sha256 => bitcoin::opcodes::all::OP_SHA256,
        TapscriptHashKind::Hash256 => bitcoin::opcodes::all::OP_HASH256,
        TapscriptHashKind::Ripemd160 => bitcoin::opcodes::all::OP_RIPEMD160,
        TapscriptHashKind::Hash160 => bitcoin::opcodes::all::OP_HASH160,
    };
    let mut builder = bitcoin::script::Builder::new().push_opcode(bitcoin::opcodes::all::OP_IF);
    for pk in &if_keys {
        builder = builder
            .push_x_only_key(pk)
            .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY);
    }
    builder = builder
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(hash_op(if_kind))
        .push_slice(<&bitcoin::script::PushBytes>::try_from(if_digest).expect("if digest"))
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .push_opcode(bitcoin::opcodes::all::OP_ELSE);
    for pk in &else_keys {
        builder = builder
            .push_x_only_key(pk)
            .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY);
    }
    let leaf = builder
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(hash_op(else_kind))
        .push_slice(<&bitcoin::script::PushBytes>::try_from(else_digest).expect("else digest"))
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .into_script();
    let (p_if, p_else, p_ik, p_id, p_ek, p_ed) =
        bare_tapscript_or_i_hash_and_v_pk_hash_template(&leaf)
            .expect("test leaf is dual-hash or_i");
    assert_eq!(p_if, if_keys);
    assert_eq!(p_else, else_keys);
    assert_eq!(p_ik, if_kind);
    assert_eq!(p_id, if_digest);
    assert_eq!(p_ek, else_kind);
    assert_eq!(p_ed, else_digest);
    // Must not cross-match classic HTLC / reverse HTLC / inheritance / vault.
    assert!(bare_tapscript_or_i_hash_and_v_pk_older_template(&leaf).is_none());
    assert!(bare_tapscript_or_i_hash_and_v_pk_after_template(&leaf).is_none());
    assert!(bare_tapscript_or_i_older_and_v_pk_hash_template(&leaf).is_none());
    assert!(bare_tapscript_or_i_after_and_v_pk_hash_template(&leaf).is_none());
    assert!(bare_tapscript_or_i_pk_and_v_pk_older_template(&leaf).is_none());
    assert!(bare_tapscript_or_i_pk_and_v_pk_hash_template(&leaf).is_none());
    assert!(bare_tapscript_or_i_and_v_pk_older_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_or_i_hash_template(&leaf).is_none());

    let spend_info = TaprootBuilder::new()
        .add_leaf(0, leaf.clone())
        .expect("add leaf")
        .finalize(&secp, internal_xonly)
        .expect("finalize tree");
    let merkle = spend_info.merkle_root();
    let control_block = spend_info
        .control_block(&(leaf.clone(), LeafVersion::TapScript))
        .expect("control block for leaf");
    let (psbt, spk) = p2tr_psbt_with_internal(internal_xonly, merkle);
    assert_eq!(spk, ScriptBuf::new_p2tr_tweaked(spend_info.output_key()));
    (psbt, leaf, control_block, if_keys, else_keys)
}

/// Dual-hash IF claim (sig + H1 preimage) → Complete; prefers IF when both ready.
#[test]
fn finalize_taproot_or_i_hash_and_v_pk_hash_if_is_complete() {
    use bitcoin::hashes::{Hash, sha256};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let if_sks = [[220u8; 32]];
    let else_sks = [[221u8; 32]];
    let (pre_if, dig_if) = sample_sha256_preimage_and_digest(222);
    let (pre_else, dig_else) = sample_sha256_preimage_and_digest(223);
    let (mut psbt, leaf, control_block, if_keys, else_keys) =
        p2tr_or_i_hash_and_v_pk_hash_script_path_psbt(
            [224u8; 32],
            &if_sks,
            &else_sks,
            TapscriptHashKind::Sha256,
            &dig_if,
            TapscriptHashKind::Sha256,
            &dig_else,
        );
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    let if_sig = sample_tap_key_sig(if_sks[0], [225u8; 32]);
    let else_sig = sample_tap_key_sig(else_sks[0], [226u8; 32]);
    psbt.inputs[0].tap_scripts.insert(
        control_block.clone(),
        (leaf.clone(), LeafVersion::TapScript),
    );
    psbt.inputs[0]
        .tap_script_sigs
        .insert((if_keys[0], leaf_hash), if_sig);
    // ELSE material also present — IF still preferred.
    psbt.inputs[0]
        .tap_script_sigs
        .insert((else_keys[0], leaf_hash), else_sig);
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(dig_if), pre_if.to_vec());
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(dig_else), pre_else.to_vec());

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete() && fin.is_broadcast_ready(), "{fin:?}");
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("dual-hash IF final")
        .to_vec();
    // bottom→top: preimage_H1, sig_if, 0x01
    assert_eq!(items.len(), 5);
    assert_eq!(items[0], pre_if.to_vec());
    assert_eq!(items[1], if_sig.to_vec());
    assert_eq!(items[2], vec![1u8]);
    assert_eq!(items[3], leaf.as_bytes());
    assert_eq!(items[4], control_block.serialize());
    assert!(extract_finalized_tx(psbt).is_ok());
}

