/// Combined hash+timeout after (CLTV) → Complete.
#[test]
fn finalize_taproot_and_v_pk_hash_after_is_complete() {
    use bitcoin::hashes::{Hash, sha256};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let key_sks = [[90u8; 32]];
    let (pre, dig) = sample_sha256_preimage_and_digest(91);
    let (mut psbt, leaf, control_block, keys) = p2tr_and_v_pk_hash_lock_script_path_psbt(
        [92u8; 32],
        &key_sks,
        TapscriptHashKind::Sha256,
        &dig,
        DualTimeoutLock::After(100),
    );
    psbt.unsigned_tx.input[0].sequence = Sequence::ENABLE_RBF_NO_LOCKTIME;
    psbt.unsigned_tx.lock_time = LockTime::from_height(100).expect("height 100");
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    let sig = sample_tap_key_sig(key_sks[0], [93u8; 32]);
    psbt.inputs[0].tap_scripts.insert(
        control_block.clone(),
        (leaf.clone(), LeafVersion::TapScript),
    );
    psbt.inputs[0]
        .tap_script_sigs
        .insert((keys[0], leaf_hash), sig);
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(dig), pre.to_vec());

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete() && fin.is_broadcast_ready(), "{fin:?}");
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("pk+hash+after final")
        .to_vec();
    assert_eq!(items[0], pre.to_vec());
    assert_eq!(items[1], sig.to_vec());
    assert!(extract_finalized_tx(psbt).is_ok());
}

