/// Reverse combined hash+timeout + bad control block → hard error.
#[test]
fn finalize_taproot_and_v_hash_pk_lock_bad_control_is_hard_error() {
    use bitcoin::hashes::{Hash, sha256};
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let key_sks = [[153u8; 32]];
    let (pre, dig) = sample_sha256_preimage_and_digest(154);
    let (mut psbt, leaf, _good_cb, keys) = p2tr_and_v_hash_pk_lock_script_path_psbt(
        [155u8; 32],
        &key_sks,
        TapscriptHashKind::Sha256,
        &dig,
        DualTimeoutLock::Older(3),
    );
    psbt.unsigned_tx.input[0].sequence = Sequence::from_height(3);
    let secp = Secp256k1::new();
    let wrong_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[156u8; 32]).expect("wsk"));
    let (wrong_internal, wrong_parity) = wrong_kp.x_only_public_key();
    let bad_cb = bitcoin::taproot::ControlBlock {
        leaf_version: LeafVersion::TapScript,
        output_key_parity: wrong_parity,
        internal_key: wrong_internal,
        merkle_branch: Default::default(),
    };
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    psbt.inputs[0]
        .tap_scripts
        .insert(bad_cb, (leaf, LeafVersion::TapScript));
    psbt.inputs[0].tap_script_sigs.insert(
        (keys[0], leaf_hash),
        sample_tap_key_sig(key_sks[0], [157u8; 32]),
    );
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(dig), pre.to_vec());

    let err = finalize_psbt(&mut psbt).unwrap_err();
    let msg = err.to_string().to_ascii_lowercase();
    assert!(
        msg.contains("control block")
            || msg.contains("verify")
            || msg.contains("tamper")
            || msg.contains("commit"),
        "{err}"
    );
    assert!(psbt.inputs[0].final_script_witness.is_none());
}

/// Reverse combined templates reject reverse multi-hash, pk-first combined, sandwich, HTLC.
#[test]
fn bare_tapscript_and_v_hash_pk_lock_templates_reject_siblings() {
    use bitcoin::secp256k1::{Keypair, SecretKey};

    let secp = Secp256k1::new();
    let kp_a = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[158u8; 32]).expect("a"));
    let kp_b = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[159u8; 32]).expect("b"));
    let (pk_a, _) = kp_a.x_only_public_key();
    let (pk_b, _) = kp_b.x_only_public_key();
    let digest = [0xabu8; 32];

    // and_v(v:hash, pk) ends CHECKSIG — not CHECKSIGVERIFY+CSV.
    let hash_pk = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&digest)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .into_script();
    assert!(bare_tapscript_and_v_hash_pk_template(&hash_pk).is_some());
    assert!(bare_tapscript_and_v_hash_pk_lock_template(&hash_pk).is_none());

    // Reverse multi-hash and_v(v:hash, and_v(v:pk…)) — ends CHECKSIG, no lock.
    let rev_multi = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&digest)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .into_script();
    assert!(bare_tapscript_and_v_hash_multi_pk_template(&rev_multi).is_some());
    assert!(bare_tapscript_and_v_hash_pk_lock_template(&rev_multi).is_none());

    // Pk-first combined and_v(v:pk…, and_v(v:hash, older)) — keys before hash.
    let pk_first = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&digest)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_int(8)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .into_script();
    assert!(bare_tapscript_and_v_pk_hash_lock_template(&pk_first).is_some());
    assert!(bare_tapscript_and_v_hash_pk_lock_template(&pk_first).is_none());

    // Sandwich and_v(v:pk, and_v(v:hash, pk)) — right keys after EQUALVERIFY.
    let sandwich = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&digest)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .into_script();
    assert!(bare_tapscript_and_v_multi_pk_hash_multi_pk_template(&sandwich).is_some());
    assert!(bare_tapscript_and_v_hash_pk_lock_template(&sandwich).is_none());

    // Classic HTLC or_i — dual-path OR, not AND.
    let classic = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_IF)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&digest)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .push_opcode(bitcoin::opcodes::all::OP_ELSE)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_int(7)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .into_script();
    assert!(bare_tapscript_or_i_hash_and_v_pk_older_template(&classic).is_some());
    assert!(bare_tapscript_and_v_hash_pk_lock_template(&classic).is_none());

    // Positive sample matches only reverse combined hash+timeout.
    let good = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&digest)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_int(8)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .into_script();
    let parts = bare_tapscript_and_v_hash_pk_lock_template(&good).expect("good");
    assert_eq!(parts.0, vec![pk_a]);
    assert_eq!(parts.1, TapscriptHashKind::Sha256);
    assert_eq!(parts.2, digest);
    assert_eq!(parts.3, DualTimeoutLock::Older(8));
    assert!(bare_tapscript_and_v_pk_hash_lock_template(&good).is_none());
    assert!(bare_tapscript_and_v_hash_pk_template(&good).is_none());
    assert!(bare_tapscript_and_v_hash_multi_pk_template(&good).is_none());
    assert!(bare_tapscript_or_i_hash_and_v_pk_older_template(&good).is_none());

    // after variant.
    let good_after = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&digest)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_int(150)
        .push_opcode(bitcoin::opcodes::all::OP_CLTV)
        .into_script();
    let parts_a = bare_tapscript_and_v_hash_pk_lock_template(&good_after).expect("after");
    assert_eq!(parts_a.3, DualTimeoutLock::After(150));

    assert!(bare_tapscript_and_v_hash_pk_lock_template(&ScriptBuf::new()).is_none());
}

// -------------------------------------------------------------------------
// Lock-first combined hash+timeout: and_v(v:older|after, and_v(v:pk…, hash))
// -------------------------------------------------------------------------

/// Build lock-first combined hash+timeout
/// `and_v(v:older|after, and_v(v:pk…, hash(H)))` leaf.
fn p2tr_and_v_lock_pk_hash_script_path_psbt(
    internal_sk: [u8; 32],
    key_sks: &[[u8; 32]],
    kind: TapscriptHashKind,
    digest: &[u8],
    lock: DualTimeoutLock,
) -> (
    bitcoin::psbt::Psbt,
    ScriptBuf,
    bitcoin::taproot::ControlBlock,
    Vec<bitcoin::secp256k1::XOnlyPublicKey>,
) {
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TaprootBuilder};

    assert!(!key_sks.is_empty());
    assert_eq!(digest.len(), kind.expected_digest_len());

    let secp = Secp256k1::new();
    let internal_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&internal_sk).expect("isk"));
    let (internal_xonly, _) = internal_kp.x_only_public_key();

    let mut keys = Vec::with_capacity(key_sks.len());
    for sk_bytes in key_sks {
        let kp = Keypair::from_secret_key(&secp, &SecretKey::from_slice(sk_bytes).expect("sk"));
        let (xonly, _) = kp.x_only_public_key();
        keys.push(xonly);
    }

    let hash_op = match kind {
        TapscriptHashKind::Sha256 => bitcoin::opcodes::all::OP_SHA256,
        TapscriptHashKind::Hash256 => bitcoin::opcodes::all::OP_HASH256,
        TapscriptHashKind::Ripemd160 => bitcoin::opcodes::all::OP_RIPEMD160,
        TapscriptHashKind::Hash160 => bitcoin::opcodes::all::OP_HASH160,
    };
    let mut builder = match lock {
        DualTimeoutLock::Older(n) => bitcoin::script::Builder::new()
            .push_int(i64::from(n))
            .push_opcode(bitcoin::opcodes::all::OP_CSV)
            .push_opcode(bitcoin::opcodes::all::OP_VERIFY),
        DualTimeoutLock::After(n) => bitcoin::script::Builder::new()
            .push_int(i64::from(n))
            .push_opcode(bitcoin::opcodes::all::OP_CLTV)
            .push_opcode(bitcoin::opcodes::all::OP_VERIFY),
    };
    for pk in &keys {
        builder = builder
            .push_x_only_key(pk)
            .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY);
    }
    builder = builder
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(hash_op)
        .push_slice(<&bitcoin::script::PushBytes>::try_from(digest).expect("digest"))
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL);
    let leaf = builder.into_script();
    let (p_keys, p_kind, p_dig, p_lock) =
        bare_tapscript_and_v_lock_pk_hash_template(&leaf).expect("test leaf is lock+pk+hash");
    assert_eq!(p_keys, keys);
    assert_eq!(p_kind, kind);
    assert_eq!(p_dig, digest);
    assert_eq!(p_lock, lock);
    // Must not cross-match reverse multi older/after / multi-pk hash / pk-first
    // combined / reverse combined / sandwich / HTLC.
    assert!(bare_tapscript_and_v_older_multi_pk_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_after_multi_pk_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_pk_hash_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_multi_pk_hash_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_pk_hash_lock_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_hash_pk_lock_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_pk_lock_hash_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_multi_pk_hash_multi_pk_template(&leaf).is_none());
    assert!(bare_tapscript_or_i_hash_and_v_pk_older_template(&leaf).is_none());
    assert!(bare_tapscript_or_i_older_and_v_pk_hash_template(&leaf).is_none());
    assert!(bare_tapscript_or_i_lock_and_v_pk_lock_template(&leaf).is_none());

    let spend_info = TaprootBuilder::new()
        .add_leaf(0, leaf.clone())
        .expect("add leaf")
        .finalize(&secp, internal_xonly)
        .expect("finalize tree");
    let merkle = spend_info.merkle_root();
    let control_block = spend_info
        .control_block(&(leaf.clone(), LeafVersion::TapScript))
        .expect("control block for leaf");
    let (psbt, spk) = p2tr_psbt_with_internal(internal_xonly, merkle);
    assert_eq!(spk, ScriptBuf::new_p2tr_tweaked(spend_info.output_key()));
    (psbt, leaf, control_block, keys)
}

/// Lock-first combined older: sig + preimage + good nSequence → Complete.
#[test]
fn finalize_taproot_and_v_older_pk_hash_is_complete() {
    use bitcoin::hashes::{Hash, sha256};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let key_sks = [[160u8; 32]];
    let (pre, dig) = sample_sha256_preimage_and_digest(161);
    let older_n = 6u32;
    let (mut psbt, leaf, control_block, keys) = p2tr_and_v_lock_pk_hash_script_path_psbt(
        [162u8; 32],
        &key_sks,
        TapscriptHashKind::Sha256,
        &dig,
        DualTimeoutLock::Older(older_n),
    );
    psbt.unsigned_tx.input[0].sequence = Sequence::from_height(6);
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    let sig = sample_tap_key_sig(key_sks[0], [163u8; 32]);
    psbt.inputs[0].tap_scripts.insert(
        control_block.clone(),
        (leaf.clone(), LeafVersion::TapScript),
    );
    psbt.inputs[0]
        .tap_script_sigs
        .insert((keys[0], leaf_hash), sig);
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(dig), pre.to_vec());

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete() && fin.is_broadcast_ready(), "{fin:?}");
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("older+pk+hash final")
        .to_vec();
    // bottom→top: preimage, sig, leaf, control
    assert_eq!(items.len(), 4);
    assert_eq!(items[0], pre.to_vec());
    assert_eq!(items[1], sig.to_vec());
    assert_eq!(items[2], leaf.as_bytes());
    assert_eq!(items[3], control_block.serialize());
    assert!(extract_finalized_tx(psbt).is_ok());
}

