/// Pk+lock+hash combined missing preimage → Partial (never invents).
#[test]
fn finalize_taproot_and_v_pk_lock_hash_missing_preimage_is_partial() {
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let key_sks = [[218u8; 32]];
    let (_pre, dig) = sample_sha256_preimage_and_digest(219);
    let (mut psbt, leaf, control_block, keys) = p2tr_and_v_pk_lock_hash_script_path_psbt(
        [220u8; 32],
        &key_sks,
        TapscriptHashKind::Sha256,
        &dig,
        DualTimeoutLock::Older(3),
    );
    psbt.unsigned_tx.input[0].sequence = Sequence::from_height(3);
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    psbt.inputs[0]
        .tap_scripts
        .insert(control_block, (leaf, LeafVersion::TapScript));
    psbt.inputs[0].tap_script_sigs.insert(
        (keys[0], leaf_hash),
        sample_tap_key_sig(key_sks[0], [221u8; 32]),
    );

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(!fin.is_complete() && !fin.is_broadcast_ready(), "{fin:?}");
    assert!(psbt.inputs[0].final_script_witness.is_none());
    match &fin {
        FinalizeOutcome::Partial { detail, .. } => {
            let d = detail.to_ascii_lowercase();
            assert!(
                d.contains("preimage") || d.contains("hash") || d.contains("and_v"),
                "{detail}"
            );
        }
        other => panic!("expected Partial, got {other:?}"),
    }
}

