/// Hash+lock+pk combined + bad control block → hard error.
#[test]
fn finalize_taproot_and_v_hash_lock_pk_bad_control_is_hard_error() {
    use bitcoin::hashes::{Hash, sha256};
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let key_sks = [[33u8; 32]];
    let (pre, dig) = sample_sha256_preimage_and_digest(34);
    let (mut psbt, leaf, _good_cb, keys) = p2tr_and_v_hash_lock_pk_script_path_psbt(
        [35u8; 32],
        &key_sks,
        TapscriptHashKind::Sha256,
        &dig,
        DualTimeoutLock::Older(3),
    );
    psbt.unsigned_tx.input[0].sequence = Sequence::from_height(3);
    let secp = Secp256k1::new();
    let wrong_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[36u8; 32]).expect("wsk"));
    let (wrong_internal, wrong_parity) = wrong_kp.x_only_public_key();
    let bad_cb = bitcoin::taproot::ControlBlock {
        leaf_version: LeafVersion::TapScript,
        output_key_parity: wrong_parity,
        internal_key: wrong_internal,
        merkle_branch: Default::default(),
    };
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    psbt.inputs[0]
        .tap_scripts
        .insert(bad_cb, (leaf, LeafVersion::TapScript));
    psbt.inputs[0].tap_script_sigs.insert(
        (keys[0], leaf_hash),
        sample_tap_key_sig(key_sks[0], [37u8; 32]),
    );
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(dig), pre.to_vec());

    let err = finalize_psbt(&mut psbt).unwrap_err();
    let msg = err.to_string().to_ascii_lowercase();
    assert!(
        msg.contains("control block")
            || msg.contains("verify")
            || msg.contains("tamper")
            || msg.contains("commit"),
        "{err}"
    );
    assert!(psbt.inputs[0].final_script_witness.is_none());
}

/// Hash+lock+pk templates reject reverse multi-hash, reverse combined, single hash+pk, siblings.
#[test]
fn bare_tapscript_and_v_hash_lock_pk_templates_reject_siblings() {
    use bitcoin::secp256k1::{Keypair, SecretKey};

    let secp = Secp256k1::new();
    let kp_a = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[38u8; 32]).expect("a"));
    let kp_b = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[39u8; 32]).expect("b"));
    let (pk_a, _) = kp_a.x_only_public_key();
    let (pk_b, _) = kp_b.x_only_public_key();
    let digest = [0xbeu8; 32];

    // Reverse multi-hash and_v(v:hash, and_v(v:pk…)) — no middle lock.
    let rev_multi = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&digest)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .into_script();
    assert!(bare_tapscript_and_v_hash_multi_pk_template(&rev_multi).is_some());
    assert!(bare_tapscript_and_v_hash_lock_pk_template(&rev_multi).is_none());

    // Single and_v(v:hash, pk) — no lock.
    let hash_pk = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&digest)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .into_script();
    assert!(bare_tapscript_and_v_hash_pk_template(&hash_pk).is_some());
    assert!(bare_tapscript_and_v_hash_lock_pk_template(&hash_pk).is_none());

    // Reverse combined and_v(v:hash, and_v(v:pk…, older)) — keys then bare CSV.
    let rev_comb = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&digest)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_int(8)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .into_script();
    assert!(bare_tapscript_and_v_hash_pk_lock_template(&rev_comb).is_some());
    assert!(bare_tapscript_and_v_hash_lock_pk_template(&rev_comb).is_none());

    // Pk+lock+hash and_v(v:pk…, and_v(v:older, hash)).
    let pk_lock_hash = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_int(8)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .push_opcode(bitcoin::opcodes::all::OP_VERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&digest)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    assert!(bare_tapscript_and_v_pk_lock_hash_template(&pk_lock_hash).is_some());
    assert!(bare_tapscript_and_v_hash_lock_pk_template(&pk_lock_hash).is_none());

    // Lock-first combined and_v(v:older, and_v(v:pk…, hash)).
    let lock_first = bitcoin::script::Builder::new()
        .push_int(8)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .push_opcode(bitcoin::opcodes::all::OP_VERIFY)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&digest)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    assert!(bare_tapscript_and_v_lock_pk_hash_template(&lock_first).is_some());
    assert!(bare_tapscript_and_v_hash_lock_pk_template(&lock_first).is_none());

    // Lock+hash+pk sibling and_v(v:older, and_v(v:hash, pk)).
    let lock_hash_pk = bitcoin::script::Builder::new()
        .push_int(8)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .push_opcode(bitcoin::opcodes::all::OP_VERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&digest)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .into_script();
    assert!(bare_tapscript_and_v_lock_hash_pk_template(&lock_hash_pk).is_some());
    assert!(bare_tapscript_and_v_hash_lock_pk_template(&lock_hash_pk).is_none());

    // Classic HTLC or_i — dual-path OR, not AND.
    let classic = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_IF)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&digest)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .push_opcode(bitcoin::opcodes::all::OP_ELSE)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_int(7)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .into_script();
    assert!(bare_tapscript_or_i_hash_and_v_pk_older_template(&classic).is_some());
    assert!(bare_tapscript_and_v_hash_lock_pk_template(&classic).is_none());

    // Positive sample matches only hash+lock+pk combined.
    let good = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&digest)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_int(8)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .push_opcode(bitcoin::opcodes::all::OP_VERIFY)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .into_script();
    let parts = bare_tapscript_and_v_hash_lock_pk_template(&good).expect("good");
    assert_eq!(parts.0, vec![pk_a]);
    assert_eq!(parts.1, TapscriptHashKind::Sha256);
    assert_eq!(parts.2, digest);
    assert_eq!(parts.3, DualTimeoutLock::Older(8));
    assert!(bare_tapscript_and_v_hash_pk_lock_template(&good).is_none());
    assert!(bare_tapscript_and_v_pk_hash_lock_template(&good).is_none());
    assert!(bare_tapscript_and_v_lock_pk_hash_template(&good).is_none());
    assert!(bare_tapscript_and_v_pk_lock_hash_template(&good).is_none());
    assert!(bare_tapscript_and_v_lock_hash_pk_template(&good).is_none());
    assert!(bare_tapscript_and_v_hash_pk_template(&good).is_none());
    assert!(bare_tapscript_or_i_hash_and_v_pk_older_template(&good).is_none());

    // after variant.
    let good_after = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&digest)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_int(150)
        .push_opcode(bitcoin::opcodes::all::OP_CLTV)
        .push_opcode(bitcoin::opcodes::all::OP_VERIFY)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .into_script();
    let parts_a = bare_tapscript_and_v_hash_lock_pk_template(&good_after).expect("after");
    assert_eq!(parts_a.3, DualTimeoutLock::After(150));

    assert!(bare_tapscript_and_v_hash_lock_pk_template(&ScriptBuf::new()).is_none());
}

// -------------------------------------------------------------------------
// Lock + middle hash + trailing pk: and_v(v:older|after, and_v(v:hash, pk…))
// -------------------------------------------------------------------------

/// Build lock+middle-hash+trailing-pk combined hash+timeout
/// `and_v(v:older|after, and_v(v:hash(H), pk…))` leaf.
fn p2tr_and_v_lock_hash_pk_script_path_psbt(
    internal_sk: [u8; 32],
    key_sks: &[[u8; 32]],
    kind: TapscriptHashKind,
    digest: &[u8],
    lock: DualTimeoutLock,
) -> (
    bitcoin::psbt::Psbt,
    ScriptBuf,
    bitcoin::taproot::ControlBlock,
    Vec<bitcoin::secp256k1::XOnlyPublicKey>,
) {
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TaprootBuilder};

    assert!(!key_sks.is_empty());
    assert_eq!(digest.len(), kind.expected_digest_len());

    let secp = Secp256k1::new();
    let internal_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&internal_sk).expect("isk"));
    let (internal_xonly, _) = internal_kp.x_only_public_key();

    let mut keys = Vec::with_capacity(key_sks.len());
    for sk_bytes in key_sks {
        let kp = Keypair::from_secret_key(&secp, &SecretKey::from_slice(sk_bytes).expect("sk"));
        let (xonly, _) = kp.x_only_public_key();
        keys.push(xonly);
    }

    let hash_op = match kind {
        TapscriptHashKind::Sha256 => bitcoin::opcodes::all::OP_SHA256,
        TapscriptHashKind::Hash256 => bitcoin::opcodes::all::OP_HASH256,
        TapscriptHashKind::Ripemd160 => bitcoin::opcodes::all::OP_RIPEMD160,
        TapscriptHashKind::Hash160 => bitcoin::opcodes::all::OP_HASH160,
    };
    let mut builder = match lock {
        DualTimeoutLock::Older(n) => bitcoin::script::Builder::new()
            .push_int(i64::from(n))
            .push_opcode(bitcoin::opcodes::all::OP_CSV)
            .push_opcode(bitcoin::opcodes::all::OP_VERIFY),
        DualTimeoutLock::After(n) => bitcoin::script::Builder::new()
            .push_int(i64::from(n))
            .push_opcode(bitcoin::opcodes::all::OP_CLTV)
            .push_opcode(bitcoin::opcodes::all::OP_VERIFY),
    };
    builder = builder
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(hash_op)
        .push_slice(<&bitcoin::script::PushBytes>::try_from(digest).expect("digest"))
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY);
    for (i, pk) in keys.iter().enumerate() {
        builder = builder.push_x_only_key(pk);
        if i + 1 < keys.len() {
            builder = builder.push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY);
        } else {
            builder = builder.push_opcode(bitcoin::opcodes::all::OP_CHECKSIG);
        }
    }
    let leaf = builder.into_script();
    let (p_keys, p_kind, p_dig, p_lock) =
        bare_tapscript_and_v_lock_hash_pk_template(&leaf).expect("test leaf is lock+hash+pk");
    assert_eq!(p_keys, keys);
    assert_eq!(p_kind, kind);
    assert_eq!(p_dig, digest);
    assert_eq!(p_lock, lock);
    assert!(bare_tapscript_and_v_older_multi_pk_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_after_multi_pk_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_lock_pk_hash_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_hash_lock_pk_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_pk_lock_hash_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_pk_hash_lock_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_hash_pk_lock_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_hash_pk_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_hash_multi_pk_template(&leaf).is_none());
    assert!(bare_tapscript_or_i_hash_and_v_pk_older_template(&leaf).is_none());

    let spend_info = TaprootBuilder::new()
        .add_leaf(0, leaf.clone())
        .expect("add leaf")
        .finalize(&secp, internal_xonly)
        .expect("finalize tree");
    let merkle = spend_info.merkle_root();
    let control_block = spend_info
        .control_block(&(leaf.clone(), LeafVersion::TapScript))
        .expect("control block for leaf");
    let (psbt, spk) = p2tr_psbt_with_internal(internal_xonly, merkle);
    assert_eq!(spk, ScriptBuf::new_p2tr_tweaked(spend_info.output_key()));
    (psbt, leaf, control_block, keys)
}

/// Lock+hash+pk combined older: sig + preimage + good nSequence → Complete.
#[test]
fn finalize_taproot_and_v_older_hash_pk_is_complete() {
    use bitcoin::hashes::{Hash, sha256};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let key_sks = [[40u8; 32]];
    let (pre, dig) = sample_sha256_preimage_and_digest(41);
    let (mut psbt, leaf, control_block, keys) = p2tr_and_v_lock_hash_pk_script_path_psbt(
        [42u8; 32],
        &key_sks,
        TapscriptHashKind::Sha256,
        &dig,
        DualTimeoutLock::Older(6),
    );
    psbt.unsigned_tx.input[0].sequence = Sequence::from_height(6);
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    let sig = sample_tap_key_sig(key_sks[0], [43u8; 32]);
    psbt.inputs[0].tap_scripts.insert(
        control_block.clone(),
        (leaf.clone(), LeafVersion::TapScript),
    );
    psbt.inputs[0]
        .tap_script_sigs
        .insert((keys[0], leaf_hash), sig);
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(dig), pre.to_vec());

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete() && fin.is_broadcast_ready(), "{fin:?}");
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("older+hash+pk final")
        .to_vec();
    // bottom→top: sig, preimage, leaf, control
    assert_eq!(items.len(), 4);
    assert_eq!(items[0], sig.to_vec());
    assert_eq!(items[1], pre.to_vec());
    assert_eq!(items[2], leaf.as_bytes());
    assert_eq!(items[3], control_block.serialize());
    assert!(extract_finalized_tx(psbt).is_ok());
}

