/// Lock+hash+pk combined + bad control block → hard error.
#[test]
fn finalize_taproot_and_v_lock_hash_pk_bad_control_is_hard_error() {
    use bitcoin::hashes::{Hash, sha256};
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let key_sks = [[73u8; 32]];
    let (pre, dig) = sample_sha256_preimage_and_digest(74);
    let (mut psbt, leaf, _good_cb, keys) = p2tr_and_v_lock_hash_pk_script_path_psbt(
        [75u8; 32],
        &key_sks,
        TapscriptHashKind::Sha256,
        &dig,
        DualTimeoutLock::Older(3),
    );
    psbt.unsigned_tx.input[0].sequence = Sequence::from_height(3);
    let secp = Secp256k1::new();
    let wrong_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[76u8; 32]).expect("wsk"));
    let (wrong_internal, wrong_parity) = wrong_kp.x_only_public_key();
    let bad_cb = bitcoin::taproot::ControlBlock {
        leaf_version: LeafVersion::TapScript,
        output_key_parity: wrong_parity,
        internal_key: wrong_internal,
        merkle_branch: Default::default(),
    };
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    psbt.inputs[0]
        .tap_scripts
        .insert(bad_cb, (leaf, LeafVersion::TapScript));
    psbt.inputs[0].tap_script_sigs.insert(
        (keys[0], leaf_hash),
        sample_tap_key_sig(key_sks[0], [77u8; 32]),
    );
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(dig), pre.to_vec());

    let err = finalize_psbt(&mut psbt).unwrap_err();
    let msg = err.to_string().to_ascii_lowercase();
    assert!(
        msg.contains("control block")
            || msg.contains("verify")
            || msg.contains("tamper")
            || msg.contains("commit"),
        "{err}"
    );
    assert!(psbt.inputs[0].final_script_witness.is_none());
}

/// Lock+hash+pk templates reject reverse multi older, lock-first combined, hash+lock+pk, siblings.
#[test]
fn bare_tapscript_and_v_lock_hash_pk_templates_reject_siblings() {
    use bitcoin::secp256k1::{Keypair, SecretKey};

    let secp = Secp256k1::new();
    let kp_a = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[78u8; 32]).expect("a"));
    let kp_b = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[79u8; 32]).expect("b"));
    let (pk_a, _) = kp_a.x_only_public_key();
    let (pk_b, _) = kp_b.x_only_public_key();
    let digest = [0xcfu8; 32];

    // Reverse multi older and_v(v:older, and_v(v:pk…)) — ends CHECKSIG, no hash.
    let rev_older = bitcoin::script::Builder::new()
        .push_int(8)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .push_opcode(bitcoin::opcodes::all::OP_VERIFY)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .into_script();
    assert!(bare_tapscript_and_v_older_multi_pk_template(&rev_older).is_some());
    assert!(bare_tapscript_and_v_lock_hash_pk_template(&rev_older).is_none());

    // Lock-first combined and_v(v:older, and_v(v:pk…, hash)) — keys then bare EQUAL.
    let lock_first = bitcoin::script::Builder::new()
        .push_int(8)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .push_opcode(bitcoin::opcodes::all::OP_VERIFY)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&digest)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    assert!(bare_tapscript_and_v_lock_pk_hash_template(&lock_first).is_some());
    assert!(bare_tapscript_and_v_lock_hash_pk_template(&lock_first).is_none());

    // Hash+lock+pk and_v(v:hash, and_v(v:older, pk)).
    let hash_lock_pk = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&digest)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_int(8)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .push_opcode(bitcoin::opcodes::all::OP_VERIFY)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .into_script();
    assert!(bare_tapscript_and_v_hash_lock_pk_template(&hash_lock_pk).is_some());
    assert!(bare_tapscript_and_v_lock_hash_pk_template(&hash_lock_pk).is_none());

    // Reverse multi-hash (no lock).
    let rev_hash = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&digest)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .into_script();
    assert!(bare_tapscript_and_v_hash_multi_pk_template(&rev_hash).is_some());
    assert!(bare_tapscript_and_v_lock_hash_pk_template(&rev_hash).is_none());

    // Pk-first combined and_v(v:pk…, and_v(v:hash, older)).
    let pk_first = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&digest)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_int(8)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .into_script();
    assert!(bare_tapscript_and_v_pk_hash_lock_template(&pk_first).is_some());
    assert!(bare_tapscript_and_v_lock_hash_pk_template(&pk_first).is_none());

    // Classic HTLC or_i.
    let classic = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_IF)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&digest)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .push_opcode(bitcoin::opcodes::all::OP_ELSE)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_int(7)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .into_script();
    assert!(bare_tapscript_or_i_hash_and_v_pk_older_template(&classic).is_some());
    assert!(bare_tapscript_and_v_lock_hash_pk_template(&classic).is_none());

    // Positive sample matches only lock+hash+pk combined.
    let good = bitcoin::script::Builder::new()
        .push_int(8)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .push_opcode(bitcoin::opcodes::all::OP_VERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&digest)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .into_script();
    let parts = bare_tapscript_and_v_lock_hash_pk_template(&good).expect("good");
    assert_eq!(parts.0, vec![pk_a]);
    assert_eq!(parts.1, TapscriptHashKind::Sha256);
    assert_eq!(parts.2, digest);
    assert_eq!(parts.3, DualTimeoutLock::Older(8));
    assert!(bare_tapscript_and_v_lock_pk_hash_template(&good).is_none());
    assert!(bare_tapscript_and_v_hash_lock_pk_template(&good).is_none());
    assert!(bare_tapscript_and_v_pk_lock_hash_template(&good).is_none());
    assert!(bare_tapscript_and_v_pk_hash_lock_template(&good).is_none());
    assert!(bare_tapscript_and_v_hash_pk_lock_template(&good).is_none());
    assert!(bare_tapscript_and_v_older_multi_pk_template(&good).is_none());
    assert!(bare_tapscript_or_i_hash_and_v_pk_older_template(&good).is_none());

    // after variant.
    let good_after = bitcoin::script::Builder::new()
        .push_int(150)
        .push_opcode(bitcoin::opcodes::all::OP_CLTV)
        .push_opcode(bitcoin::opcodes::all::OP_VERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&digest)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .into_script();
    let parts_a = bare_tapscript_and_v_lock_hash_pk_template(&good_after).expect("after");
    assert_eq!(parts_a.3, DualTimeoutLock::After(150));

    assert!(bare_tapscript_and_v_lock_hash_pk_template(&ScriptBuf::new()).is_none());
}

// -------------------------------------------------------------------------
// Dual-hash+timeout: and_v(v:pk…, and_v(v:hash(H1), and_v(v:hash(H2), older|after)))
// -------------------------------------------------------------------------

/// Build dual-hash+timeout
/// `and_v(v:pk…, and_v(v:hash(H1), and_v(v:hash(H2), older|after)))` leaf.
fn p2tr_and_v_pk_dual_hash_lock_script_path_psbt(
    internal_sk: [u8; 32],
    key_sks: &[[u8; 32]],
    kind1: TapscriptHashKind,
    digest1: &[u8],
    kind2: TapscriptHashKind,
    digest2: &[u8],
    lock: DualTimeoutLock,
) -> (
    bitcoin::psbt::Psbt,
    ScriptBuf,
    bitcoin::taproot::ControlBlock,
    Vec<bitcoin::secp256k1::XOnlyPublicKey>,
) {
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TaprootBuilder};

    assert!(!key_sks.is_empty());
    assert_eq!(digest1.len(), kind1.expected_digest_len());
    assert_eq!(digest2.len(), kind2.expected_digest_len());

    let secp = Secp256k1::new();
    let internal_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&internal_sk).expect("isk"));
    let (internal_xonly, _) = internal_kp.x_only_public_key();

    let mut keys = Vec::with_capacity(key_sks.len());
    for sk_bytes in key_sks {
        let kp = Keypair::from_secret_key(&secp, &SecretKey::from_slice(sk_bytes).expect("sk"));
        let (xonly, _) = kp.x_only_public_key();
        keys.push(xonly);
    }

    let hash_op = |kind: TapscriptHashKind| match kind {
        TapscriptHashKind::Sha256 => bitcoin::opcodes::all::OP_SHA256,
        TapscriptHashKind::Hash256 => bitcoin::opcodes::all::OP_HASH256,
        TapscriptHashKind::Ripemd160 => bitcoin::opcodes::all::OP_RIPEMD160,
        TapscriptHashKind::Hash160 => bitcoin::opcodes::all::OP_HASH160,
    };
    let mut builder = bitcoin::script::Builder::new();
    for pk in &keys {
        builder = builder
            .push_x_only_key(pk)
            .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY);
    }
    builder = builder
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(hash_op(kind1))
        .push_slice(<&bitcoin::script::PushBytes>::try_from(digest1).expect("digest1"))
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(hash_op(kind2))
        .push_slice(<&bitcoin::script::PushBytes>::try_from(digest2).expect("digest2"))
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY);
    builder = match lock {
        DualTimeoutLock::Older(n) => builder
            .push_int(i64::from(n))
            .push_opcode(bitcoin::opcodes::all::OP_CSV),
        DualTimeoutLock::After(n) => builder
            .push_int(i64::from(n))
            .push_opcode(bitcoin::opcodes::all::OP_CLTV),
    };
    let leaf = builder.into_script();
    let (p_keys, p_k1, p_d1, p_k2, p_d2, p_lock) =
        bare_tapscript_and_v_pk_dual_hash_lock_template(&leaf)
            .expect("test leaf is pk+dual-hash+lock");
    assert_eq!(p_keys, keys);
    assert_eq!(p_k1, kind1);
    assert_eq!(p_d1, digest1);
    assert_eq!(p_k2, kind2);
    assert_eq!(p_d2, digest2);
    assert_eq!(p_lock, lock);
    // Must not cross-match single-hash combined / multi-pk hash / dual-hash
    // AND without lock / dual-hash or_i / sandwich / HTLC / reverse forms.
    assert!(bare_tapscript_and_v_pk_hash_lock_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_pk_hash_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_multi_pk_hash_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_pk_dual_hash_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_hash_pk_lock_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_lock_pk_hash_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_pk_lock_hash_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_hash_lock_pk_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_lock_hash_pk_template(&leaf).is_none());
    assert!(bare_tapscript_or_i_hash_and_v_pk_hash_template(&leaf).is_none());
    assert!(bare_tapscript_or_i_hash_and_v_pk_older_template(&leaf).is_none());
    assert!(bare_tapscript_or_i_lock_and_v_pk_lock_template(&leaf).is_none());

    let spend_info = TaprootBuilder::new()
        .add_leaf(0, leaf.clone())
        .expect("add leaf")
        .finalize(&secp, internal_xonly)
        .expect("finalize tree");
    let merkle = spend_info.merkle_root();
    let control_block = spend_info
        .control_block(&(leaf.clone(), LeafVersion::TapScript))
        .expect("control block for leaf");
    let (psbt, spk) = p2tr_psbt_with_internal(internal_xonly, merkle);
    assert_eq!(spk, ScriptBuf::new_p2tr_tweaked(spend_info.output_key()));
    (psbt, leaf, control_block, keys)
}

/// Dual-hash+timeout older: both preimages + sig + good nSequence → Complete.
#[test]
fn finalize_taproot_and_v_pk_dual_hash_older_is_complete() {
    use bitcoin::hashes::{Hash, sha256};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let key_sks = [[140u8; 32]];
    let (pre1, dig1) = sample_sha256_preimage_and_digest(141);
    let (pre2, dig2) = sample_sha256_preimage_and_digest(142);
    let older_n = 6u32;
    let (mut psbt, leaf, control_block, keys) = p2tr_and_v_pk_dual_hash_lock_script_path_psbt(
        [143u8; 32],
        &key_sks,
        TapscriptHashKind::Sha256,
        &dig1,
        TapscriptHashKind::Sha256,
        &dig2,
        DualTimeoutLock::Older(older_n),
    );
    psbt.unsigned_tx.input[0].sequence = Sequence::from_height(6);
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    let sig = sample_tap_key_sig(key_sks[0], [144u8; 32]);
    psbt.inputs[0].tap_scripts.insert(
        control_block.clone(),
        (leaf.clone(), LeafVersion::TapScript),
    );
    psbt.inputs[0]
        .tap_script_sigs
        .insert((keys[0], leaf_hash), sig);
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(dig1), pre1.to_vec());
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(dig2), pre2.to_vec());

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete() && fin.is_broadcast_ready(), "{fin:?}");
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("pk+dual-hash+older final")
        .to_vec();
    // bottom→top: preimage2, preimage1, sig, leaf, control
    assert_eq!(items.len(), 5);
    assert_eq!(items[0], pre2.to_vec());
    assert_eq!(items[1], pre1.to_vec());
    assert_eq!(items[2], sig.to_vec());
    assert_eq!(items[3], leaf.as_bytes());
    assert_eq!(items[4], control_block.serialize());
    assert!(extract_finalized_tx(psbt).is_ok());
}

/// Dual-hash+timeout with 2 keys → Complete (reverse-key witness).
#[test]
fn finalize_taproot_and_v_pk_dual_hash_older_2key_is_complete() {
    use bitcoin::hashes::{Hash, sha256};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let key_sks = [[145u8; 32], [146u8; 32]];
    let (pre1, dig1) = sample_sha256_preimage_and_digest(147);
    let (pre2, dig2) = sample_sha256_preimage_and_digest(148);
    let (mut psbt, leaf, control_block, keys) = p2tr_and_v_pk_dual_hash_lock_script_path_psbt(
        [149u8; 32],
        &key_sks,
        TapscriptHashKind::Sha256,
        &dig1,
        TapscriptHashKind::Sha256,
        &dig2,
        DualTimeoutLock::Older(5),
    );
    psbt.unsigned_tx.input[0].sequence = Sequence::from_height(5);
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    let sig0 = sample_tap_key_sig(key_sks[0], [150u8; 32]);
    let sig1 = sample_tap_key_sig(key_sks[1], [151u8; 32]);
    psbt.inputs[0].tap_scripts.insert(
        control_block.clone(),
        (leaf.clone(), LeafVersion::TapScript),
    );
    psbt.inputs[0]
        .tap_script_sigs
        .insert((keys[0], leaf_hash), sig0);
    psbt.inputs[0]
        .tap_script_sigs
        .insert((keys[1], leaf_hash), sig1);
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(dig1), pre1.to_vec());
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(dig2), pre2.to_vec());

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete() && fin.is_broadcast_ready(), "{fin:?}");
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("2key dual-hash+older final")
        .to_vec();
    // bottom→top: preimage2, preimage1, sig1, sig0
    assert_eq!(items.len(), 6);
    assert_eq!(items[0], pre2.to_vec());
    assert_eq!(items[1], pre1.to_vec());
    assert_eq!(items[2], sig1.to_vec());
    assert_eq!(items[3], sig0.to_vec());
    assert!(extract_finalized_tx(psbt).is_ok());
}

/// Dual-hash+timeout after (CLTV) → Complete.
#[test]
fn finalize_taproot_and_v_pk_dual_hash_after_is_complete() {
    use bitcoin::hashes::{Hash, sha256};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let key_sks = [[152u8; 32]];
    let (pre1, dig1) = sample_sha256_preimage_and_digest(153);
    let (pre2, dig2) = sample_sha256_preimage_and_digest(154);
    let (mut psbt, leaf, control_block, keys) = p2tr_and_v_pk_dual_hash_lock_script_path_psbt(
        [155u8; 32],
        &key_sks,
        TapscriptHashKind::Sha256,
        &dig1,
        TapscriptHashKind::Sha256,
        &dig2,
        DualTimeoutLock::After(200),
    );
    psbt.unsigned_tx.lock_time = LockTime::from_height(200).expect("height");
    psbt.unsigned_tx.input[0].sequence = Sequence::from_consensus(0xFFFFFFFE);
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    let sig = sample_tap_key_sig(key_sks[0], [156u8; 32]);
    psbt.inputs[0].tap_scripts.insert(
        control_block.clone(),
        (leaf.clone(), LeafVersion::TapScript),
    );
    psbt.inputs[0]
        .tap_script_sigs
        .insert((keys[0], leaf_hash), sig);
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(dig1), pre1.to_vec());
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(dig2), pre2.to_vec());

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete() && fin.is_broadcast_ready(), "{fin:?}");
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("pk+dual-hash+after final")
        .to_vec();
    assert_eq!(items[0], pre2.to_vec());
    assert_eq!(items[1], pre1.to_vec());
    assert_eq!(items[2], sig.to_vec());
    assert!(extract_finalized_tx(psbt).is_ok());
}

/// Dual-hash+timeout missing H1 preimage → Partial.
#[test]
fn finalize_taproot_and_v_pk_dual_hash_lock_missing_preimage1_is_partial() {
    use bitcoin::hashes::{Hash, sha256};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let key_sks = [[157u8; 32]];
    let (_pre1, dig1) = sample_sha256_preimage_and_digest(158);
    let (pre2, dig2) = sample_sha256_preimage_and_digest(159);
    let (mut psbt, leaf, control_block, keys) = p2tr_and_v_pk_dual_hash_lock_script_path_psbt(
        [160u8; 32],
        &key_sks,
        TapscriptHashKind::Sha256,
        &dig1,
        TapscriptHashKind::Sha256,
        &dig2,
        DualTimeoutLock::Older(3),
    );
    psbt.unsigned_tx.input[0].sequence = Sequence::from_height(3);
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    psbt.inputs[0]
        .tap_scripts
        .insert(control_block, (leaf, LeafVersion::TapScript));
    psbt.inputs[0].tap_script_sigs.insert(
        (keys[0], leaf_hash),
        sample_tap_key_sig(key_sks[0], [161u8; 32]),
    );
    // Only H2 preimage present.
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(dig2), pre2.to_vec());

    let fin = finalize_psbt(&mut psbt).unwrap();
    match &fin {
        FinalizeOutcome::Partial { detail, .. } => {
            let d = detail.to_ascii_lowercase();
            assert!(
                d.contains("preimage") && (d.contains("h1") || d.contains("hash")),
                "{detail}"
            );
        }
        other => panic!("expected Partial, got {other:?}"),
    }
    assert!(psbt.inputs[0].final_script_witness.is_none());
}

