/// Dual-hash+timeout + bad control block → hard error.
#[test]
fn finalize_taproot_and_v_pk_dual_hash_lock_bad_control_is_hard_error() {
    use bitcoin::hashes::{Hash, sha256};
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let key_sks = [[181u8; 32]];
    let (pre1, dig1) = sample_sha256_preimage_and_digest(182);
    let (pre2, dig2) = sample_sha256_preimage_and_digest(183);
    let (mut psbt, leaf, _good_cb, keys) = p2tr_and_v_pk_dual_hash_lock_script_path_psbt(
        [184u8; 32],
        &key_sks,
        TapscriptHashKind::Sha256,
        &dig1,
        TapscriptHashKind::Sha256,
        &dig2,
        DualTimeoutLock::Older(3),
    );
    psbt.unsigned_tx.input[0].sequence = Sequence::from_height(3);
    let secp = Secp256k1::new();
    let wrong_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[185u8; 32]).expect("wsk"));
    let (wrong_internal, wrong_parity) = wrong_kp.x_only_public_key();
    let bad_cb = bitcoin::taproot::ControlBlock {
        leaf_version: LeafVersion::TapScript,
        output_key_parity: wrong_parity,
        internal_key: wrong_internal,
        merkle_branch: Default::default(),
    };
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    psbt.inputs[0]
        .tap_scripts
        .insert(bad_cb, (leaf, LeafVersion::TapScript));
    psbt.inputs[0].tap_script_sigs.insert(
        (keys[0], leaf_hash),
        sample_tap_key_sig(key_sks[0], [186u8; 32]),
    );
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(dig1), pre1.to_vec());
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(dig2), pre2.to_vec());

    let err = finalize_psbt(&mut psbt).unwrap_err();
    let msg = err.to_string().to_ascii_lowercase();
    assert!(
        msg.contains("control block")
            || msg.contains("verify")
            || msg.contains("tamper")
            || msg.contains("commit"),
        "{err}"
    );
    assert!(psbt.inputs[0].final_script_witness.is_none());
}

/// Dual-hash+timeout templates reject single-hash combined, dual-hash or_i, siblings.
#[test]
fn bare_tapscript_and_v_pk_dual_hash_lock_templates_reject_siblings() {
    use bitcoin::secp256k1::{Keypair, SecretKey};

    let secp = Secp256k1::new();
    let kp_a = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[187u8; 32]).expect("a"));
    let kp_b = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[188u8; 32]).expect("b"));
    let (pk_a, _) = kp_a.x_only_public_key();
    let (pk_b, _) = kp_b.x_only_public_key();
    let dig1 = [0xd1u8; 32];
    let dig2 = [0xd2u8; 32];

    // Single-hash combined and_v(v:pk…, and_v(v:hash, older)) — one hash only.
    let single = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&dig1)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_int(8)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .into_script();
    assert!(bare_tapscript_and_v_pk_hash_lock_template(&single).is_some());
    assert!(bare_tapscript_and_v_pk_dual_hash_lock_template(&single).is_none());

    // Multi-pk hash (one hash EQUAL, no lock).
    let multi_hash = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&dig1)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    assert!(bare_tapscript_and_v_multi_pk_hash_template(&multi_hash).is_some());
    assert!(bare_tapscript_and_v_pk_dual_hash_lock_template(&multi_hash).is_none());

    // Dual-hash AND without lock (two hashes, bare EQUAL terminal).
    let dual_no_lock = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&dig1)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&dig2)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    assert!(bare_tapscript_and_v_pk_dual_hash_lock_template(&dual_no_lock).is_none());
    assert!(bare_tapscript_and_v_pk_hash_lock_template(&dual_no_lock).is_none());
    assert!(bare_tapscript_and_v_pk_dual_hash_template(&dual_no_lock).is_some());

    // Dual-hash or_i (OR dual-path).
    let dual_or = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_IF)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&dig1)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .push_opcode(bitcoin::opcodes::all::OP_ELSE)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&dig2)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .into_script();
    assert!(bare_tapscript_or_i_hash_and_v_pk_hash_template(&dual_or).is_some());
    assert!(bare_tapscript_and_v_pk_dual_hash_lock_template(&dual_or).is_none());

    // Classic HTLC or_i.
    let classic = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_IF)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&dig1)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .push_opcode(bitcoin::opcodes::all::OP_ELSE)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_int(7)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .push_opcode(bitcoin::opcodes::all::OP_ENDIF)
        .into_script();
    assert!(bare_tapscript_or_i_hash_and_v_pk_older_template(&classic).is_some());
    assert!(bare_tapscript_and_v_pk_dual_hash_lock_template(&classic).is_none());

    // Sandwich hash middle.
    let sandwich = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&dig1)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .into_script();
    assert!(bare_tapscript_and_v_multi_pk_hash_multi_pk_template(&sandwich).is_some());
    assert!(bare_tapscript_and_v_pk_dual_hash_lock_template(&sandwich).is_none());

    // Positive sample matches only dual-hash+timeout.
    let good = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&dig1)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&dig2)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_int(8)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .into_script();
    let parts = bare_tapscript_and_v_pk_dual_hash_lock_template(&good).expect("good");
    assert_eq!(parts.0, vec![pk_a]);
    assert_eq!(parts.1, TapscriptHashKind::Sha256);
    assert_eq!(parts.2, dig1);
    assert_eq!(parts.3, TapscriptHashKind::Sha256);
    assert_eq!(parts.4, dig2);
    assert_eq!(parts.5, DualTimeoutLock::Older(8));
    assert!(bare_tapscript_and_v_pk_hash_lock_template(&good).is_none());
    assert!(bare_tapscript_and_v_multi_pk_hash_template(&good).is_none());
    assert!(bare_tapscript_and_v_pk_dual_hash_template(&good).is_none());
    assert!(bare_tapscript_and_v_dual_hash_pk_lock_template(&good).is_none());
    assert!(bare_tapscript_or_i_hash_and_v_pk_hash_template(&good).is_none());
    assert!(bare_tapscript_or_i_hash_and_v_pk_older_template(&good).is_none());

    // Hash-first dual-hash+timeout (hashes before keys) — not pk-first.
    let hash_first_lock = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&dig1)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&dig2)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_int(8)
        .push_opcode(bitcoin::opcodes::all::OP_CSV)
        .into_script();
    assert!(bare_tapscript_and_v_dual_hash_pk_lock_template(&hash_first_lock).is_some());
    assert!(bare_tapscript_and_v_pk_dual_hash_lock_template(&hash_first_lock).is_none());

    // after variant.
    let good_after = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&dig1)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(&dig2)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_int(150)
        .push_opcode(bitcoin::opcodes::all::OP_CLTV)
        .into_script();
    let parts_a = bare_tapscript_and_v_pk_dual_hash_lock_template(&good_after).expect("after");
    assert_eq!(parts_a.5, DualTimeoutLock::After(150));

    assert!(bare_tapscript_and_v_pk_dual_hash_lock_template(&ScriptBuf::new()).is_none());
}

// -------------------------------------------------------------------------
// Hash-first dual-hash+timeout:
// and_v(v:hash(H1), and_v(v:hash(H2), and_v(v:pk…, older|after)))
// -------------------------------------------------------------------------

/// Build hash-first dual-hash+timeout
/// `and_v(v:hash(H1), and_v(v:hash(H2), and_v(v:pk…, older|after)))` leaf.
fn p2tr_and_v_dual_hash_pk_lock_script_path_psbt(
    internal_sk: [u8; 32],
    key_sks: &[[u8; 32]],
    kind1: TapscriptHashKind,
    digest1: &[u8],
    kind2: TapscriptHashKind,
    digest2: &[u8],
    lock: DualTimeoutLock,
) -> (
    bitcoin::psbt::Psbt,
    ScriptBuf,
    bitcoin::taproot::ControlBlock,
    Vec<bitcoin::secp256k1::XOnlyPublicKey>,
) {
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TaprootBuilder};

    assert!(!key_sks.is_empty());
    assert_eq!(digest1.len(), kind1.expected_digest_len());
    assert_eq!(digest2.len(), kind2.expected_digest_len());

    let secp = Secp256k1::new();
    let internal_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&internal_sk).expect("isk"));
    let (internal_xonly, _) = internal_kp.x_only_public_key();

    let mut keys = Vec::with_capacity(key_sks.len());
    for sk_bytes in key_sks {
        let kp = Keypair::from_secret_key(&secp, &SecretKey::from_slice(sk_bytes).expect("sk"));
        let (xonly, _) = kp.x_only_public_key();
        keys.push(xonly);
    }

    let hash_op = |kind: TapscriptHashKind| match kind {
        TapscriptHashKind::Sha256 => bitcoin::opcodes::all::OP_SHA256,
        TapscriptHashKind::Hash256 => bitcoin::opcodes::all::OP_HASH256,
        TapscriptHashKind::Ripemd160 => bitcoin::opcodes::all::OP_RIPEMD160,
        TapscriptHashKind::Hash160 => bitcoin::opcodes::all::OP_HASH160,
    };
    let mut builder = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(hash_op(kind1))
        .push_slice(<&bitcoin::script::PushBytes>::try_from(digest1).expect("digest1"))
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(hash_op(kind2))
        .push_slice(<&bitcoin::script::PushBytes>::try_from(digest2).expect("digest2"))
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY);
    for pk in &keys {
        builder = builder
            .push_x_only_key(pk)
            .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY);
    }
    builder = match lock {
        DualTimeoutLock::Older(n) => builder
            .push_int(i64::from(n))
            .push_opcode(bitcoin::opcodes::all::OP_CSV),
        DualTimeoutLock::After(n) => builder
            .push_int(i64::from(n))
            .push_opcode(bitcoin::opcodes::all::OP_CLTV),
    };
    let leaf = builder.into_script();
    let (p_keys, p_k1, p_d1, p_k2, p_d2, p_lock) =
        bare_tapscript_and_v_dual_hash_pk_lock_template(&leaf)
            .expect("test leaf is hash-first dual-hash+timeout");
    assert_eq!(p_keys, keys);
    assert_eq!(p_k1, kind1);
    assert_eq!(p_d1, digest1);
    assert_eq!(p_k2, kind2);
    assert_eq!(p_d2, digest2);
    assert_eq!(p_lock, lock);
    // Must not cross-match pk-first dual-hash+timeout / hash-first dual-hash
    // AND / reverse combined / dual-hash AND / sandwich dual-hash / HTLC.
    assert!(bare_tapscript_and_v_pk_dual_hash_lock_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_dual_hash_pk_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_pk_dual_hash_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_hash_pk_hash_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_hash_pk_lock_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_pk_hash_lock_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_hash_multi_pk_template(&leaf).is_none());
    assert!(bare_tapscript_or_i_hash_and_v_pk_hash_template(&leaf).is_none());
    assert!(bare_tapscript_or_i_hash_and_v_pk_older_template(&leaf).is_none());
    assert!(bare_tapscript_or_i_lock_and_v_pk_lock_template(&leaf).is_none());

    let spend_info = TaprootBuilder::new()
        .add_leaf(0, leaf.clone())
        .expect("add leaf")
        .finalize(&secp, internal_xonly)
        .expect("finalize tree");
    let merkle = spend_info.merkle_root();
    let control_block = spend_info
        .control_block(&(leaf.clone(), LeafVersion::TapScript))
        .expect("control block for leaf");
    let (psbt, spk) = p2tr_psbt_with_internal(internal_xonly, merkle);
    assert_eq!(spk, ScriptBuf::new_p2tr_tweaked(spend_info.output_key()));
    (psbt, leaf, control_block, keys)
}

/// Hash-first dual-hash+timeout older: both preimages + sig + good nSequence → Complete.
#[test]
fn finalize_taproot_and_v_dual_hash_pk_older_is_complete() {
    use bitcoin::hashes::{Hash, sha256};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let key_sks = [[190u8; 32]];
    let (pre1, dig1) = sample_sha256_preimage_and_digest(191);
    let (pre2, dig2) = sample_sha256_preimage_and_digest(192);
    let older_n = 6u32;
    let (mut psbt, leaf, control_block, keys) = p2tr_and_v_dual_hash_pk_lock_script_path_psbt(
        [193u8; 32],
        &key_sks,
        TapscriptHashKind::Sha256,
        &dig1,
        TapscriptHashKind::Sha256,
        &dig2,
        DualTimeoutLock::Older(older_n),
    );
    psbt.unsigned_tx.input[0].sequence = Sequence::from_height(6);
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    let sig = sample_tap_key_sig(key_sks[0], [194u8; 32]);
    psbt.inputs[0].tap_scripts.insert(
        control_block.clone(),
        (leaf.clone(), LeafVersion::TapScript),
    );
    psbt.inputs[0]
        .tap_script_sigs
        .insert((keys[0], leaf_hash), sig);
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(dig1), pre1.to_vec());
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(dig2), pre2.to_vec());

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete() && fin.is_broadcast_ready(), "{fin:?}");
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("hash-first dual-hash+older final")
        .to_vec();
    // bottom→top: sig, preimage2, preimage1, leaf, control
    assert_eq!(items.len(), 5);
    assert_eq!(items[0], sig.to_vec());
    assert_eq!(items[1], pre2.to_vec());
    assert_eq!(items[2], pre1.to_vec());
    assert_eq!(items[3], leaf.as_bytes());
    assert_eq!(items[4], control_block.serialize());
    assert!(extract_finalized_tx(psbt).is_ok());
}

