/// a:pk thresh leaf + bad control block → hard error (tamper).
#[test]
fn finalize_taproot_thresh_a_pk_bad_control_block_is_hard_error() {
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let sks = [[118u8; 32], [119u8; 32]];
    let (mut psbt, leaf, _good_cb, keys) = p2tr_thresh_a_pk_script_path_psbt([120u8; 32], &sks, 2);
    let secp = Secp256k1::new();
    let wrong_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[121u8; 32]).expect("wsk"));
    let (wrong_internal, wrong_parity) = wrong_kp.x_only_public_key();
    let bad_cb = bitcoin::taproot::ControlBlock {
        leaf_version: LeafVersion::TapScript,
        output_key_parity: wrong_parity,
        internal_key: wrong_internal,
        merkle_branch: Default::default(),
    };
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    psbt.inputs[0]
        .tap_scripts
        .insert(bad_cb, (leaf, LeafVersion::TapScript));
    psbt.inputs[0]
        .tap_script_sigs
        .insert((keys[0], leaf_hash), sample_tap_key_sig(sks[0], [37u8; 32]));
    psbt.inputs[0]
        .tap_script_sigs
        .insert((keys[1], leaf_hash), sample_tap_key_sig(sks[1], [38u8; 32]));

    let err = finalize_psbt(&mut psbt).unwrap_err();
    let msg = err.to_string().to_ascii_lowercase();
    assert!(
        msg.contains("control block")
            || msg.contains("verify")
            || msg.contains("tamper")
            || msg.contains("commit"),
        "{err}"
    );
    assert!(psbt.inputs[0].final_script_witness.is_none());
}

/// Multi-leaf: incomplete a:pk thresh skipped; later bare CHECKSIG wins.
#[test]
fn finalize_taproot_multi_leaf_incomplete_a_pk_thresh_then_bare_checksig() {
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TapLeafHash, TaprootBuilder};

    let secp = Secp256k1::new();
    let internal_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[122u8; 32]).expect("isk"));
    let (internal_xonly, _) = internal_kp.x_only_public_key();
    let sk_bare = [123u8; 32];
    let sk_t0 = [124u8; 32];
    let sk_t1 = [125u8; 32];
    let kp_bare = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&sk_bare).expect("skb"));
    let (pk_bare, _) = kp_bare.x_only_public_key();
    let kp_t0 = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&sk_t0).expect("sk0"));
    let (pk_t0, _) = kp_t0.x_only_public_key();
    let kp_t1 = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&sk_t1).expect("sk1"));
    let (pk_t1, _) = kp_t1.x_only_public_key();

    let thresh_leaf = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_t0)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_TOALTSTACK)
        .push_x_only_key(&pk_t1)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_FROMALTSTACK)
        .push_opcode(bitcoin::opcodes::all::OP_ADD)
        .push_int(2)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    assert!(bare_tapscript_thresh_a_pk_checksig_template(&thresh_leaf).is_some());
    assert!(bare_tapscript_thresh_checksig_template(&thresh_leaf).is_none());

    let bare_leaf = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_bare)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .into_script();

    let spend_info = TaprootBuilder::new()
        .add_leaf(1, thresh_leaf.clone())
        .expect("a:pk thresh leaf")
        .add_leaf(1, bare_leaf.clone())
        .expect("bare leaf")
        .finalize(&secp, internal_xonly)
        .expect("finalize tree");
    let merkle = spend_info.merkle_root();
    let cb_thresh = spend_info
        .control_block(&(thresh_leaf.clone(), LeafVersion::TapScript))
        .expect("cb thresh");
    let cb_bare = spend_info
        .control_block(&(bare_leaf.clone(), LeafVersion::TapScript))
        .expect("cb bare");
    let (mut psbt, _spk) = p2tr_psbt_with_internal(internal_xonly, merkle);

    psbt.inputs[0]
        .tap_scripts
        .insert(cb_thresh, (thresh_leaf, LeafVersion::TapScript));
    psbt.inputs[0]
        .tap_scripts
        .insert(cb_bare.clone(), (bare_leaf.clone(), LeafVersion::TapScript));
    let bare_hash = TapLeafHash::from_script(&bare_leaf, LeafVersion::TapScript);
    let sig_bare = sample_tap_key_sig(sk_bare, [39u8; 32]);
    psbt.inputs[0]
        .tap_script_sigs
        .insert((pk_bare, bare_hash), sig_bare);

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(
        fin.is_complete() && fin.is_broadcast_ready(),
        "must skip incomplete a:pk thresh and assemble bare CHECKSIG: {fin:?}"
    );
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("bare final")
        .to_vec();
    assert_eq!(items[0], sig_bare.to_vec());
    assert_eq!(items[1], bare_leaf.as_bytes());
    assert_eq!(items[2], cb_bare.serialize());
}

/// Template parser rejects s:pk / multi_a / mixed / no-altstack siblings.
#[test]
fn bare_tapscript_thresh_a_pk_template_rejects_non_a_pk() {
    use bitcoin::secp256k1::{Keypair, SecretKey};

    let secp = Secp256k1::new();
    let kp = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[126u8; 32]).expect("sk"));
    let (xonly, _) = kp.x_only_public_key();
    let kp2 = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[127u8; 32]).expect("sk2"));
    let (xonly2, _) = kp2.x_only_public_key();

    // s:pk thresh (SWAP) must not parse as a:pk.
    let s_pk = bitcoin::script::Builder::new()
        .push_x_only_key(&xonly)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_SWAP)
        .push_x_only_key(&xonly2)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_ADD)
        .push_int(2)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    assert!(bare_tapscript_thresh_checksig_template(&s_pk).is_some());
    assert!(bare_tapscript_thresh_a_pk_checksig_template(&s_pk).is_none());

    // multi_a
    let multi_a = bitcoin::script::Builder::new()
        .push_x_only_key(&xonly)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_x_only_key(&xonly2)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGADD)
        .push_int(2)
        .push_opcode(bitcoin::opcodes::all::OP_NUMEQUAL)
        .into_script();
    assert!(bare_tapscript_thresh_a_pk_checksig_template(&multi_a).is_none());

    // TOALTSTACK without FROMALTSTACK
    let no_from = bitcoin::script::Builder::new()
        .push_x_only_key(&xonly)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_TOALTSTACK)
        .push_x_only_key(&xonly2)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_ADD)
        .push_int(2)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    assert!(bare_tapscript_thresh_a_pk_checksig_template(&no_from).is_none());

    // Mixed s:/a: arms: not pure a:pk / s:pk; mixed sibling accepts.
    let mixed = bitcoin::script::Builder::new()
        .push_x_only_key(&xonly)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_SWAP)
        .push_x_only_key(&xonly2)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_ADD)
        .push_opcode(bitcoin::opcodes::all::OP_TOALTSTACK)
        .push_x_only_key(&xonly)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_FROMALTSTACK)
        .push_opcode(bitcoin::opcodes::all::OP_ADD)
        .push_int(2)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    assert!(bare_tapscript_thresh_a_pk_checksig_template(&mixed).is_none());
    assert!(bare_tapscript_thresh_checksig_template(&mixed).is_none());
    assert!(bare_tapscript_thresh_mixed_sa_checksig_template(&mixed).is_some());

    // k > n
    let k_gt_n = bitcoin::script::Builder::new()
        .push_x_only_key(&xonly)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_TOALTSTACK)
        .push_x_only_key(&xonly2)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_FROMALTSTACK)
        .push_opcode(bitcoin::opcodes::all::OP_ADD)
        .push_int(3)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    assert!(bare_tapscript_thresh_a_pk_checksig_template(&k_gt_n).is_none());

    assert!(bare_tapscript_thresh_a_pk_checksig_template(&ScriptBuf::new()).is_none());
}

// --- Taproot mixed s:/a: thresh (SWAP + TOALTSTACK arms + k EQUAL) ---

/// Build bare mixed s:/a: thresh leaf.
///
/// Arms after the type-B first key alternate starting with SWAP then
/// TOALTSTACK (…s: a: s: a:…) so both wrappers appear when `n ≥ 3`.
fn p2tr_thresh_mixed_sa_script_path_psbt(
    internal_sk: [u8; 32],
    spend_sks: &[[u8; 32]],
    threshold: u8,
) -> (
    bitcoin::psbt::Psbt,
    ScriptBuf,
    bitcoin::taproot::ControlBlock,
    Vec<bitcoin::secp256k1::XOnlyPublicKey>,
) {
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TaprootBuilder};

    assert!(spend_sks.len() >= 3, "mixed s:/a: thresh needs n ≥ 3");
    assert!(
        threshold >= 1 && (threshold as usize) <= spend_sks.len(),
        "k must be in 1..=n"
    );

    let secp = Secp256k1::new();
    let internal_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&internal_sk).expect("isk"));
    let (internal_xonly, _) = internal_kp.x_only_public_key();

    let mut keys = Vec::with_capacity(spend_sks.len());
    for sk in spend_sks {
        let kp = Keypair::from_secret_key(&secp, &SecretKey::from_slice(sk).expect("sk"));
        let (xonly, _) = kp.x_only_public_key();
        keys.push(xonly);
    }

    // type B first, then alternate s: (SWAP) / a: (TOALTSTACK) W arms.
    let mut b = bitcoin::script::Builder::new()
        .push_x_only_key(&keys[0])
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG);
    for (i, pk) in keys[1..].iter().enumerate() {
        if i % 2 == 0 {
            b = b
                .push_opcode(bitcoin::opcodes::all::OP_SWAP)
                .push_x_only_key(pk)
                .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
                .push_opcode(bitcoin::opcodes::all::OP_ADD);
        } else {
            b = b
                .push_opcode(bitcoin::opcodes::all::OP_TOALTSTACK)
                .push_x_only_key(pk)
                .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
                .push_opcode(bitcoin::opcodes::all::OP_FROMALTSTACK)
                .push_opcode(bitcoin::opcodes::all::OP_ADD);
        }
    }
    let leaf = b
        .push_int(i64::from(threshold))
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();

    let (parsed_k, parsed_pks) = bare_tapscript_thresh_mixed_sa_checksig_template(&leaf)
        .expect("test leaf must parse as mixed s:/a: thresh");
    assert_eq!(parsed_k, threshold as usize);
    assert_eq!(parsed_pks, keys);
    // Must not be mis-parsed as pure s:pk, pure a:pk, or multi_a.
    assert!(bare_tapscript_thresh_checksig_template(&leaf).is_none());
    assert!(bare_tapscript_thresh_a_pk_checksig_template(&leaf).is_none());
    assert!(bare_tapscript_checksigadd_multi_template(&leaf).is_none());

    let spend_info = TaprootBuilder::new()
        .add_leaf(0, leaf.clone())
        .expect("add leaf")
        .finalize(&secp, internal_xonly)
        .expect("finalize tree");
    let merkle = spend_info.merkle_root();
    let control_block = spend_info
        .control_block(&(leaf.clone(), LeafVersion::TapScript))
        .expect("control block for leaf");
    let (psbt, spk) = p2tr_psbt_with_internal(internal_xonly, merkle);
    assert_eq!(spk, ScriptBuf::new_p2tr_tweaked(spend_info.output_key()));
    assert!(control_block.verify_taproot_commitment(
        &secp,
        p2tr_output_key(&spk).expect("output key"),
        &leaf
    ));
    (psbt, leaf, control_block, keys)
}

/// 2-of-3 mixed s:/a: with first two keys signed → Complete; reverse-key witness.
#[test]
fn finalize_taproot_thresh_mixed_sa_2of3_with_first_two_sigs_is_complete() {
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let sks = [[130u8; 32], [131u8; 32], [132u8; 32]];
    let (mut psbt, leaf, control_block, keys) =
        p2tr_thresh_mixed_sa_script_path_psbt([133u8; 32], &sks, 2);
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    let sig0 = sample_tap_key_sig(sks[0], [40u8; 32]);
    let sig1 = sample_tap_key_sig(sks[1], [41u8; 32]);
    psbt.inputs[0].tap_scripts.insert(
        control_block.clone(),
        (leaf.clone(), LeafVersion::TapScript),
    );
    psbt.inputs[0]
        .tap_script_sigs
        .insert((keys[0], leaf_hash), sig0);
    psbt.inputs[0]
        .tap_script_sigs
        .insert((keys[1], leaf_hash), sig1);
    assert!(psbt.inputs[0].tap_key_sig.is_none());

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete() && fin.is_broadcast_ready(), "{fin:?}");
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("mixed thresh final witness")
        .to_vec();
    // reverse: key2 empty, key1 sig, key0 sig, script, cb
    assert_eq!(items.len(), 5);
    assert!(
        items[0].is_empty(),
        "unused last key must be empty BIP-342 placeholder"
    );
    assert_eq!(items[1], sig1.to_vec());
    assert_eq!(items[2], sig0.to_vec());
    assert_eq!(items[3], leaf.as_bytes());
    assert_eq!(items[4], control_block.serialize());
    assert!(psbt_is_broadcast_ready(&psbt));
    let tx = extract_finalized_tx(psbt).unwrap();
    assert_eq!(tx.input[0].witness.len(), 5);
}

