/// Mixed s:/a: thresh leaf + bad control block → hard error (tamper).
#[test]
fn finalize_taproot_thresh_mixed_sa_bad_control_block_is_hard_error() {
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let sks = [[150u8; 32], [151u8; 32], [152u8; 32]];
    let (mut psbt, leaf, _good_cb, keys) =
        p2tr_thresh_mixed_sa_script_path_psbt([153u8; 32], &sks, 2);
    let secp = Secp256k1::new();
    let wrong_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[154u8; 32]).expect("wsk"));
    let (wrong_internal, wrong_parity) = wrong_kp.x_only_public_key();
    let bad_cb = bitcoin::taproot::ControlBlock {
        leaf_version: LeafVersion::TapScript,
        output_key_parity: wrong_parity,
        internal_key: wrong_internal,
        merkle_branch: Default::default(),
    };
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    psbt.inputs[0]
        .tap_scripts
        .insert(bad_cb, (leaf, LeafVersion::TapScript));
    psbt.inputs[0]
        .tap_script_sigs
        .insert((keys[0], leaf_hash), sample_tap_key_sig(sks[0], [48u8; 32]));
    psbt.inputs[0]
        .tap_script_sigs
        .insert((keys[1], leaf_hash), sample_tap_key_sig(sks[1], [49u8; 32]));

    let err = finalize_psbt(&mut psbt).unwrap_err();
    let msg = err.to_string().to_ascii_lowercase();
    assert!(
        msg.contains("control block")
            || msg.contains("verify")
            || msg.contains("tamper")
            || msg.contains("commit"),
        "{err}"
    );
    assert!(psbt.inputs[0].final_script_witness.is_none());
}

/// Multi-leaf: incomplete mixed s:/a: thresh skipped; later bare CHECKSIG wins.
#[test]
fn finalize_taproot_multi_leaf_incomplete_mixed_sa_thresh_then_bare_checksig() {
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TapLeafHash, TaprootBuilder};

    let secp = Secp256k1::new();
    let internal_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[155u8; 32]).expect("isk"));
    let (internal_xonly, _) = internal_kp.x_only_public_key();
    let sk_bare = [156u8; 32];
    let sk_t0 = [157u8; 32];
    let sk_t1 = [158u8; 32];
    let sk_t2 = [159u8; 32];
    let kp_bare = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&sk_bare).expect("skb"));
    let (pk_bare, _) = kp_bare.x_only_public_key();
    let kp_t0 = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&sk_t0).expect("sk0"));
    let (pk_t0, _) = kp_t0.x_only_public_key();
    let kp_t1 = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&sk_t1).expect("sk1"));
    let (pk_t1, _) = kp_t1.x_only_public_key();
    let kp_t2 = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&sk_t2).expect("sk2"));
    let (pk_t2, _) = kp_t2.x_only_public_key();

    let thresh_leaf = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_t0)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_SWAP)
        .push_x_only_key(&pk_t1)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_ADD)
        .push_opcode(bitcoin::opcodes::all::OP_TOALTSTACK)
        .push_x_only_key(&pk_t2)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_FROMALTSTACK)
        .push_opcode(bitcoin::opcodes::all::OP_ADD)
        .push_int(2)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    assert!(bare_tapscript_thresh_mixed_sa_checksig_template(&thresh_leaf).is_some());
    assert!(bare_tapscript_thresh_checksig_template(&thresh_leaf).is_none());
    assert!(bare_tapscript_thresh_a_pk_checksig_template(&thresh_leaf).is_none());

    let bare_leaf = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_bare)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .into_script();

    let spend_info = TaprootBuilder::new()
        .add_leaf(1, thresh_leaf.clone())
        .expect("mixed thresh leaf")
        .add_leaf(1, bare_leaf.clone())
        .expect("bare leaf")
        .finalize(&secp, internal_xonly)
        .expect("finalize tree");
    let merkle = spend_info.merkle_root();
    let cb_thresh = spend_info
        .control_block(&(thresh_leaf.clone(), LeafVersion::TapScript))
        .expect("cb thresh");
    let cb_bare = spend_info
        .control_block(&(bare_leaf.clone(), LeafVersion::TapScript))
        .expect("cb bare");
    let (mut psbt, _spk) = p2tr_psbt_with_internal(internal_xonly, merkle);

    psbt.inputs[0]
        .tap_scripts
        .insert(cb_thresh, (thresh_leaf, LeafVersion::TapScript));
    psbt.inputs[0]
        .tap_scripts
        .insert(cb_bare.clone(), (bare_leaf.clone(), LeafVersion::TapScript));
    let bare_hash = TapLeafHash::from_script(&bare_leaf, LeafVersion::TapScript);
    let sig_bare = sample_tap_key_sig(sk_bare, [50u8; 32]);
    psbt.inputs[0]
        .tap_script_sigs
        .insert((pk_bare, bare_hash), sig_bare);

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(
        fin.is_complete() && fin.is_broadcast_ready(),
        "must skip incomplete mixed thresh and assemble bare CHECKSIG: {fin:?}"
    );
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("bare final")
        .to_vec();
    assert_eq!(items[0], sig_bare.to_vec());
    assert_eq!(items[1], bare_leaf.as_bytes());
    assert_eq!(items[2], cb_bare.serialize());
}

/// Template parser rejects pure s:/a: / multi_a / a-then-s-only-one-kind siblings.
#[test]
fn bare_tapscript_thresh_mixed_sa_template_rejects_non_mixed() {
    use bitcoin::secp256k1::{Keypair, SecretKey};

    let secp = Secp256k1::new();
    let kp = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[160u8; 32]).expect("sk"));
    let (xonly, _) = kp.x_only_public_key();
    let kp2 = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[161u8; 32]).expect("sk2"));
    let (xonly2, _) = kp2.x_only_public_key();
    let kp3 = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[162u8; 32]).expect("sk3"));
    let (xonly3, _) = kp3.x_only_public_key();

    // Pure s:pk must not parse as mixed.
    let s_pk = bitcoin::script::Builder::new()
        .push_x_only_key(&xonly)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_SWAP)
        .push_x_only_key(&xonly2)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_ADD)
        .push_int(2)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    assert!(bare_tapscript_thresh_checksig_template(&s_pk).is_some());
    assert!(bare_tapscript_thresh_mixed_sa_checksig_template(&s_pk).is_none());

    // Pure a:pk must not parse as mixed.
    let a_pk = bitcoin::script::Builder::new()
        .push_x_only_key(&xonly)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_TOALTSTACK)
        .push_x_only_key(&xonly2)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_FROMALTSTACK)
        .push_opcode(bitcoin::opcodes::all::OP_ADD)
        .push_int(2)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    assert!(bare_tapscript_thresh_a_pk_checksig_template(&a_pk).is_some());
    assert!(bare_tapscript_thresh_mixed_sa_checksig_template(&a_pk).is_none());

    // multi_a
    let multi_a = bitcoin::script::Builder::new()
        .push_x_only_key(&xonly)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_x_only_key(&xonly2)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGADD)
        .push_int(2)
        .push_opcode(bitcoin::opcodes::all::OP_NUMEQUAL)
        .into_script();
    assert!(bare_tapscript_thresh_mixed_sa_checksig_template(&multi_a).is_none());

    // Pure s: with three keys still pure (no a: arm).
    let pure_s3 = bitcoin::script::Builder::new()
        .push_x_only_key(&xonly)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_SWAP)
        .push_x_only_key(&xonly2)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_ADD)
        .push_opcode(bitcoin::opcodes::all::OP_SWAP)
        .push_x_only_key(&xonly3)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_ADD)
        .push_int(2)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    assert!(bare_tapscript_thresh_checksig_template(&pure_s3).is_some());
    assert!(bare_tapscript_thresh_mixed_sa_checksig_template(&pure_s3).is_none());

    // a: then s: (alt first) is still mixed — accepted.
    let a_then_s = bitcoin::script::Builder::new()
        .push_x_only_key(&xonly)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_TOALTSTACK)
        .push_x_only_key(&xonly2)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_FROMALTSTACK)
        .push_opcode(bitcoin::opcodes::all::OP_ADD)
        .push_opcode(bitcoin::opcodes::all::OP_SWAP)
        .push_x_only_key(&xonly3)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_ADD)
        .push_int(2)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    assert!(bare_tapscript_thresh_mixed_sa_checksig_template(&a_then_s).is_some());
    assert!(bare_tapscript_thresh_checksig_template(&a_then_s).is_none());
    assert!(bare_tapscript_thresh_a_pk_checksig_template(&a_then_s).is_none());

    // k > n
    let k_gt_n = bitcoin::script::Builder::new()
        .push_x_only_key(&xonly)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_SWAP)
        .push_x_only_key(&xonly2)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_ADD)
        .push_opcode(bitcoin::opcodes::all::OP_TOALTSTACK)
        .push_x_only_key(&xonly3)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_FROMALTSTACK)
        .push_opcode(bitcoin::opcodes::all::OP_ADD)
        .push_int(4)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    assert!(bare_tapscript_thresh_mixed_sa_checksig_template(&k_gt_n).is_none());

    assert!(bare_tapscript_thresh_mixed_sa_checksig_template(&ScriptBuf::new()).is_none());
}

// --- Taproot thresh s:hash (trailing or middle non-pk arm) ---

/// Build bare `thresh(k, pk…, s:hash)` with hash at a type-W arm index.
///
/// `spend_sks` are the pk arms in script order (n_pk ≥ 1). `hash_arm_idx`
/// is the arm index among all n = n_pk + 1 arms (`1..n`; 0 is the type-B
/// first pk). Trailing = `hash_arm_idx == n_pk`; middle has pk arms after.
/// `threshold` is k for the full thresh including the hash arm.
fn p2tr_thresh_s_hash_script_path_psbt(
    internal_sk: [u8; 32],
    spend_sks: &[[u8; 32]],
    threshold: u8,
    digest: &[u8],
    kind: TapscriptHashKind,
    hash_arm_idx: usize,
) -> (
    bitcoin::psbt::Psbt,
    ScriptBuf,
    bitcoin::taproot::ControlBlock,
    Vec<bitcoin::secp256k1::XOnlyPublicKey>,
) {
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TaprootBuilder};

    assert!(!spend_sks.is_empty(), "thresh(s:hash) needs ≥ 1 pk arm");
    let n = spend_sks.len() + 1;
    assert!(
        threshold >= 1 && (threshold as usize) <= n,
        "k must be in 1..=n (n = n_pk + 1)"
    );
    assert!(
        hash_arm_idx >= 1 && hash_arm_idx < n,
        "hash_arm_idx must be in 1..n (type-W; first arm is type-B pk)"
    );

    let secp = Secp256k1::new();
    let internal_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&internal_sk).expect("isk"));
    let (internal_xonly, _) = internal_kp.x_only_public_key();

    let mut pubkeys = Vec::with_capacity(spend_sks.len());
    for sk in spend_sks {
        let kp = Keypair::from_secret_key(&secp, &SecretKey::from_slice(sk).expect("sk"));
        let (xonly, _) = kp.x_only_public_key();
        pubkeys.push(xonly);
    }

    let hash_op = match kind {
        TapscriptHashKind::Sha256 => bitcoin::opcodes::all::OP_SHA256,
        TapscriptHashKind::Hash256 => bitcoin::opcodes::all::OP_HASH256,
        TapscriptHashKind::Ripemd160 => bitcoin::opcodes::all::OP_RIPEMD160,
        TapscriptHashKind::Hash160 => bitcoin::opcodes::all::OP_HASH160,
    };

    // Emit arms in order: arm 0 = type-B first pk; remaining interleave
    // s:pk and exactly one s:hash at hash_arm_idx.
    let mut builder = bitcoin::script::Builder::new()
        .push_x_only_key(&pubkeys[0])
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG);
    let mut next_pk = 1usize;
    for arm_i in 1..n {
        builder = builder.push_opcode(bitcoin::opcodes::all::OP_SWAP);
        if arm_i == hash_arm_idx {
            builder = builder
                .push_opcode(bitcoin::opcodes::all::OP_SIZE)
                .push_int(32)
                .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
                .push_opcode(hash_op)
                .push_slice(
                    <&bitcoin::script::PushBytes>::try_from(digest).expect("digest pushable"),
                )
                .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
                .push_opcode(bitcoin::opcodes::all::OP_ADD);
        } else {
            let pk = &pubkeys[next_pk];
            next_pk += 1;
            builder = builder
                .push_x_only_key(pk)
                .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
                .push_opcode(bitcoin::opcodes::all::OP_ADD);
        }
    }
    assert_eq!(next_pk, pubkeys.len(), "all pk arms emitted");
    let leaf = builder
        .push_int(i64::from(threshold))
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();

    let parsed = bare_tapscript_thresh_s_hash_template(&leaf).expect("test leaf is thresh(s:hash)");
    assert_eq!(parsed.threshold, threshold as usize);
    assert_eq!(parsed.pubkeys, pubkeys);
    assert_eq!(parsed.n_hash(), 1);
    let single = parsed.single_hash().expect("single s:hash");
    assert_eq!(single.arm_idx, hash_arm_idx);
    assert_eq!(single.kind, kind);
    assert_eq!(single.digest, digest);
    // Must not cross-match pure pk thresh / a:hash / mixed+hash / bare hash / and_v hash.
    assert!(bare_tapscript_thresh_checksig_template(&leaf).is_none());
    assert!(bare_tapscript_thresh_a_pk_checksig_template(&leaf).is_none());
    assert!(bare_tapscript_thresh_mixed_sa_checksig_template(&leaf).is_none());
    assert!(bare_tapscript_thresh_a_hash_template(&leaf).is_none());
    assert!(bare_tapscript_thresh_mixed_sa_hash_template(&leaf).is_none());
    assert!(bare_tapscript_hash_preimage_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_pk_hash_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_hash_pk_template(&leaf).is_none());
    assert!(bare_tapscript_checksigadd_multi_template(&leaf).is_none());

    let spend_info = TaprootBuilder::new()
        .add_leaf(0, leaf.clone())
        .expect("add leaf")
        .finalize(&secp, internal_xonly)
        .expect("finalize tree");
    let merkle = spend_info.merkle_root();
    let control_block = spend_info
        .control_block(&(leaf.clone(), LeafVersion::TapScript))
        .expect("control block for leaf");
    let (psbt, spk) = p2tr_psbt_with_internal(internal_xonly, merkle);
    assert_eq!(spk, ScriptBuf::new_p2tr_tweaked(spend_info.output_key()));
    assert!(control_block.verify_taproot_commitment(
        &secp,
        p2tr_output_key(&spk).expect("output key"),
        &leaf
    ));
    (psbt, leaf, control_block, pubkeys)
}

/// Trailing helper: hash is the last arm (`hash_arm_idx = n_pk`).
fn p2tr_thresh_s_hash_trailing_script_path_psbt(
    internal_sk: [u8; 32],
    spend_sks: &[[u8; 32]],
    threshold: u8,
    digest: &[u8],
    kind: TapscriptHashKind,
) -> (
    bitcoin::psbt::Psbt,
    ScriptBuf,
    bitcoin::taproot::ControlBlock,
    Vec<bitcoin::secp256k1::XOnlyPublicKey>,
) {
    let hash_arm_idx = spend_sks.len(); // last of n = n_pk + 1 arms
    p2tr_thresh_s_hash_script_path_psbt(
        internal_sk,
        spend_sks,
        threshold,
        digest,
        kind,
        hash_arm_idx,
    )
}

/// 2-of-2 thresh(pk, s:sha256) with sig + preimage → Complete.
#[test]
fn finalize_taproot_thresh_s_hash_2of2_with_sig_and_preimage_is_complete() {
    use bitcoin::hashes::{Hash, sha256};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let (preimage, digest) = sample_sha256_preimage_and_digest(60);
    let sk_a = [61u8; 32];
    let (mut psbt, leaf, control_block, pks) = p2tr_thresh_s_hash_trailing_script_path_psbt(
        [62u8; 32],
        &[sk_a],
        2,
        &digest,
        TapscriptHashKind::Sha256,
    );
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    let sig_a = sample_tap_key_sig(sk_a, [63u8; 32]);
    psbt.inputs[0].tap_scripts.insert(
        control_block.clone(),
        (leaf.clone(), LeafVersion::TapScript),
    );
    psbt.inputs[0]
        .tap_script_sigs
        .insert((pks[0], leaf_hash), sig_a);
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(digest), preimage.to_vec());

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete() && fin.is_broadcast_ready(), "{fin:?}");
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("thresh(s:hash) final")
        .to_vec();
    // <preimage> <sigA> <script> <cb>
    assert_eq!(items.len(), 4);
    assert_eq!(items[0], preimage.to_vec());
    assert_eq!(items[1], sig_a.to_vec());
    assert_eq!(items[2], leaf.as_bytes());
    assert_eq!(items[3], control_block.serialize());
    let _tx = extract_finalized_tx(psbt).unwrap();
}

/// 1-of-2 thresh(pk, s:sha256): only preimage (empty pk) → Complete.
///
/// Hash contributes 1; k−1 = 0 pk sigs required. Present pk sig must still
/// be left empty so EQUAL sees sum exactly 1 (never invent / overfill).
#[test]
fn finalize_taproot_thresh_s_hash_1of2_preimage_only_empties_pk() {
    use bitcoin::hashes::{Hash, sha256};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let (preimage, digest) = sample_sha256_preimage_and_digest(64);
    let sk_a = [65u8; 32];
    let (mut psbt, leaf, control_block, pks) = p2tr_thresh_s_hash_trailing_script_path_psbt(
        [66u8; 32],
        &[sk_a],
        1,
        &digest,
        TapscriptHashKind::Sha256,
    );
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    // Sig present but must not be used for k=1 (would make sum 2).
    let sig_a = sample_tap_key_sig(sk_a, [67u8; 32]);
    psbt.inputs[0].tap_scripts.insert(
        control_block.clone(),
        (leaf.clone(), LeafVersion::TapScript),
    );
    psbt.inputs[0]
        .tap_script_sigs
        .insert((pks[0], leaf_hash), sig_a);
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(digest), preimage.to_vec());

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete() && fin.is_broadcast_ready(), "{fin:?}");
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("1-of-2 final")
        .to_vec();
    // <preimage> <empty> <script> <cb>
    assert_eq!(items.len(), 4);
    assert_eq!(items[0], preimage.to_vec());
    assert!(
        items[1].is_empty(),
        "k=1 must empty pk slot even when sig is present (exact EQUAL)"
    );
    assert_eq!(items[2], leaf.as_bytes());
    assert_eq!(items[3], control_block.serialize());
    let _tx = extract_finalized_tx(psbt).unwrap();
}

/// 2-of-3 thresh(pk, s:pk, s:sha256): first pk + preimage → Complete.
#[test]
fn finalize_taproot_thresh_s_hash_2of3_first_pk_and_preimage_is_complete() {
    use bitcoin::hashes::{Hash, sha256};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let (preimage, digest) = sample_sha256_preimage_and_digest(68);
    let sk_a = [69u8; 32];
    let sk_b = [70u8; 32];
    let (mut psbt, leaf, control_block, pks) = p2tr_thresh_s_hash_trailing_script_path_psbt(
        [71u8; 32],
        &[sk_a, sk_b],
        2,
        &digest,
        TapscriptHashKind::Sha256,
    );
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    let sig_a = sample_tap_key_sig(sk_a, [72u8; 32]);
    psbt.inputs[0].tap_scripts.insert(
        control_block.clone(),
        (leaf.clone(), LeafVersion::TapScript),
    );
    // Only first pk; second stays empty (k−1 = 1).
    psbt.inputs[0]
        .tap_script_sigs
        .insert((pks[0], leaf_hash), sig_a);
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(digest), preimage.to_vec());

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete() && fin.is_broadcast_ready(), "{fin:?}");
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("2-of-3 final")
        .to_vec();
    // <preimage> <empty_B> <sigA> <script> <cb>
    assert_eq!(items.len(), 5);
    assert_eq!(items[0], preimage.to_vec());
    assert!(items[1].is_empty(), "unused second pk is empty placeholder");
    assert_eq!(items[2], sig_a.to_vec());
    assert_eq!(items[3], leaf.as_bytes());
    assert_eq!(items[4], control_block.serialize());
    let _tx = extract_finalized_tx(psbt).unwrap();
}

