// --- Taproot thresh a:hash (TOALTSTACK dual of s:hash) ---

/// Build bare `thresh(k, pk…, a:hash)` with hash at a type-W arm index.
fn p2tr_thresh_a_hash_script_path_psbt(
    internal_sk: [u8; 32],
    spend_sks: &[[u8; 32]],
    threshold: u8,
    digest: &[u8],
    kind: TapscriptHashKind,
    hash_arm_idx: usize,
) -> (
    bitcoin::psbt::Psbt,
    ScriptBuf,
    bitcoin::taproot::ControlBlock,
    Vec<bitcoin::secp256k1::XOnlyPublicKey>,
) {
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TaprootBuilder};

    assert!(!spend_sks.is_empty(), "thresh(a:hash) needs ≥ 1 pk arm");
    let n = spend_sks.len() + 1;
    assert!(
        threshold >= 1 && (threshold as usize) <= n,
        "k must be in 1..=n (n = n_pk + 1)"
    );
    assert!(
        hash_arm_idx >= 1 && hash_arm_idx < n,
        "hash_arm_idx must be in 1..n"
    );

    let secp = Secp256k1::new();
    let internal_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&internal_sk).expect("isk"));
    let (internal_xonly, _) = internal_kp.x_only_public_key();

    let mut pubkeys = Vec::with_capacity(spend_sks.len());
    for sk in spend_sks {
        let kp = Keypair::from_secret_key(&secp, &SecretKey::from_slice(sk).expect("sk"));
        let (xonly, _) = kp.x_only_public_key();
        pubkeys.push(xonly);
    }

    let hash_op = match kind {
        TapscriptHashKind::Sha256 => bitcoin::opcodes::all::OP_SHA256,
        TapscriptHashKind::Hash256 => bitcoin::opcodes::all::OP_HASH256,
        TapscriptHashKind::Ripemd160 => bitcoin::opcodes::all::OP_RIPEMD160,
        TapscriptHashKind::Hash160 => bitcoin::opcodes::all::OP_HASH160,
    };

    let mut builder = bitcoin::script::Builder::new()
        .push_x_only_key(&pubkeys[0])
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG);
    let mut next_pk = 1usize;
    for arm_i in 1..n {
        builder = builder.push_opcode(bitcoin::opcodes::all::OP_TOALTSTACK);
        if arm_i == hash_arm_idx {
            builder = builder
                .push_opcode(bitcoin::opcodes::all::OP_SIZE)
                .push_int(32)
                .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
                .push_opcode(hash_op)
                .push_slice(
                    <&bitcoin::script::PushBytes>::try_from(digest).expect("digest pushable"),
                )
                .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
                .push_opcode(bitcoin::opcodes::all::OP_FROMALTSTACK)
                .push_opcode(bitcoin::opcodes::all::OP_ADD);
        } else {
            let pk = &pubkeys[next_pk];
            next_pk += 1;
            builder = builder
                .push_x_only_key(pk)
                .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
                .push_opcode(bitcoin::opcodes::all::OP_FROMALTSTACK)
                .push_opcode(bitcoin::opcodes::all::OP_ADD);
        }
    }
    assert_eq!(next_pk, pubkeys.len(), "all pk arms emitted");
    let leaf = builder
        .push_int(i64::from(threshold))
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();

    let parsed = bare_tapscript_thresh_a_hash_template(&leaf).expect("test leaf is thresh(a:hash)");
    assert_eq!(parsed.threshold, threshold as usize);
    assert_eq!(parsed.pubkeys, pubkeys);
    assert_eq!(parsed.n_hash(), 1);
    let single = parsed.single_hash().expect("single a:hash");
    assert_eq!(single.arm_idx, hash_arm_idx);
    assert_eq!(single.kind, kind);
    assert_eq!(single.digest, digest);
    assert!(bare_tapscript_thresh_s_hash_template(&leaf).is_none());
    assert!(bare_tapscript_thresh_checksig_template(&leaf).is_none());
    assert!(bare_tapscript_thresh_a_pk_checksig_template(&leaf).is_none());
    assert!(bare_tapscript_thresh_mixed_sa_checksig_template(&leaf).is_none());
    assert!(bare_tapscript_thresh_mixed_sa_hash_template(&leaf).is_none());
    assert!(bare_tapscript_hash_preimage_template(&leaf).is_none());
    assert!(bare_tapscript_and_v_pk_hash_template(&leaf).is_none());
    assert!(bare_tapscript_checksigadd_multi_template(&leaf).is_none());

    let spend_info = TaprootBuilder::new()
        .add_leaf(0, leaf.clone())
        .expect("add leaf")
        .finalize(&secp, internal_xonly)
        .expect("finalize tree");
    let merkle = spend_info.merkle_root();
    let control_block = spend_info
        .control_block(&(leaf.clone(), LeafVersion::TapScript))
        .expect("control block for leaf");
    let (psbt, spk) = p2tr_psbt_with_internal(internal_xonly, merkle);
    assert_eq!(spk, ScriptBuf::new_p2tr_tweaked(spend_info.output_key()));
    assert!(control_block.verify_taproot_commitment(
        &secp,
        p2tr_output_key(&spk).expect("output key"),
        &leaf
    ));
    (psbt, leaf, control_block, pubkeys)
}

/// 2-of-2 thresh(pk, a:sha256) with sig + preimage → Complete.
#[test]
fn finalize_taproot_thresh_a_hash_2of2_with_sig_and_preimage_is_complete() {
    use bitcoin::hashes::{Hash, sha256};
    use bitcoin::taproot::{LeafVersion, TapLeafHash};

    let (preimage, digest) = sample_sha256_preimage_and_digest(115);
    let sk_a = [116u8; 32];
    let (mut psbt, leaf, control_block, pks) = p2tr_thresh_a_hash_script_path_psbt(
        [117u8; 32],
        &[sk_a],
        2,
        &digest,
        TapscriptHashKind::Sha256,
        1,
    );
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    let sig_a = sample_tap_key_sig(sk_a, [118u8; 32]);
    psbt.inputs[0].tap_scripts.insert(
        control_block.clone(),
        (leaf.clone(), LeafVersion::TapScript),
    );
    psbt.inputs[0]
        .tap_script_sigs
        .insert((pks[0], leaf_hash), sig_a);
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(digest), preimage.to_vec());

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete() && fin.is_broadcast_ready(), "{fin:?}");
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("thresh(a:hash) final")
        .to_vec();
    // reverse [A, hash] → <preimage> <sigA> <script> <cb>
    assert_eq!(items.len(), 4);
    assert_eq!(items[0], preimage.to_vec());
    assert_eq!(items[1], sig_a.to_vec());
    assert_eq!(items[2], leaf.as_bytes());
    assert_eq!(items[3], control_block.serialize());
    let _tx = extract_finalized_tx(psbt).unwrap();
}

