/// Multi-hash with k > n_hash: `thresh(3, pkA, s:hash1, s:pkB, s:hash2)` —
/// both preimages + first pk sig → Complete (pk_needed = 1; unused pk empty).
#[test]
fn finalize_taproot_thresh_multi_s_hash_k_gt_n_hash_with_one_pk_sig_is_complete() {
    use bitcoin::hashes::{Hash, sha256};
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TapLeafHash, TaprootBuilder};

    let (preimage_a, digest_a) = sample_sha256_preimage_and_digest(180);
    let (preimage_b, digest_b) = sample_sha256_preimage_and_digest(181);
    let sk_a = [182u8; 32];
    let sk_b = [183u8; 32];
    let internal_sk = [184u8; 32];
    let secp = Secp256k1::new();
    let internal_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&internal_sk).expect("isk"));
    let (internal_xonly, _) = internal_kp.x_only_public_key();
    let kp_a = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&sk_a).expect("ska"));
    let (pk_a, _) = kp_a.x_only_public_key();
    let kp_b = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&sk_b).expect("skb"));
    let (pk_b, _) = kp_b.x_only_public_key();

    // arm0 pkA, arm1 s:hashA, arm2 s:pkB, arm3 s:hashB; k=3 → n_hash=2, pk_needed=1.
    let leaf = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_SWAP)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(<&bitcoin::script::PushBytes>::try_from(digest_a.as_slice()).unwrap())
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .push_opcode(bitcoin::opcodes::all::OP_ADD)
        .push_opcode(bitcoin::opcodes::all::OP_SWAP)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_ADD)
        .push_opcode(bitcoin::opcodes::all::OP_SWAP)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(<&bitcoin::script::PushBytes>::try_from(digest_b.as_slice()).unwrap())
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .push_opcode(bitcoin::opcodes::all::OP_ADD)
        .push_int(3)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    let tmpl = bare_tapscript_thresh_s_hash_template(&leaf).expect("multi s:hash k>n_hash");
    assert_eq!(tmpl.n_hash(), 2);
    assert_eq!(tmpl.threshold, 3);
    assert_eq!(tmpl.pubkeys.len(), 2);
    assert_eq!(tmpl.hash_arms[0].arm_idx, 1);
    assert_eq!(tmpl.hash_arms[1].arm_idx, 3);
    assert!(bare_tapscript_thresh_a_hash_template(&leaf).is_none());
    assert!(bare_tapscript_thresh_checksig_template(&leaf).is_none());

    let spend_info = TaprootBuilder::new()
        .add_leaf(0, leaf.clone())
        .expect("add leaf")
        .finalize(&secp, internal_xonly)
        .expect("finalize tree");
    let merkle = spend_info.merkle_root();
    let control_block = spend_info
        .control_block(&(leaf.clone(), LeafVersion::TapScript))
        .expect("control block");
    let (mut psbt, _spk) = p2tr_psbt_with_internal(internal_xonly, merkle);
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    let sig_a = sample_tap_key_sig(sk_a, [185u8; 32]);
    psbt.inputs[0]
        .tap_scripts
        .insert(control_block, (leaf, LeafVersion::TapScript));
    // First present pk in script order (pkA); pkB absent.
    psbt.inputs[0]
        .tap_script_sigs
        .insert((pk_a, leaf_hash), sig_a);
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(digest_a), preimage_a.to_vec());
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(digest_b), preimage_b.to_vec());

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete() && fin.is_broadcast_ready(), "{fin:?}");
    let items: Vec<Vec<u8>> = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("final witness")
        .to_vec();
    // reverse arms: hashB, empty-pkB, hashA, sigA, script, control
    assert_eq!(
        items.len(),
        6,
        "2 preimages + 2 pk slots + script + control"
    );
    assert_eq!(items[0], preimage_b.to_vec());
    assert!(items[1].is_empty(), "unused pkB empty BIP-342 placeholder");
    assert_eq!(items[2], preimage_a.to_vec());
    assert_eq!(items[3], sig_a.to_vec());
    assert!(extract_finalized_tx(psbt).is_ok());
}

