    let sig_a = sample_tap_key_sig(sk_a, [196u8; 32]);
    let sig_b = sample_tap_key_sig(sk_b, [197u8; 32]);
    psbt.inputs[0]
        .tap_scripts
        .insert(control_block, (leaf, LeafVersion::TapScript));
    // Both pk sigs present; only first (pkA) fills pk_needed=1; pkB emptied.
    psbt.inputs[0]
        .tap_script_sigs
