/// Mixed s:hash + a:hash (both hash, both wrappers) k=2 with both preimages → Complete.
#[test]
fn finalize_taproot_thresh_mixed_s_hash_a_hash_both_preimages_is_complete() {
    use bitcoin::hashes::{Hash, sha256};
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TaprootBuilder};

    let (preimage_s, digest_s) = sample_sha256_preimage_and_digest(214);
    let (preimage_a, digest_a) = sample_sha256_preimage_and_digest(215);
    let sk_a = [216u8; 32];
    let internal_sk = [217u8; 32];
    let secp = Secp256k1::new();
    let internal_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&internal_sk).expect("isk"));
    let (internal_xonly, _) = internal_kp.x_only_public_key();
    let kp_a = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&sk_a).expect("ska"));
    let (pk_a, _) = kp_a.x_only_public_key();

    // type-B pkA, s:hash, a:hash; k=2 → n_hash=2, pk_needed=0.
    let leaf = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_SWAP)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(<&bitcoin::script::PushBytes>::try_from(digest_s.as_slice()).unwrap())
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .push_opcode(bitcoin::opcodes::all::OP_ADD)
        .push_opcode(bitcoin::opcodes::all::OP_TOALTSTACK)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(<&bitcoin::script::PushBytes>::try_from(digest_a.as_slice()).unwrap())
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .push_opcode(bitcoin::opcodes::all::OP_FROMALTSTACK)
        .push_opcode(bitcoin::opcodes::all::OP_ADD)
        .push_int(2)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    let tmpl = bare_tapscript_thresh_mixed_sa_hash_template(&leaf).expect("mixed s:hash+a:hash");
    assert_eq!(tmpl.n_hash(), 2);
    assert_eq!(tmpl.threshold, 2);
    assert_eq!(tmpl.pubkeys.len(), 1);
    assert_eq!(tmpl.hash_arms[0].arm_idx, 1);
    assert_eq!(tmpl.hash_arms[1].arm_idx, 2);
    assert!(bare_tapscript_thresh_s_hash_template(&leaf).is_none());
    assert!(bare_tapscript_thresh_a_hash_template(&leaf).is_none());

    let spend_info = TaprootBuilder::new()
        .add_leaf(0, leaf.clone())
        .expect("add leaf")
        .finalize(&secp, internal_xonly)
        .expect("finalize tree");
    let merkle = spend_info.merkle_root();
    let control_block = spend_info
        .control_block(&(leaf.clone(), LeafVersion::TapScript))
        .expect("control block");
    let (mut psbt, _spk) = p2tr_psbt_with_internal(internal_xonly, merkle);
    psbt.inputs[0]
        .tap_scripts
        .insert(control_block, (leaf, LeafVersion::TapScript));
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(digest_s), preimage_s.to_vec());
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(digest_a), preimage_a.to_vec());

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete() && fin.is_broadcast_ready(), "{fin:?}");
    let items: Vec<Vec<u8>> = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("final witness")
        .to_vec();
    // reverse: a:hash preimage, s:hash preimage, empty pkA, script, control
    assert_eq!(items.len(), 5);
    assert_eq!(items[0], preimage_a.to_vec());
    assert_eq!(items[1], preimage_s.to_vec());
    assert!(items[2].is_empty(), "pk arm empty when pk_needed=0");
    assert!(extract_finalized_tx(psbt).is_ok());
}

/// Mixed s:/a:+hash template rejects pure s:hash, pure a:hash, mixed pk-only, empty.
#[test]
fn bare_tapscript_thresh_mixed_sa_hash_template_rejects_siblings() {
    use bitcoin::secp256k1::{Keypair, SecretKey};

    let secp = Secp256k1::new();
    let kp_a = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[220u8; 32]).unwrap());
    let (pk_a, _) = kp_a.x_only_public_key();
    let kp_b = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[221u8; 32]).unwrap());
    let (pk_b, _) = kp_b.x_only_public_key();
    let kp_c = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[222u8; 32]).unwrap());
    let (pk_c, _) = kp_c.x_only_public_key();
    let digest = [0xabu8; 32];

    // Pure s:hash — must not match mixed.
    let pure_s = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_SWAP)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(<&bitcoin::script::PushBytes>::try_from(digest.as_slice()).unwrap())
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .push_opcode(bitcoin::opcodes::all::OP_ADD)
        .push_int(1)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    assert!(bare_tapscript_thresh_s_hash_template(&pure_s).is_some());
    assert!(bare_tapscript_thresh_mixed_sa_hash_template(&pure_s).is_none());

    // Pure a:hash.
    let pure_a = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_TOALTSTACK)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(<&bitcoin::script::PushBytes>::try_from(digest.as_slice()).unwrap())
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .push_opcode(bitcoin::opcodes::all::OP_FROMALTSTACK)
        .push_opcode(bitcoin::opcodes::all::OP_ADD)
        .push_int(1)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    assert!(bare_tapscript_thresh_a_hash_template(&pure_a).is_some());
    assert!(bare_tapscript_thresh_mixed_sa_hash_template(&pure_a).is_none());

    // Mixed s:/a: pk-only (no hash).
    let mixed_pk = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_SWAP)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_ADD)
        .push_opcode(bitcoin::opcodes::all::OP_TOALTSTACK)
        .push_x_only_key(&pk_c)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_FROMALTSTACK)
        .push_opcode(bitcoin::opcodes::all::OP_ADD)
        .push_int(2)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    assert!(bare_tapscript_thresh_mixed_sa_checksig_template(&mixed_pk).is_some());
    assert!(bare_tapscript_thresh_mixed_sa_hash_template(&mixed_pk).is_none());

    assert!(bare_tapscript_thresh_mixed_sa_hash_template(&ScriptBuf::new()).is_none());
}

/// Mixed s:pk + a:hash bad control block → hard error (not silent Partial).
#[test]
fn finalize_taproot_thresh_mixed_s_pk_a_hash_bad_control_block_is_hard_error() {
    use bitcoin::hashes::{Hash, sha256};
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TapLeafHash, TaprootBuilder};

    let (preimage, digest) = sample_sha256_preimage_and_digest(218);
    let sk_a = [219u8; 32];
    let sk_b = [223u8; 32];
    let internal_sk = [224u8; 32];
    let secp = Secp256k1::new();
    let internal_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&internal_sk).expect("isk"));
    let (internal_xonly, _) = internal_kp.x_only_public_key();
    let kp_a = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&sk_a).expect("ska"));
    let (pk_a, _) = kp_a.x_only_public_key();
    let kp_b = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&sk_b).expect("skb"));
    let (pk_b, _) = kp_b.x_only_public_key();

    let leaf = bitcoin::script::Builder::new()
        .push_x_only_key(&pk_a)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_SWAP)
        .push_x_only_key(&pk_b)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .push_opcode(bitcoin::opcodes::all::OP_ADD)
        .push_opcode(bitcoin::opcodes::all::OP_TOALTSTACK)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SHA256)
        .push_slice(<&bitcoin::script::PushBytes>::try_from(digest.as_slice()).unwrap())
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .push_opcode(bitcoin::opcodes::all::OP_FROMALTSTACK)
        .push_opcode(bitcoin::opcodes::all::OP_ADD)
        .push_int(2)
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();

    let spend_info = TaprootBuilder::new()
        .add_leaf(0, leaf.clone())
        .expect("add leaf")
        .finalize(&secp, internal_xonly)
        .expect("finalize tree");
    let merkle = spend_info.merkle_root();
    // Control block from a different internal key — fails commitment verify.
    let wrong_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&[225u8; 32]).expect("wrong"));
    let (wrong_xonly, _) = wrong_kp.x_only_public_key();
    let wrong_info = TaprootBuilder::new()
        .add_leaf(0, leaf.clone())
        .expect("add")
        .finalize(&secp, wrong_xonly)
        .expect("finalize");
    let bad_cb = wrong_info
        .control_block(&(leaf.clone(), LeafVersion::TapScript))
        .expect("cb");
    let (mut psbt, _spk) = p2tr_psbt_with_internal(internal_xonly, merkle);
    let leaf_hash = TapLeafHash::from_script(&leaf, LeafVersion::TapScript);
    psbt.inputs[0]
        .tap_scripts
        .insert(bad_cb, (leaf, LeafVersion::TapScript));
    psbt.inputs[0]
        .tap_script_sigs
        .insert((pk_a, leaf_hash), sample_tap_key_sig(sk_a, [226u8; 32]));
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(digest), preimage.to_vec());

    let err = finalize_psbt(&mut psbt).expect_err("bad control block must hard-error");
    let msg = err.to_string().to_ascii_lowercase();
    assert!(
        msg.contains("control block") || msg.contains("taproot"),
        "expected control-block hard error, got: {err}"
    );
    assert!(psbt.inputs[0].final_script_witness.is_none());
}

// --- Taproot bare hash / and_v(v:pk, hash) script-path finalize ---

/// Build bare miniscript hash leaf under a single-leaf Taproot tree.
fn p2tr_hash_script_path_psbt(
    internal_sk: [u8; 32],
    kind: TapscriptHashKind,
    digest: &[u8],
) -> (
    bitcoin::psbt::Psbt,
    ScriptBuf,
    bitcoin::taproot::ControlBlock,
) {
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TaprootBuilder};

    let secp = Secp256k1::new();
    let internal_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&internal_sk).expect("isk"));
    let (internal_xonly, _) = internal_kp.x_only_public_key();

    let hash_op = match kind {
        TapscriptHashKind::Sha256 => bitcoin::opcodes::all::OP_SHA256,
        TapscriptHashKind::Hash256 => bitcoin::opcodes::all::OP_HASH256,
        TapscriptHashKind::Ripemd160 => bitcoin::opcodes::all::OP_RIPEMD160,
        TapscriptHashKind::Hash160 => bitcoin::opcodes::all::OP_HASH160,
    };
    let leaf = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(hash_op)
        .push_slice(<&bitcoin::script::PushBytes>::try_from(digest).expect("digest pushable"))
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    let parsed = bare_tapscript_hash_preimage_template(&leaf).expect("test leaf is bare hash");
    assert_eq!(parsed.0, kind);
    assert_eq!(parsed.1, digest);

    let spend_info = TaprootBuilder::new()
        .add_leaf(0, leaf.clone())
        .expect("add leaf")
        .finalize(&secp, internal_xonly)
        .expect("finalize tree");
    let merkle = spend_info.merkle_root();
    let control_block = spend_info
        .control_block(&(leaf.clone(), LeafVersion::TapScript))
        .expect("control block for leaf");
    let (psbt, spk) = p2tr_psbt_with_internal(internal_xonly, merkle);
    assert_eq!(spk, ScriptBuf::new_p2tr_tweaked(spend_info.output_key()));
    assert!(control_block.verify_taproot_commitment(
        &secp,
        p2tr_output_key(&spk).expect("output key"),
        &leaf
    ));
    (psbt, leaf, control_block)
}

/// Build and_v(v:pk, hash) leaf under a single-leaf Taproot tree.
fn p2tr_and_v_pk_hash_script_path_psbt(
    internal_sk: [u8; 32],
    spend_sk: [u8; 32],
    kind: TapscriptHashKind,
    digest: &[u8],
) -> (
    bitcoin::psbt::Psbt,
    ScriptBuf,
    bitcoin::taproot::ControlBlock,
    bitcoin::secp256k1::XOnlyPublicKey,
) {
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TaprootBuilder};

    let secp = Secp256k1::new();
    let internal_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&internal_sk).expect("isk"));
    let (internal_xonly, _) = internal_kp.x_only_public_key();
    let spend_kp = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&spend_sk).expect("ssk"));
    let (spend_xonly, _) = spend_kp.x_only_public_key();

    let hash_op = match kind {
        TapscriptHashKind::Sha256 => bitcoin::opcodes::all::OP_SHA256,
        TapscriptHashKind::Hash256 => bitcoin::opcodes::all::OP_HASH256,
        TapscriptHashKind::Ripemd160 => bitcoin::opcodes::all::OP_RIPEMD160,
        TapscriptHashKind::Hash160 => bitcoin::opcodes::all::OP_HASH160,
    };
    let leaf = bitcoin::script::Builder::new()
        .push_x_only_key(&spend_xonly)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIGVERIFY)
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(hash_op)
        .push_slice(<&bitcoin::script::PushBytes>::try_from(digest).expect("digest pushable"))
        .push_opcode(bitcoin::opcodes::all::OP_EQUAL)
        .into_script();
    let parsed =
        bare_tapscript_and_v_pk_hash_template(&leaf).expect("test leaf is and_v(v:pk, hash)");
    assert_eq!(parsed.0, spend_xonly);
    assert_eq!(parsed.1, kind);
    assert_eq!(parsed.2, digest);

    let spend_info = TaprootBuilder::new()
        .add_leaf(0, leaf.clone())
        .expect("add leaf")
        .finalize(&secp, internal_xonly)
        .expect("finalize tree");
    let merkle = spend_info.merkle_root();
    let control_block = spend_info
        .control_block(&(leaf.clone(), LeafVersion::TapScript))
        .expect("control block for leaf");
    let (psbt, spk) = p2tr_psbt_with_internal(internal_xonly, merkle);
    assert_eq!(spk, ScriptBuf::new_p2tr_tweaked(spend_info.output_key()));
    assert!(control_block.verify_taproot_commitment(
        &secp,
        p2tr_output_key(&spk).expect("output key"),
        &leaf
    ));
    (psbt, leaf, control_block, spend_xonly)
}

/// Build and_v(v:hash, pk) leaf under a single-leaf Taproot tree.
fn p2tr_and_v_hash_pk_script_path_psbt(
    internal_sk: [u8; 32],
    spend_sk: [u8; 32],
    kind: TapscriptHashKind,
    digest: &[u8],
) -> (
    bitcoin::psbt::Psbt,
    ScriptBuf,
    bitcoin::taproot::ControlBlock,
    bitcoin::secp256k1::XOnlyPublicKey,
) {
    use bitcoin::secp256k1::{Keypair, SecretKey};
    use bitcoin::taproot::{LeafVersion, TaprootBuilder};

    let secp = Secp256k1::new();
    let internal_kp =
        Keypair::from_secret_key(&secp, &SecretKey::from_slice(&internal_sk).expect("isk"));
    let (internal_xonly, _) = internal_kp.x_only_public_key();
    let spend_kp = Keypair::from_secret_key(&secp, &SecretKey::from_slice(&spend_sk).expect("ssk"));
    let (spend_xonly, _) = spend_kp.x_only_public_key();

    let hash_op = match kind {
        TapscriptHashKind::Sha256 => bitcoin::opcodes::all::OP_SHA256,
        TapscriptHashKind::Hash256 => bitcoin::opcodes::all::OP_HASH256,
        TapscriptHashKind::Ripemd160 => bitcoin::opcodes::all::OP_RIPEMD160,
        TapscriptHashKind::Hash160 => bitcoin::opcodes::all::OP_HASH160,
    };
    // v:hash uses EQUALVERIFY; bare hash uses EQUAL.
    let leaf = bitcoin::script::Builder::new()
        .push_opcode(bitcoin::opcodes::all::OP_SIZE)
        .push_int(32)
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_opcode(hash_op)
        .push_slice(<&bitcoin::script::PushBytes>::try_from(digest).expect("digest pushable"))
        .push_opcode(bitcoin::opcodes::all::OP_EQUALVERIFY)
        .push_x_only_key(&spend_xonly)
        .push_opcode(bitcoin::opcodes::all::OP_CHECKSIG)
        .into_script();
    let parsed =
        bare_tapscript_and_v_hash_pk_template(&leaf).expect("test leaf is and_v(v:hash, pk)");
    assert_eq!(parsed.0, spend_xonly);
    assert_eq!(parsed.1, kind);
    assert_eq!(parsed.2, digest);
    // Must not parse as siblings.
    assert!(bare_tapscript_and_v_pk_hash_template(&leaf).is_none());
    assert!(bare_tapscript_hash_preimage_template(&leaf).is_none());

    let spend_info = TaprootBuilder::new()
        .add_leaf(0, leaf.clone())
        .expect("add leaf")
        .finalize(&secp, internal_xonly)
        .expect("finalize tree");
    let merkle = spend_info.merkle_root();
    let control_block = spend_info
        .control_block(&(leaf.clone(), LeafVersion::TapScript))
        .expect("control block for leaf");
    let (psbt, spk) = p2tr_psbt_with_internal(internal_xonly, merkle);
    assert_eq!(spk, ScriptBuf::new_p2tr_tweaked(spend_info.output_key()));
    assert!(control_block.verify_taproot_commitment(
        &secp,
        p2tr_output_key(&spk).expect("output key"),
        &leaf
    ));
    (psbt, leaf, control_block, spend_xonly)
}

fn sample_sha256_preimage_and_digest(seed: u8) -> ([u8; 32], [u8; 32]) {
    use bitcoin::hashes::{Hash, sha256};
    let mut preimage = [0u8; 32];
    preimage.fill(seed);
    preimage[0] = seed.wrapping_add(1);
    let digest = sha256::Hash::hash(&preimage).to_byte_array();
    (preimage, digest)
}

fn sample_hash160_preimage_and_digest(seed: u8) -> ([u8; 32], [u8; 20]) {
    use bitcoin::hashes::{Hash, hash160};
    let mut preimage = [0u8; 32];
    preimage.fill(seed);
    preimage[0] = seed.wrapping_add(2);
    let digest = hash160::Hash::hash(&preimage).to_byte_array();
    (preimage, digest)
}

/// bare sha256 with matching PSBT preimage → Complete.
#[test]
fn finalize_taproot_bare_sha256_with_preimage_is_complete() {
    use bitcoin::hashes::{Hash, sha256};
    use bitcoin::taproot::LeafVersion;

    let (preimage, digest) = sample_sha256_preimage_and_digest(90);
    let (mut psbt, leaf, control_block) =
        p2tr_hash_script_path_psbt([91u8; 32], TapscriptHashKind::Sha256, &digest);
    psbt.inputs[0].tap_scripts.insert(
        control_block.clone(),
        (leaf.clone(), LeafVersion::TapScript),
    );
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(digest), preimage.to_vec());

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete() && fin.is_broadcast_ready(), "{fin:?}");
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("hash final")
        .to_vec();
    assert_eq!(items.len(), 3);
    assert_eq!(items[0], preimage.to_vec());
    assert_eq!(items[1], leaf.as_bytes());
    assert_eq!(items[2], control_block.serialize());
    assert!(psbt_is_broadcast_ready(&psbt));
    let _tx = extract_finalized_tx(psbt).unwrap();
}

/// bare hash160 with matching PSBT preimage → Complete (SIZE still 32).
#[test]
fn finalize_taproot_bare_hash160_with_preimage_is_complete() {
    use bitcoin::hashes::{Hash, hash160};
    use bitcoin::taproot::LeafVersion;

    let (preimage, digest) = sample_hash160_preimage_and_digest(92);
    let (mut psbt, leaf, control_block) =
        p2tr_hash_script_path_psbt([93u8; 32], TapscriptHashKind::Hash160, &digest);
    psbt.inputs[0].tap_scripts.insert(
        control_block.clone(),
        (leaf.clone(), LeafVersion::TapScript),
    );
    psbt.inputs[0]
        .hash160_preimages
        .insert(hash160::Hash::from_byte_array(digest), preimage.to_vec());

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(fin.is_complete() && fin.is_broadcast_ready(), "{fin:?}");
    let items = psbt.inputs[0]
        .final_script_witness
        .as_ref()
        .expect("hash160 final")
        .to_vec();
    assert_eq!(items[0], preimage.to_vec());
    assert_eq!(items[0].len(), 32, "miniscript preimage is always 32 bytes");
    assert_eq!(items[1], leaf.as_bytes());
    assert_eq!(items[2], control_block.serialize());
}

