/// and_v(v:hash, pk) missing sig → Partial (preimage alone insufficient).
#[test]
fn finalize_taproot_and_v_hash_pk_missing_sig_is_partial() {
    use bitcoin::hashes::{Hash, sha256};
    use bitcoin::taproot::LeafVersion;

    let (preimage, digest) = sample_sha256_preimage_and_digest(205);
    let (mut psbt, leaf, control_block, _pk) = p2tr_and_v_hash_pk_script_path_psbt(
        [206u8; 32],
        [207u8; 32],
        TapscriptHashKind::Sha256,
        &digest,
    );
    psbt.inputs[0]
        .tap_scripts
        .insert(control_block, (leaf, LeafVersion::TapScript));
    psbt.inputs[0]
        .sha256_preimages
        .insert(sha256::Hash::from_byte_array(digest), preimage.to_vec());
    assert!(psbt.inputs[0].tap_script_sigs.is_empty());

    let fin = finalize_psbt(&mut psbt).unwrap();
    assert!(!fin.is_complete() && !fin.is_broadcast_ready(), "{fin:?}");
    match &fin {
        FinalizeOutcome::Partial { detail, .. } => {
            let d = detail.to_ascii_lowercase();
            assert!(
                d.contains("and_v")
                    || d.contains("missing")
                    || d.contains("tap_script")
                    || d.contains("hash"),
                "{detail}"
            );
            assert!(
                d.contains("v:hash") || d.contains("hash, pk") || d.contains("missing a"),
                "must name and_v(v:hash, pk) residual: {detail}"
            );
        }
        other => panic!("expected Partial, got {other:?}"),
    }
    assert!(psbt.inputs[0].final_script_witness.is_none());
    assert!(extract_finalized_tx(psbt).is_err());
}

